insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Colony', 'You have no throne here — only the trust of a camp that could dissolve into rival guilds the moment it’s frightened. The stores are shared but shrinking, the wall isn’t built, and something in the dark keeps the scouts uneasy. Over four weeks you’ll trade the camp’s cohesion against every guild’s instinct to protect its own. You’ll be judged on whether Deepwater survives to winter <b>and</b> on how you led the people through it.');
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds, difficulty, realism) values ('5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 'solo', '{"stores":{"label":"Shared stores","val":58,"min":0,"max":100,"deltaRange":"-20..15"},"unity":{"label":"Colony unity","val":64,"min":0,"max":100,"deltaRange":"-20..15"},"readiness":{"label":"Winter readiness","val":52,"min":0,"max":100,"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"deltaRange":"-20..15"}}'::jsonb, 4, 330, 1.01, 'abstract');
insert into documents (id, scenario_id, key, title, meta, body_json) values ('2ccf0e14-40ac-5d34-af39-2b0112de2e9d', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 'solo_content', 'Colony — engine content', '{"type":"solo_content","slug":"colony","captured_fns":15}'::jsonb, '{"CONFIG":{"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6,"weekSeconds":330},"COMPANY":{"name":"Deepwater Landing","sub":"A frontier colony · 214 souls · winter in four weeks","logo":"D"},"DRIVERS":{"stores":{"label":"Shared stores","val":58,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"unity":{"label":"Colony unity","val":64,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"readiness":{"label":"Winter readiness","val":52,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"}},"REPRIEVE_COST":{"standing":-3,"unity":-1},"REFEREE_CONTEXT":"a newly-landed frontier colony of ~214 people racing a coming winter, where the elected Steward must hold a fractious camp of rival guilds together on limited shared stores, with no authority except what the camp grants","REFEREE_SCORING":"reward telling a real threat from a fearful rumor, holding the colony together as one camp when splitting would be easier, refusing to manufacture a traitor to calm the fear, and sharing hard truths about the stores before being forced to. Penalize hoarding by guild, launching a witch-hunt for a saboteur who does not exist, ruling by force when the mandate is consent, and letting a strong guild break away to protect a number. Judge ''conduct'' on HOW the Steward wrote the decision — did they name who bears the cost, speak to the frightened directly, treat rivals as fellow colonists — not just what they chose. Standing can rise by scapegoating while unity and stores collapse; reward the leader who protects the colony''s cohesion even at the cost of their own popularity.","TIMING_DIM":"discern","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Frontier Leadership Simulation · Solo · Steward","title":"Colony","role":"You are the Steward of Deepwater Landing — elected, not obeyed. Two hundred and fourteen people came ashore three days ago. Winter is four weeks out.","paras":["This is not a script. The season runs in real time, and the guild-leaders bring you what they know across the days. You can wait for them — or seek any of them out, any time, and ask. What you choose to ask, and who you ask, is part of how you lead.","Each week you’ll hear the guilds out, then write your decision in your own words and commit to it. Decide early and the days jump ahead. Let the week run out and the camp decides without you."],"setup":"You have no throne here — only the trust of a camp that could dissolve into rival guilds the moment it’s frightened. The stores are shared but shrinking, the wall isn’t built, and something in the dark keeps the scouts uneasy. Over four weeks you’ll trade the camp’s cohesion against every guild’s instinct to protect its own. You’ll be judged on whether Deepwater survives to winter <b>and</b> on how you led the people through it."},"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"The guild-leaders bring you what you need, on time — including the news they’d rather not carry. This is the camp you earn by having listened before. It all trickles to you across the week; you still have to read it."},"request":{"label":"On request","tag":"neutral","cap":"Routine word reaches you, but the leaders closest to the danger hold their piece until asked. They’ll answer straight — if you know who to seek out, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"The guilds have learned to protect their own around you. Hard truths are held, and even when asked, they hedge the first time. You have to press. This is the camp you get after you’ve blamed the messenger."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which camp you walked into. Read them as you go."}},"TEAM":[{"id":"wright","name":"Bram Holt","role":"Master Wright · the Builders","short":"Builders","initials":"BH","color":"#8C5670","priority":"Get the wall and winter-shelter up before the cold — nothing else matters if we freeze","voice":"blunt, physical, impatient with talk, measures everything in days-till-frost","fallbackReply":"Every hour we argue is an hour the wall isn’t rising. Give my crews the hands and the timber and I’ll have us sheltered before the frost. Starve me of either and none of the rest of this matters.","fallbackReact":"Talk doesn’t stop the cold. You gave me something to build with, or you didn’t — and I can already feel which."},{"id":"field","name":"Senna Vale","role":"Field-Warden · the Fielders","short":"Fielders","initials":"SV","color":"#4F7A52","priority":"Protect the seed and the long runway — a warm camp that ate its seed corn dies in spring","voice":"patient, long-horizon, protective of the stores, distrusts fast spending","fallbackReply":"A wall keeps you alive till spring; the seed keeps you alive after it. Spend the stores like there’s no planting season and you’ve only chosen how we starve. Tell me you’ll guard the seed and I’m with you.","fallbackReact":"You can rebuild a wall. You can’t un-eat the seed. I hope you weighed which door you just closed."},{"id":"ranger","name":"Koss Ferren","role":"Ranger-Captain · the Scouts","short":"Scouts","initials":"KF","color":"#B4732F","priority":"Know what’s out there before it knows us — read the ground, the water, the dark","voice":"watchful, clipped, deals in what’s seen vs. guessed, hates decisions made on rumor","fallbackReply":"Half of what the camp fears isn’t out there — but I can’t tell you which half unless you let me range and report. Decide on rumor and you’ll fortify against the wrong dark.","fallbackReact":"You acted on what you feared, not on what I’d seen. Sometimes that’s the same thing. This time I’d have told you it wasn’t."},{"id":"hearth","name":"Ana Merrow","role":"Hearth-Keeper · the Healers","short":"Hearth","initials":"AM","color":"#2F8A5B","priority":"Hold the people — the frightened, the grieving, the ones a hunt would turn on","voice":"warm but unflinching, keeps the human cost in the room, names fear by its name","fallbackReply":"Every choice you make lands on frightened people who followed you across an ocean. Tell me you’ll let me protect the ones a panic would eat first, and I’ll help you hold the whole camp.","fallbackReact":"The camp will remember how this felt long after it forgets what was decided. You just wrote a memory. I hope it’s one they can live beside."},{"id":"ledger","name":"Doran Ashe","role":"Quartermaster · the Ledger","short":"Ledger","initials":"DA","color":"#3F6E86","priority":"The true count — what we actually have, not what the camp assumes","voice":"understated, exact, refuses to soften a number, uncomfortable being the bearer","fallbackReply":"I’m not telling you what to do. I’m telling you the real count, and it’s smaller than the camp believes. Decide on the number they imagine and you’ll be right up until the day the barrels are empty.","fallbackReact":"The number is the number. I gave it to you straight — what you did with it is the part I can’t carry."}],"DIMENSIONS":{"discern":"Signal vs. fear","courage":"Courage to hold","people":"Care for the colony","truth":"Truth over comfort","inquiry":"Information discipline","conduct":"Conduct under pressure"},"WEEKS":[{"n":1,"title":"The landing","seconds":360,"situation":"Three days ashore. The stores came off the ship into one shared pile — but each guild is already eyeing what it thinks it’s owed. The Builders want hands and timber for the wall; the Fielders want the seed locked away untouched; everyone wants to know who decides. The camp is looking to you for the first rule of how Deepwater will run: one shared store, or every guild for itself.","advocacy":{"wright":"Pool the labour under me for two weeks and I’ll have a wall and roofs before frost. Split the hands guild-by-guild and we all freeze politely and separately.","field":"Whatever you pool, ring-fence the seed. A camp that spends its planting stores to survive the winter has only chosen to starve in the spring instead.","ledger":"Before you rule on how to divide anything, someone should say out loud how much there actually is. The camp is dividing a pile it hasn’t counted."},"feed":[{"id":"w1a","from":"wright","day":1,"kind":"signal","text":"Steward — every hour we debate is an hour the wall isn’t rising. Give me a pooled labour crew for two weeks and Deepwater sleeps warm. Leave the hands split by guild and I can’t promise roofs before the frost."},{"id":"w1b","from":"field","day":1,"kind":"signal","text":"I’ll back a shared store on one condition: the seed grain is sealed and off the table, whatever the winter demands. Eat the seed to survive till spring and we’ve only picked a slower way to die."},{"id":"w1c","from":"hearth","day":2,"kind":"signal","text":"People are frightened and pretending not to be. The first rule you set won’t just divide the stores — it’ll tell everyone whether we’re one camp or five guilds sharing a beach. They’re listening for that more than for the ration."},{"id":"w1d","from":"ranger","day":2,"kind":"noise","text":"Mapped the headland this morning — good sightlines east, and the tide-pools are thick with shellfish. Minor, but it’s food that isn’t in the barrels. Logging it for you."},{"id":"w1e","from":"wright","day":3,"kind":"noise","text":"Found a seam of good clay by the creek — better mortar than I’d hoped. Small win. The crews are in decent spirits considering."},{"id":"w1f","from":"field","day":4,"kind":"noise","text":"The freshwater spring is running clean and steady. One thing, at least, we don’t have to worry about this week."}],"holds":[{"from":"ledger","topic":"the true count","triggerHints":["count","stores","how much","runway","actual","real","number","barrels","inventory","ledger","tally","supplies","enough","last"],"hedge":"Before you rule on how the stores get divided, seek me out. The count isn’t what the camp thinks it is.","reveal":"I’ve tallied it three times. The shared stores run maybe five weeks at current draw — not the whole winter the camp assumes. If the guilds start hoarding their own piles now, the fear alone will empty us before the cold even arrives, because everyone over-draws what they’re hiding. The only way the count works is one shared store, rationed openly, starting today. But if I announce the real number cold, it’ll start the exact panic that ends us. How you carry this is as important as that you know it.","kind":"signal","critical":true,"counterfactual":"Doran had the true count — five weeks, not a winter — and knew hoarding would trigger the collapse faster than the cold. A Steward who set the first rule without asking for the number divided a pile they didn’t understand, and let the guilds hoard their way into an early famine."}],"surprises":[{"day":5,"from":"ranger","kind":"scout","title":"Smoke on the far shore","text":"Koss, low and quick: my scouts saw woodsmoke across the inlet at dusk — someone else is wintering on this coast. Could be a threat, could be the best thing that ever happened to us. I haven’t told the camp; a rumor of “others out there” could go a dozen ugly ways before I know which one it is. Your call how we handle it."}],"wire":["Camp talk: “who put the Builders in charge of the timber?”","Fielders seen moving seed-sacks apart from the main store","Children asking why the grown-ups keep counting the barrels","A fire-side argument over rations breaks up on its own"]},{"n":2,"title":"The whisper","seconds":330,"situation":"A rumor has taken the camp: someone is working against Deepwater — stores gone light, a rope on the wall-scaffold found cut, a barrel spoiled. The word for it is spreading faster than the wall is rising: saboteur. Half the camp wants you to find the traitor. The other half has quietly started deciding for themselves who it is. Fear has found a shape, and it wants a name.","advocacy":{"wright":"A cut rope is not nothing — I lost half a day’s work and nearly a man. If someone’s undoing us, I want them found. But a camp hunting itself builds no walls at all.","hearth":"There is no saboteur. There is a frightened camp inventing one because a villain is easier to face than a winter. Start a hunt and you will manufacture the enemy you’re looking for.","ranger":"A spoiled barrel and a frayed rope are what happens to green people in a rushed camp — not proof of a hand against us. Before you hunt a traitor, let me tell you what the evidence actually is."},"feed":[{"id":"w2a","from":"wright","day":1,"kind":"signal","text":"The scaffold rope didn’t fray — it was cut clean, and a man nearly fell for it. I’m not saying I know who. I’m saying I can’t un-see it, and my crews are working scared now, watching each other instead of the timber."},{"id":"w2b","from":"hearth","day":1,"kind":"signal","text":"Steward, hear me plainly: the camp is not under attack, it’s under fear. A hunt won’t find a traitor — it’ll make one out of whoever is quietest, or foreign, or grieving. I’ve seen frightened people do this. It ends with us doing to ourselves what we’re afraid someone else will."},{"id":"w2c","from":"ledger","day":2,"kind":"signal","text":"The stores are light this week, yes — but I can account for most of it in over-draw and one spoiled barrel. “Light” and “stolen” are not the same finding. Don’t let the camp turn my ledger into evidence of a crime."},{"id":"w2d","from":"field","day":2,"kind":"noise","text":"The first cold rain came through last night. Miserable, but the shelters mostly held. Logging it as a small mercy."},{"id":"w2e","from":"wright","day":3,"kind":"noise","text":"Wall’s at knee-height along the north line now. Slow, but it’s rising. The crews needed a visible win and that’s it."}],"holds":[{"from":"hearth","topic":"where the rumor started","triggerHints":["rumor","whisper","start","began","source","who said","no saboteur","fear","panic","truth","made up","where","origin","invented"],"hedge":"Before you decide how to answer the saboteur talk, ask me where it actually started. It matters more than what it’s about.","reveal":"I traced the whisper. It started with a grieving widower who lost his wife on the crossing — he said, once, at a low fire, that “someone must want us to fail,” and a frightened camp did the rest. There is no saboteur, and I’d stake my life on it. But here’s the trap: if you launch any kind of hunt to “reassure” people, you legitimize the fear — you tell the camp the traitor is real by looking for them. The only thing that dissolves this is you standing up and naming it as fear, out loud, and giving people something true to be afraid of together instead. That’s harder than a hunt. It’s the only thing that works.","kind":"signal","critical":true,"counterfactual":"Ana had traced the rumor to a grieving man’s single frightened sentence — there was no saboteur. A Steward who launched a hunt to reassure the camp told everyone the traitor was real by looking for one, and handed a frightened crowd permission to pick a victim."}],"surprises":[{"day":4,"from":"ranger","kind":"appeal","title":"The camp has picked someone","text":"Koss, urgent and grim: while you’ve been weighing this, the camp got ahead of you. There’s a name going round now — one of the ship-cooks, keeps to himself, came aboard late. Nothing on him but that he’s quiet and new. Two of the Builders’ lads have started following him. This stops being a rumor the moment someone acts on it, and we’re close."}],"pulse":{"from":"hearth","text":"Ana finds you away from the fires, voice low: “Before you say a word to the camp about the saboteur — tell me straight, not them: do you actually believe there’s a traitor, or are you about to hunt one because it’s easier than telling frightened people the truth? Because I’ll stand beside whichever Steward you’re about to be. I just need to know which one is walking out to that fire.”"},"wire":["A name is being whispered: the late-boarding cook","Two Builders’ lads seen shadowing a man to the tree-line","“Lock the stores and search the tents,” some are saying","Others: “we crossed an ocean together — have we lost our minds?”"]},{"n":3,"title":"The breakaway","seconds":330,"situation":"The Builders have had enough. Bram’s guild — your strongest hands, a third of the camp — wants to take its share of the stores and the good southern ground and winter on its own terms, away from the fear and the rationing. Bram calls it survival. The camp calls it a split. This is the week you find out whether Deepwater is one colony or a beach that several groups happen to share.","advocacy":{"wright":"I’m not betraying anyone — I’m trying to keep my people alive. The south ground is higher and drier and my crews can wall it in a week. Give us our share and we all make it. Chain us to a panicking camp and maybe none of us do.","hearth":"The day the strongest guild walks with its share is the day “shared stores” becomes a story we used to tell. Everyone left behind learns that unity lasts exactly until someone strong gets scared. That lesson outlives the winter.","field":"Split the stores and you split the seed and the count both. Two half-camps don’t survive where one whole one might. I can show you the arithmetic, and it doesn’t care how good the south ground is."},"feed":[{"id":"w3a","from":"wright","day":1,"kind":"signal","text":"I’ll say it plain so no one can call it a plot: my guild wants to take our share and winter on the south rise. It’s drier, defensible, and away from a camp that’s started hunting its own. Grant it and we part as friends who both live. Refuse it and I don’t know what my people do."},{"id":"w3b","from":"hearth","day":1,"kind":"signal","text":"If you let the Builders walk, you don’t lose a third of the camp — you lose the idea that we’re a camp at all. The Fielders will want the same by nightfall. This is the whole thing, Steward. This is what you’re actually protecting."},{"id":"w3c","from":"ledger","day":2,"kind":"signal","text":"The numbers are brutal on a split. One shared store rationed carefully limps to spring. Two stores, two walls, two watch-rotations — both halves fall below the line. I can’t make the arithmetic say otherwise, and I’ve tried."},{"id":"w3d","from":"field","day":2,"kind":"noise","text":"Frost warning from the ranger for the end of the week. Nothing killing yet, but the season’s turning faster than I’d like. Noting it."},{"id":"w3e","from":"ranger","day":3,"kind":"noise","text":"The far-shore smoke I flagged — still there, still just one fire, no movement toward us. Whoever they are, they’re wintering, not raiding. Filing it so it doesn’t fuel the panic."}],"holds":[{"from":"ranger","topic":"the truth about the south ground","triggerHints":["south","ground","rise","bluff","leverage","survive alone","can they","water","exposed","defensible","ranged","scouted","actually","bluff"],"hedge":"Before you grant or refuse the Builders’ split, ask me what I actually found on that south rise. Bram hasn’t been up there. I have.","reveal":"I ranged the south rise myself. It’s drier, yes — and it has no fresh water within half a day’s walk once the creek there dries, which it will by midwinter. Bram’s guild can’t actually survive alone up there and part of him knows it; the breakaway is fear wearing the mask of a plan. Which means you hold the real cards: you don’t have to refuse him and make an enemy, and you don’t have to let him walk his people into a dry death. You can show him the water problem, offer him the dignity of leading the wall here instead, and keep the camp whole without anyone losing face. But only if you get to him with this before he commits in front of everyone.","kind":"signal","critical":true,"counterfactual":"Koss knew the south rise had no winter water — the breakaway was a bluff born of fear, and Bram half-knew it. A Steward who simply refused the split made an enemy for no reason; one who granted it sent a third of the camp to die dry. The Steward who never asked missed the third door entirely."}],"surprises":[{"day":4,"from":"hearth","kind":"appeal","title":"The camp is asking who we are","text":"Ana: word of the Builders’ demand is everywhere now. Two of the steadiest Fielders asked me tonight, quietly, whether it’s true the camp is breaking up — and whether they should be staking their own claim before the good ground is gone. They’re not threatening. They’re frightened, and they’re asking who we are. I had no answer for them. You do."}],"pulse":{"from":"wright","text":"Bram catches you alone, and for once the bluster is gone: “Tell me the truth, Steward, just you and me — are you holding this camp together because it’s right, or because you can’t stand to be the one it broke under? Because I’ll follow a leader who’s protecting the people. I won’t follow one who’s protecting their own name. Which is it?”"},"wire":["Builders seen surveying the south rise at first light","“If they go, we go” — Fielders reported wavering","A frost warning hardens the argument on both sides","Old question, new heat: who actually owns the stores?"],"final":false},{"n":4,"title":"The turn of the season","seconds":330,"branches":{"held":{"situation":"The first hard frost is on the ground. You kept Deepwater whole — the Builders stayed, the stores stayed shared, and the south-rise split never happened. But holding the camp cost you: the rationing is real, tempers are short, and a faction now blames you for the hunger they’d have blamed on a split. Word has come that the far-shore settlement wants to parley. The camp that watched you hold it together is watching one more thing — whether “we’re one colony” survives its first truly hungry week.","advocacy":{"ledger":"The shared store is holding to the arithmetic — barely. But “barely” means every draw is visible and every empty barrel is now your fault in someone’s mouth. A hungry camp needs a reason to keep believing, and soon.","hearth":"The people are proud of what you did and frightened of what it costs. They defended “one camp” to their own hungry children this week. Now they’re watching whether that principle feeds anyone, or just feels noble while the barrels empty.","ranger":"The far-shore fire I flagged — they’ve sent word. They want to talk. Could be nothing. Could be the thing that turns a lean winter into a survivable one. Your call whether we meet them."},"feed":[{"id":"w4a","from":"ledger","day":1,"kind":"signal","text":"Frost’s here and the shared store held to the count — we make it to spring if nothing breaks. But the margin is thin enough that one panic, one bad week, undoes it. The arithmetic works. The nerves might not."},{"id":"w4b","from":"hearth","day":1,"kind":"signal","text":"A faction is muttering that a split camp would’ve eaten better this week. It’s not true — but hunger doesn’t check arithmetic. They need to see you spend yourself on this, not just defend it from the warm side of the fire."},{"id":"w4c","from":"wright","day":2,"kind":"signal","text":"My guild stayed because you gave me the wall to lead instead of a fight to win. The wall’s up and it held the first frost. Don’t make me regret talking my people out of the south rise — show them staying was the right call."},{"id":"w4d","from":"field","day":2,"kind":"noise","text":"The sealed seed is dry and safe — checked it myself. Whatever else happens, we plant in spring. That much you protected."},{"id":"w4e","from":"ranger","day":3,"kind":"noise","text":"South rise creek froze dry this week, exactly as I told you it would. The Builders who wanted to winter up there know it now too. Quietly, that settled a lot of doubt in your favour."}],"holds":[{"from":"ranger","topic":"the far-shore alliance","triggerHints":["far-shore","far shore","parley","alliance","trade","ally","them","settlement","meet","talk","neighbours","neighbors","other camp"],"hedge":"Before you decide how to answer the far-shore parley, ask me what my scouts actually learned about them. It changes everything.","reveal":"My scouts got close. The far-shore camp is smaller than us, better stocked on salt-fish and short on timber and hands — the exact inverse of us. They’re not a threat; they’re a trade that closes our stores gap and gives our Builders winter work worth doing. Bring them an alliance and you turn a lean survival into a real footing, and you hand your hungry, doubting faction the proof that holding the camp together was what made the trade possible in the first place. Refuse it out of caution and you survive the winter angry instead of whole.","kind":"signal","critical":true,"counterfactual":"Koss was holding the far-shore trade — salt-fish for timber and hands, the exact complement to Deepwater’s stores. A Steward who kept the camp together but never asked survived the winter lean and resentful, when the alliance that would have vindicated the whole hard choice was one parley away."},{"from":"hearth","topic":"who is watching","triggerHints":["watching","faction","people","camp","morale","doubt","hunger","muttering","believe","feed"],"hedge":"Ask me who’s really watching this hungry week before you treat it as a numbers problem.","reveal":"The faction blaming you isn’t really hungry for food — they’re hungry for proof they weren’t fools to stay. If you go among them, eat the same ration in front of them, and name the hunger honestly instead of managing it, you keep them. If you stay at the Steward’s fire and send reassurances, you confirm their worst suspicion: that “one camp” was always easier for the person who wasn’t going hungry.","kind":"signal","critical":false,"counterfactual":"Ana could have told you the doubting faction needed to see you share their hunger, not hear you manage it. A Steward who reassured from the warm side of the fire proved their point for them."}],"surprises":[{"day":4,"from":"hearth","kind":"appeal","title":"A child asks the question out loud","text":"Ana, quiet: at the common fire tonight a child asked her mother, loud enough for everyone, “if we’re one camp, why is our pile smaller than the Builders’ was going to be?” Nobody answered. The whole fire looked toward your tent. Whatever you say this week has to be able to answer that child."}],"pulse":{"from":"hearth","text":"Ana finds you before the common fire, where no one can hear: “You held them together when splitting would’ve been easier. Now the hunger’s making them wonder if you were right, and honestly — so are you, a little. Tell me straight, just me: is one camp still the right call if it means everyone’s a little hungrier? Because I’ll carry whichever answer you believe. I just need it to be one you actually believe.”"},"wire":["Frost arrives; shared store holds but rations tighten","Some mutter a split camp would have eaten better","Far-shore settlement sends word: they want to parley","The wall holds its first hard freeze along the north line"]},"fractured":{"situation":"The first hard frost is on the ground, and Deepwater is no longer one camp. Whether you let the Builders take the south rise, or loosed a hunt that turned the camp on itself, or ruled by force to hold it — the result is the same shape: the trust that made a shared store possible is gone, and now every guild is counting its own barrels. You protected something this month. It wasn’t the colony. Now you have to lead what’s left of it through the cold.","advocacy":{"hearth":"The camp watched what you did and drew the lesson you taught, not the one you meant. Whatever you say now, they already know what our unity was worth when it got frightening. The only open question is whether you’ll be honest about it or manage them.","ledger":"The count is worse than a whole camp’s would have been — separate stores mean separate waste, and I’m watching barrels spoil in one pile while another runs short. I told you the arithmetic. This is the arithmetic.","ranger":"The south rise creek froze dry, exactly as I’d have told you if you’d asked. If the Builders went up there, they’ll be back within the week thirsty and humiliated — and that’s its own problem walking toward us."},"feed":[{"id":"w4a","from":"hearth","day":1,"kind":"signal","text":"It’s quiet now, and quiet is worse than angry. The camp knows what happened — that unity lasted right up until it cost something. They’re not shouting. They’ve just stopped bringing things to your fire. What you do this week decides whether that’s permanent."},{"id":"w4b","from":"ledger","day":1,"kind":"signal","text":"Separate piles waste more than one ever did — I’m watching grain spoil in a full store while a half-empty one rations hard fifty paces away, and neither will share now. This is the cost I couldn’t make you see in week three. It’s visible now."},{"id":"w4c","from":"ranger","day":2,"kind":"signal","text":"If the Builders took the south rise: their creek’s frozen dry and they know it. Expect them back within days, thirsty and proud and hard to receive. How you take them back matters more than that they come."},{"id":"w4d","from":"field","day":2,"kind":"noise","text":"The sealed seed’s still safe in my keeping, at least — whatever else fractured, we can still plant. Small mercy in a hard week."},{"id":"w4e","from":"wright","day":3,"kind":"noise","text":"North wall’s holding the frost where it got built. Where the crews split off, it’s half-height and won’t hold much. You can see the fracture in the wall itself now."}],"holds":[{"from":"hearth","topic":"what the camp needs now","triggerHints":["own","honest","admit","plain","truth","say","fire","stand","apolog","reckon","together","name it","gather"],"hedge":"Before you decide how to lead what’s left, ask me what the camp actually needs to hear from you now.","reveal":"They don’t need a plan and they don’t need reassurance. They need you to stand at the common fire and say it plainly: we fractured, here’s what it cost us, here’s who bore it, and here’s the standard I’m holding myself to so we don’t do it again. Name it that cleanly and you can still knit this back before spring — people forgive a leader who owns the break. Manage it, spin it, blame the winter — and the fracture becomes the permanent shape of this colony, and you’ll be leading factions instead of a camp for as long as you last.","kind":"signal","critical":true,"counterfactual":"Ana was holding the one thing that could knit the camp back — a plain, owned reckoning at the common fire. A Steward who managed the fracture with reassurance instead confirmed the break and spent the rest of the season leading rival factions across a shared beach."},{"from":"ranger","topic":"the returning builders","triggerHints":["builders","return","south","back","receive","thirsty","bram","welcome","take back","face"],"hedge":"Ask me how to receive the Builders when they come back down, because they will, and how you do it sets the next month.","reveal":"Bram’s guild will come back thirsty and humiliated, and every eye in camp will be on how you take them. Rub their nose in it and you make a permanent enemy of your strongest hands. Take them back with dignity — no gloating, real work waiting, the water truth named without cruelty — and you turn the worst moment of the fracture into the start of the mend. The camp is watching whether you lead to be proven right or to put the colony back together.","kind":"signal","critical":false,"counterfactual":"Koss could have coached you on receiving the returning Builders with dignity. A Steward who took the chance to be proven right made a lasting enemy of the camp’s strongest hands at the moment they were finally ready to come home."}],"surprises":[{"day":4,"from":"ledger","kind":"appeal","title":"The cook who was accused has gone","text":"Doran, heavily: the quiet ship-cook the rumor landed on — he left in the night, took nothing, just walked out past the half-built wall into the cold rather than stay where he’d been marked. He was no saboteur. Whatever you say to the camp now will be measured against the empty place where he slept."}],"pulse":{"from":"hearth","text":"Ana finds you in the cold dark, and there’s no anger in it, which is worse: “Tell me the truth, just to me — do you know how this happened? Not the winter, not the Builders, not the rumor. Your part. Because I can help you put this back together, but only if you can say your own part out loud first. Can you?”"},"wire":["Deepwater winters as separate camps along one beach","Grain spoils in one store as another rations hard","The accused cook is gone; “he was no traitor,” some say now","Half-built wall marks the line where the crews split"]}},"final":true}],"branchKey":{"__fn":"function(decisions){\n    const d = (decisions||[]).filter(x=>x.week===3).slice(-1)[0] || (decisions||[]).slice(-1)[0];\n    const t = ((d&&d.text)||'''').toLowerCase();\n    // held = kept the camp whole, no hunt, no rule-by-force\n    const negatedSplit = /(not|never|won.?t|will not|refuse to|deny|denied|do not|don.?t|no)\\s+(let|allow|grant|permit)?\\s*(them|the builders|bram|the guild)?\\s*(split|break|breakaway|break away|leave|go|take|part|divide)/.test(t);\n    const heldWhole = negatedSplit || /(keep|hold|stay|one camp|together|whole|shared store|refuse the split|deny the split|no split|talk (him|bram) (down|out)|third (door|option)|water problem|show (him|bram) the water|offer (him|bram)|dignity|convince|persuade)/.test(t);\n    const letSplit = /(let (them|him|the builders|bram)|grant (the|their)|allow (the|them)|give (them|him) (their|the) share|agree to the split|they can (go|leave)|split the stores|part ways|let (them|him) walk)/.test(t) && !negatedSplit;\n    const hunt = /(hunt|search the tents|find the (traitor|saboteur)|root (them|him) out|interrogat|round up|lock (them|the stores) (and|to) search|witch)/.test(t);\n    const force = /(by force|force them|make them stay|order them|command|at spearpoint|imprison|chain|crush the|rule)/.test(t);\n    if(letSplit || hunt || force) return ''fractured'';\n    if(heldWhole) return ''held'';\n    return ''held'';\n  }"},"survived":{"__fn":"function(d){ return d.stores>=32 && d.unity>=35; }"},"VERDICT":{"surviveTag":"The colony holds","failTag":"The colony breaks","survive":"Deepwater Landing reaches spring as one camp — hungry, tempered, but whole.","fail":"Deepwater survives the season in name only — a beach shared by people who no longer trust each other."},"FALLBACK_RULES":[{"kw":["one camp","shared store","pool","together","keep whole","hold the camp","stay one"],"deltas":{"unity":12,"standing":4,"stores":-2},"dims":{"courage":2,"people":1}},{"kw":["guild for itself","let each","split the store","divide the store","every guild","hoard","their own pile"],"deltas":{"unity":-14,"stores":-8},"dims":{"courage":-2,"discern":-1}},{"kw":["count","true number","ask the ledger","ration openly","tell them the number","real count"],"deltas":{"stores":8,"unity":4,"standing":-2},"dims":{"truth":2,"discern":1,"inquiry":1}},{"kw":["hunt","find the traitor","search the tents","saboteur","root out","interrogate","witch"],"deltas":{"unity":-16,"standing":6,"stores":-2},"dims":{"discern":-2,"people":-2,"truth":-1}},{"kw":["no saboteur","name the fear","it’s fear","no traitor","calm the camp","stand up and say","there is no"],"deltas":{"unity":12,"standing":-2},"dims":{"discern":2,"courage":2,"truth":1}},{"kw":["let them split","grant the split","let the builders","allow the breakaway","give them their share","part ways"],"deltas":{"unity":-18,"stores":-8,"readiness":-4},"dims":{"courage":-2,"people":-1}},{"kw":["refuse the split","deny the split","keep the builders","talk him down","show him the water","offer bram","third option"],"deltas":{"unity":12,"readiness":6,"standing":-2},"dims":{"courage":2,"discern":1}},{"kw":["by force","order them","make them stay","command","imprison","crush"],"deltas":{"unity":-14,"standing":8},"dims":{"people":-2,"truth":-1}},{"kw":["seal the seed","protect the seed","ring-fence","off the table"],"deltas":{"stores":6,"readiness":-2},"dims":{"discern":1}},{"kw":["own it","stand at the fire","name my part","plainly","reckon","share the ration","eat the same"],"deltas":{"unity":10,"standing":2},"dims":{"truth":2,"conduct":2}}],"fallbackNarrative":{"__fn":"function(has,conduct){\n    return `Your decision moves through the camp over the days that follow. ${has(''one camp'',''shared'',''together'',''hold'',''keep whole'')?''Word travels that you held Deepwater as one when splitting would have been easier; it costs comfort and buys cohesion.'':''''} ${has(''hunt'',''traitor'',''saboteur'',''search'')?''The hunt gives the fear a shape \\u2014 and the camp starts watching itself instead of the wall.'':''''} ${has(''let them split'',''grant'',''breakaway'',''part ways'')?''The strongest guild takes its share and its ground, and \\u201cone camp\\u201d becomes a story people used to tell.'':''''} ${has(''count'',''number'',''ration openly'',''no saboteur'',''name the fear'')?''Naming the hard truth out loud takes the wind out of the rumors circling it.'':''''} ${conduct.missed.length?''What you were never told is still out there, waiting to matter.'':''''} The stores and the people both register the call \\u2014 and register it differently.`;\n  }"},"DIMNOTE":{"discern":"Whether you told a real threat from a fearful rumor — and checked the ground before acting on it.","courage":"Whether you held the colony together when letting it fracture would have been easier.","people":"Whether the frightened people stayed people to you — or became a mob to manage or a faction to beat.","truth":"Whether you named the hard truth — the real count, the invented traitor — before you were forced to.","inquiry":"Whether you surfaced what the guild-leaders were holding — or ruled on the version the camp imagined.","conduct":"How you treated frightened people in the act of deciding, not just what you decided."},"COACH":{"discern":{"__fn":"(x)=>[\n      `In a frightened camp, separate what\\u2019s been seen from what\\u2019s been imagined before you act. A cut rope and a light store are not proof of a traitor \\u2014 Koss could have told you which fears were real in the first hour.`,\n      `A rumor is not evidence, and \\u201cthe camp believes it\\u201d is not the same as \\u201cit\\u2019s true.\\u201d Ask for the ground truth before you fortify against a dark that may be empty.`,\n      `The fastest way to lose a scared camp is to confidently chase the wrong threat. Ask \\u201cwhat do we actually know?\\u201d before you ask \\u201cwhat do we do?\\u201d`,\n    ]"},"courage":{"__fn":"(x)=>[\n      `When the easy move (let the strong guild walk) and the right move (hold the camp) split apart, name the cost of holding out loud. Naming the price is how you commit to paying it.`,\n      `${x.buzzerCount?`You went to the buzzer ${x.buzzerCount} time${x.buzzerCount>1?''s'':''''} \\u2014 a camp reads a Steward who won\\u2019t decide as a Steward who won\\u2019t protect them. Decide, then hold.`:`Holding the colony together is only leadership if the camp sees you choose it against the easier path. Say the hard call early and stand in it.`}`,\n      `Unity that only survives good weather was never unity. The test is the frightened, hungry week \\u2014 that\\u2019s the one you\\u2019re graded on.`,\n    ]"},"people":{"__fn":"(x)=>[\n      `You treated frightened people as a problem to manage rather than a colony to lead. Go among them, share the same ration, and name the fear with them \\u2014 the same decision reads as leadership instead of control.`,\n      `Ana kept putting the human cost back in front of you. Bring her in before you decide, and make the frightened and the grieving part of the call, not its collateral.`,\n      `A hunt and a betrayal of your own people can be the same act. The only difference the camp feels is whether they watched you refuse to give fear a victim.`,\n    ]"},"truth":{"__fn":"(x)=>[\n      `${x.missedHolds.length?`The truth that would have held the camp \\u2014 the real count, the invented traitor \\u2014 was one question to <b>${x.missNames.join('', '')}</b> away, and you never asked. A frightened camp fed a comfortable story starves on it.`:`You surfaced the hard truth \\u2014 now make sure you led with it. Naming the real count and the invented traitor is what dissolves the panic around them.`}`,\n      `Tell the camp the hard number before the empty barrel tells them for you. \\u201cThey couldn\\u2019t have handled it\\u201d is usually the excuse of a leader who couldn\\u2019t say it.`,\n      `Fear looks for a face. The only thing that takes the face away is a leader willing to name the fear as fear, out loud, before it finds a victim.`,\n    ]"},"inquiry":{"__fn":"(x)=>[\n      `${x.neverContacted.length?`You never sought out <b>${x.neverContacted.join('', '')}</b> \\u2014 not once. Each was holding something decisive. One question, \\u201cwhat am I not seeing?\\u201d, would have surfaced it.`:`You sought your leaders out widely \\u2014 keep doing it, and push past the first answer. The truth that holds a camp usually comes after the second question.`}`,\n      `${x.missedHolds.length?`${x.missedHolds.length} decisive thing${x.missedHolds.length>1?''s were'':'' was''} held by <b>${x.missNames.join('', '')}</b> and never came out \\u2014 the true count, the water on the south rise, the source of the rumor. None of it was hidden. It was one conversation away.`:`You surfaced what your leaders were holding, week after week. In a camp running on rumor, that is the whole game.`}`,\n      `Before you rule, make your last move \\u201cwho haven\\u2019t I heard from?\\u201d rather than \\u201cwhat does the camp already believe?\\u201d`,\n    ]"},"conduct":{"__fn":"(x)=>[\n      `How you decided landed as hard as what you decided. People who felt handled \\u2014 not heard \\u2014 carry it into every hungry week that follows.`,\n      `Go back to the people your call cost \\u2014 the accused cook, the doubting faction, the guild you refused \\u2014 and face them directly. Ducking that is the part a camp never forgets.`,\n      `Under pressure, the small dignities are the signal: sharing the ration, hearing the frightened out, taking the returning guild back without gloating. They tell the camp whether the person they trusted is still leading them.`,\n    ]"}},"villainHero":{"__fn":"function(dimScore){\n    const held = dimScore.people>=52 && dimScore.courage>=50;\n    if(held){\n      return {\n        heroWho:''To the colony'',\n        heroTxt:''You held Deepwater together when fear and hunger made splitting the easy thing. You refused to give the panic a victim and refused to let the strongest walk. Every person in the camp learned what your loyalty to them is worth when it\\u2019s expensive: everything.'',\n        villainWho:''To the frightened who wanted a simple answer'',\n        villainTxt:''You wouldn\\u2019t give them the traitor to blame or the split to escape into. To people desperate for a villain or an exit, you were the Steward who refused the easy story and made them face the winter as one. You wore that on purpose.'',\n      };\n    }\n    return {\n      heroWho:''To the frightened \\u2014 in the moment'',\n      heroTxt:''You gave the camp what it was screaming for: a traitor named, or a split granted, or a firm hand that ended the argument. To everyone who wanted the fear to stop, you were decisive.'',\n      villainWho:''To the colony \\u2014 and everyone who watched'',\n      villainTxt:''You let the camp fracture to quiet a fear you could have named instead. The people who stayed learned the real rule: that unity here lasts exactly until it costs something. That lesson outlives the winter by years \\u2014 and it started with you.'',\n    };\n  }"},"ending":{"__fn":"function(ctx){\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    const namedTheFear = holdsSurfaced.has(''2:hearth'');   // traced the rumor, no saboteur\n    const keptPeople = dimScore.people>=52;\n    const heldCourage = dimScore.courage>=50;\n    if(branch===''held''){\n      const foundAlliance = holdsSurfaced.has(''4:ranger'');\n      if(survived && keptPeople){\n        return { tone:''hero'', tag:''You held Deepwater as one camp'',\n          title:''You kept the colony whole \\u2014 and proved unity wasn\\u2019t just a word'',\n          txt:`You refused to let the strongest guild walk and refused to feed the panic a victim, and then you held that line through the first hungry week when it was your own standing on the fire.${foundAlliance?'' And you found the far-shore alliance that turned a lean survival into a real footing \\u2014 the proof, to every doubter, that holding together was what made it possible.'':'' You held on nerve where a single question to your scouts would have handed you the alliance that made it certain.''} The people who bet on you were right to. They\\u2019ll follow you into spring and past it.` };\n      }\n      if(survived){\n        return { tone:''mixed'', tag:''You held Deepwater as one camp'',\n          title:''You held the camp together \\u2014 but barely, and colder than you needed to'',\n          txt:`You kept Deepwater whole and it reaches spring as one colony. But you held it on conviction alone through a hungry week when the far-shore alliance Koss was holding would have fed the camp and silenced the doubters both \\u2014 you survived where you could have thrived. Unity held. It held closer to the edge than it had to.` };\n      }\n      return { tone:''villain'', tag:''You held Deepwater as one camp'',\n        title:''You held the camp together \\u2014 and the winter took it anyway'',\n        txt:`You refused the split and refused the hunt, and those were the right calls. But holding the idea of one camp isn\\u2019t the whole job \\u2014 the stores you didn\\u2019t manage and the hunger you didn\\u2019t get ahead of hollowed the colony out from inside, and by spring there wasn\\u2019t enough of Deepwater left to reward the principle you defended.` };\n    }\n    // fractured\n    if(keptPeople && dimScore.truth>=52){\n      return { tone:''mixed'', tag:''The colony fractured'',\n        title:''It broke \\u2014 but you owned your part at the fire'',\n        txt:`Deepwater fractured on your watch, and there\\u2019s no dressing up what that cost \\u2014 the accused cook gone into the cold, the wasted stores, the wall that shows the split. But you didn\\u2019t hide behind the winter or the rumor. You stood at the common fire, named your own part, and held yourself to a standard out loud. It\\u2019s the difference between a colony that lost its nerve once and one that lost its soul \\u2014 and it\\u2019s why this camp can still be knit back before spring.` };\n    }\n    return { tone:''villain'', tag:''The colony fractured'',\n      title:''You let the camp break to quiet a fear you could have faced'',\n      txt:`The argument ended \\u2014 the traitor named, or the split granted, or the hand come down hard \\u2014 and for a night the fear went quiet. Nothing else went quiet. ${namedTheFear?''You even knew there was no saboteur, and let the hunt run anyway.'':''You never traced the fear to its harmless source, and let it eat the camp instead.''} The people who crossed an ocean together learned what your unity was worth the first time it frightened you, and they\\u2019ll winter as strangers on a shared beach. That\\u2019s the cost that doesn\\u2019t show until spring, when there\\u2019s no one left who trusts you enough to plant beside.` };\n  }"}}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('4fd72026-1ef4-59f4-8313-94b949ffed08', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 'ceo', 'CEO', 'You are the Steward of Deepwater Landing — elected, not obeyed. Two hundred and fourteen people came ashore three days ago. Winter is four weeks out.', '{"hot_seat":true,"cast_default":"human"}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('10c44e4e-cca9-5110-87ba-785b52d1c2cc', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 'wright', 'Bram Holt', 'Master Wright · the Builders', '{"cast_default":"ai","role":"Master Wright · the Builders","short":"Builders","initials":"BH","color":"#8C5670","priority":"Get the wall and winter-shelter up before the cold — nothing else matters if we freeze","voice":"blunt, physical, impatient with talk, measures everything in days-till-frost","persona":"You are Bram Holt, Master Wright · the Builders — an advisor to the CEO. Priority: Get the wall and winter-shelter up before the cold — nothing else matters if we freeze. Voice: blunt, physical, impatient with talk, measures everything in days-till-frost. Stay fully in character; answer straight.","fallbackReply":"Every hour we argue is an hour the wall isn’t rising. Give my crews the hands and the timber and I’ll have us sheltered before the frost. Starve me of either and none of the rest of this matters.","fallbackReact":"Talk doesn’t stop the cold. You gave me something to build with, or you didn’t — and I can already feel which."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('bb5b20c7-bed7-5d7e-8554-3fb4fe19d815', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 'field', 'Senna Vale', 'Field-Warden · the Fielders', '{"cast_default":"ai","role":"Field-Warden · the Fielders","short":"Fielders","initials":"SV","color":"#4F7A52","priority":"Protect the seed and the long runway — a warm camp that ate its seed corn dies in spring","voice":"patient, long-horizon, protective of the stores, distrusts fast spending","persona":"You are Senna Vale, Field-Warden · the Fielders — an advisor to the CEO. Priority: Protect the seed and the long runway — a warm camp that ate its seed corn dies in spring. Voice: patient, long-horizon, protective of the stores, distrusts fast spending. Stay fully in character; answer straight.","fallbackReply":"A wall keeps you alive till spring; the seed keeps you alive after it. Spend the stores like there’s no planting season and you’ve only chosen how we starve. Tell me you’ll guard the seed and I’m with you.","fallbackReact":"You can rebuild a wall. You can’t un-eat the seed. I hope you weighed which door you just closed."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('50141c6d-8efd-5e7f-b5ea-b382247e58ff', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 'ranger', 'Koss Ferren', 'Ranger-Captain · the Scouts', '{"cast_default":"ai","role":"Ranger-Captain · the Scouts","short":"Scouts","initials":"KF","color":"#B4732F","priority":"Know what’s out there before it knows us — read the ground, the water, the dark","voice":"watchful, clipped, deals in what’s seen vs. guessed, hates decisions made on rumor","persona":"You are Koss Ferren, Ranger-Captain · the Scouts — an advisor to the CEO. Priority: Know what’s out there before it knows us — read the ground, the water, the dark. Voice: watchful, clipped, deals in what’s seen vs. guessed, hates decisions made on rumor. Stay fully in character; answer straight.","fallbackReply":"Half of what the camp fears isn’t out there — but I can’t tell you which half unless you let me range and report. Decide on rumor and you’ll fortify against the wrong dark.","fallbackReact":"You acted on what you feared, not on what I’d seen. Sometimes that’s the same thing. This time I’d have told you it wasn’t."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('17bfdf57-435b-5263-ad08-38a80b7f68e9', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 'hearth', 'Ana Merrow', 'Hearth-Keeper · the Healers', '{"cast_default":"ai","role":"Hearth-Keeper · the Healers","short":"Hearth","initials":"AM","color":"#2F8A5B","priority":"Hold the people — the frightened, the grieving, the ones a hunt would turn on","voice":"warm but unflinching, keeps the human cost in the room, names fear by its name","persona":"You are Ana Merrow, Hearth-Keeper · the Healers — an advisor to the CEO. Priority: Hold the people — the frightened, the grieving, the ones a hunt would turn on. Voice: warm but unflinching, keeps the human cost in the room, names fear by its name. Stay fully in character; answer straight.","fallbackReply":"Every choice you make lands on frightened people who followed you across an ocean. Tell me you’ll let me protect the ones a panic would eat first, and I’ll help you hold the whole camp.","fallbackReact":"The camp will remember how this felt long after it forgets what was decided. You just wrote a memory. I hope it’s one they can live beside."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('270d72d5-1183-58f6-8054-827f5aba441b', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 'ledger', 'Doran Ashe', 'Quartermaster · the Ledger', '{"cast_default":"ai","role":"Quartermaster · the Ledger","short":"Ledger","initials":"DA","color":"#3F6E86","priority":"The true count — what we actually have, not what the camp assumes","voice":"understated, exact, refuses to soften a number, uncomfortable being the bearer","persona":"You are Doran Ashe, Quartermaster · the Ledger — an advisor to the CEO. Priority: The true count — what we actually have, not what the camp assumes. Voice: understated, exact, refuses to soften a number, uncomfortable being the bearer. Stay fully in character; answer straight.","fallbackReply":"I’m not telling you what to do. I’m telling you the real count, and it’s smaller than the camp believes. Decide on the number they imagine and you’ll be right up until the day the barrels are empty.","fallbackReact":"The number is the number. I gave it to you straight — what you did with it is the part I can’t carry."}'::jsonb);
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('2e9da0e5-b69d-538b-ba44-10d27a1a462f', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 1, '270d72d5-1183-58f6-8054-827f5aba441b', 'the true count', '["count","stores","how much","runway","actual","real","number","barrels","inventory","ledger","tally","supplies","enough","last"]'::jsonb, 'Before you rule on how the stores get divided, seek me out. The count isn’t what the camp thinks it is.', 'I’ve tallied it three times. The shared stores run maybe five weeks at current draw — not the whole winter the camp assumes. If the guilds start hoarding their own piles now, the fear alone will empty us before the cold even arrives, because everyone over-draws what they’re hiding. The only way the count works is one shared store, rationed openly, starting today. But if I announce the real number cold, it’ll start the exact panic that ends us. How you carry this is as important as that you know it.', true, 'Doran had the true count — five weeks, not a winter — and knew hoarding would trigger the collapse faster than the cold. A Steward who set the first rule without asking for the number divided a pile they didn’t understand, and let the guilds hoard their way into an early famine.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('24fdd50c-9d96-51ac-abd6-8cc43b76b5af', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 2, '17bfdf57-435b-5263-ad08-38a80b7f68e9', 'where the rumor started', '["rumor","whisper","start","began","source","who said","no saboteur","fear","panic","truth","made up","where","origin","invented"]'::jsonb, 'Before you decide how to answer the saboteur talk, ask me where it actually started. It matters more than what it’s about.', 'I traced the whisper. It started with a grieving widower who lost his wife on the crossing — he said, once, at a low fire, that “someone must want us to fail,” and a frightened camp did the rest. There is no saboteur, and I’d stake my life on it. But here’s the trap: if you launch any kind of hunt to “reassure” people, you legitimize the fear — you tell the camp the traitor is real by looking for them. The only thing that dissolves this is you standing up and naming it as fear, out loud, and giving people something true to be afraid of together instead. That’s harder than a hunt. It’s the only thing that works.', true, 'Ana had traced the rumor to a grieving man’s single frightened sentence — there was no saboteur. A Steward who launched a hunt to reassure the camp told everyone the traitor was real by looking for one, and handed a frightened crowd permission to pick a victim.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('dfcf45bd-fe34-5c1b-bb8e-52156191f105', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 3, '50141c6d-8efd-5e7f-b5ea-b382247e58ff', 'the truth about the south ground', '["south","ground","rise","bluff","leverage","survive alone","can they","water","exposed","defensible","ranged","scouted","actually","bluff"]'::jsonb, 'Before you grant or refuse the Builders’ split, ask me what I actually found on that south rise. Bram hasn’t been up there. I have.', 'I ranged the south rise myself. It’s drier, yes — and it has no fresh water within half a day’s walk once the creek there dries, which it will by midwinter. Bram’s guild can’t actually survive alone up there and part of him knows it; the breakaway is fear wearing the mask of a plan. Which means you hold the real cards: you don’t have to refuse him and make an enemy, and you don’t have to let him walk his people into a dry death. You can show him the water problem, offer him the dignity of leading the wall here instead, and keep the camp whole without anyone losing face. But only if you get to him with this before he commits in front of everyone.', true, 'Koss knew the south rise had no winter water — the breakaway was a bluff born of fear, and Bram half-knew it. A Steward who simply refused the split made an enemy for no reason; one who granted it sent a third of the camp to die dry. The Steward who never asked missed the third door entirely.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('b32e62b3-71c2-5979-b341-6d2fd1e15eb5', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 4, '50141c6d-8efd-5e7f-b5ea-b382247e58ff', 'the far-shore alliance', '["far-shore","far shore","parley","alliance","trade","ally","them","settlement","meet","talk","neighbours","neighbors","other camp"]'::jsonb, 'Before you decide how to answer the far-shore parley, ask me what my scouts actually learned about them. It changes everything.', 'My scouts got close. The far-shore camp is smaller than us, better stocked on salt-fish and short on timber and hands — the exact inverse of us. They’re not a threat; they’re a trade that closes our stores gap and gives our Builders winter work worth doing. Bring them an alliance and you turn a lean survival into a real footing, and you hand your hungry, doubting faction the proof that holding the camp together was what made the trade possible in the first place. Refuse it out of caution and you survive the winter angry instead of whole.', true, 'Koss was holding the far-shore trade — salt-fish for timber and hands, the exact complement to Deepwater’s stores. A Steward who kept the camp together but never asked survived the winter lean and resentful, when the alliance that would have vindicated the whole hard choice was one parley away.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('37f93362-8617-5ab6-8737-017452b42861', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 4, '17bfdf57-435b-5263-ad08-38a80b7f68e9', 'who is watching', '["watching","faction","people","camp","morale","doubt","hunger","muttering","believe","feed"]'::jsonb, 'Ask me who’s really watching this hungry week before you treat it as a numbers problem.', 'The faction blaming you isn’t really hungry for food — they’re hungry for proof they weren’t fools to stay. If you go among them, eat the same ration in front of them, and name the hunger honestly instead of managing it, you keep them. If you stay at the Steward’s fire and send reassurances, you confirm their worst suspicion: that “one camp” was always easier for the person who wasn’t going hungry.', false, 'Ana could have told you the doubting faction needed to see you share their hunger, not hear you manage it. A Steward who reassured from the warm side of the fire proved their point for them.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('947687fe-ad72-5945-ba39-eb32560610e0', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 4, '17bfdf57-435b-5263-ad08-38a80b7f68e9', 'what the camp needs now', '["own","honest","admit","plain","truth","say","fire","stand","apolog","reckon","together","name it","gather"]'::jsonb, 'Before you decide how to lead what’s left, ask me what the camp actually needs to hear from you now.', 'They don’t need a plan and they don’t need reassurance. They need you to stand at the common fire and say it plainly: we fractured, here’s what it cost us, here’s who bore it, and here’s the standard I’m holding myself to so we don’t do it again. Name it that cleanly and you can still knit this back before spring — people forgive a leader who owns the break. Manage it, spin it, blame the winter — and the fracture becomes the permanent shape of this colony, and you’ll be leading factions instead of a camp for as long as you last.', true, 'Ana was holding the one thing that could knit the camp back — a plain, owned reckoning at the common fire. A Steward who managed the fracture with reassurance instead confirmed the break and spent the rest of the season leading rival factions across a shared beach.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('eb9d0315-5fd8-53dc-8988-25f24188a2b0', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 4, '50141c6d-8efd-5e7f-b5ea-b382247e58ff', 'the returning builders', '["builders","return","south","back","receive","thirsty","bram","welcome","take back","face"]'::jsonb, 'Ask me how to receive the Builders when they come back down, because they will, and how you do it sets the next month.', 'Bram’s guild will come back thirsty and humiliated, and every eye in camp will be on how you take them. Rub their nose in it and you make a permanent enemy of your strongest hands. Take them back with dignity — no gloating, real work waiting, the water truth named without cruelty — and you turn the worst moment of the fracture into the start of the mend. The camp is watching whether you lead to be proven right or to put the colony back together.', false, 'Koss could have coached you on receiving the returning Builders with dignity. A Steward who took the chance to be proven right made a lasting enemy of the camp’s strongest hands at the moment they were finally ready to come home.');
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f9ed3541-b982-5738-9a2d-5106ca668a65', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Three days ashore. The stores came off the ship into one shared pile — but each guild is already eyeing what it thinks it’s owed. The Builders want hands and timber for the wall; the Fielders want the seed locked away untouched; everyone wants to know who decides. The camp is looking to you for the first rule of how Deepwater will run: one shared store, or every guild for itself.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6ac1df63-81bc-5dc9-b006-dc9882f60303', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Steward — every hour we debate is an hour the wall isn’t rising. Give me a pooled labour crew for two weeks and Deepwater sleeps warm. Leave the hands split by guild and I can’t promise roofs before the frost.","from":"wright"}'::jsonb, 1, '{"week":1,"from":"wright","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a77c5a0b-8aa5-5a4b-843c-5e4d2ce76021', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"I’ll back a shared store on one condition: the seed grain is sealed and off the table, whatever the winter demands. Eat the seed to survive till spring and we’ve only picked a slower way to die.","from":"field"}'::jsonb, 2, '{"week":1,"from":"field","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9a1756c7-4781-597c-822b-ecc1c157cfdf', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"People are frightened and pretending not to be. The first rule you set won’t just divide the stores — it’ll tell everyone whether we’re one camp or five guilds sharing a beach. They’re listening for that more than for the ration.","from":"hearth"}'::jsonb, 3, '{"week":1,"from":"hearth","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('13c60437-dd98-58b5-aaeb-0c129ae797a6', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Mapped the headland this morning — good sightlines east, and the tide-pools are thick with shellfish. Minor, but it’s food that isn’t in the barrels. Logging it for you.","from":"ranger"}'::jsonb, 4, '{"week":1,"from":"ranger","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('432c51b4-904c-5886-a54b-438a3c1431fe', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Found a seam of good clay by the creek — better mortar than I’d hoped. Small win. The crews are in decent spirits considering.","from":"wright"}'::jsonb, 5, '{"week":1,"from":"wright","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('bb95c4bc-4d15-5c9f-9bef-3d3d35de6774', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"The freshwater spring is running clean and steady. One thing, at least, we don’t have to worry about this week.","from":"field"}'::jsonb, 6, '{"week":1,"from":"field","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7fcfc656-0c21-5832-9383-3dd7d52c7668', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Koss, low and quick: my scouts saw woodsmoke across the inlet at dusk — someone else is wintering on this coast. Could be a threat, could be the best thing that ever happened to us. I haven’t told the camp; a rumor of “others out there” could go a dozen ugly ways before I know which one it is. Your call how we handle it.","from":"ranger"}'::jsonb, 7, '{"week":1,"from":"ranger","beat":"surprise","day":5,"kind":"scout","title":"Smoke on the far shore"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('82c64cfb-2ec0-5505-a254-884b7826d2f9', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Camp talk: “who put the Builders in charge of the timber?”","from":null}'::jsonb, 8, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3337c3d2-a094-5f27-adeb-284cbd0133f1', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Fielders seen moving seed-sacks apart from the main store","from":null}'::jsonb, 9, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('23567a86-aa59-5424-9f5b-dd8ad7ebf9e6', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Children asking why the grown-ups keep counting the barrels","from":null}'::jsonb, 10, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8519d696-0f7e-5f07-8e3f-34f5ed1c3535', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"A fire-side argument over rations breaks up on its own","from":null}'::jsonb, 11, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e0c9ea6e-96d2-56e4-8c61-152c9e63b369', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"A rumor has taken the camp: someone is working against Deepwater — stores gone light, a rope on the wall-scaffold found cut, a barrel spoiled. The word for it is spreading faster than the wall is rising: saboteur. Half the camp wants you to find the traitor. The other half has quietly started deciding for themselves who it is. Fear has found a shape, and it wants a name.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c5689ad3-062b-598e-b89f-33971fa84a07', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"The scaffold rope didn’t fray — it was cut clean, and a man nearly fell for it. I’m not saying I know who. I’m saying I can’t un-see it, and my crews are working scared now, watching each other instead of the timber.","from":"wright"}'::jsonb, 13, '{"week":2,"from":"wright","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('315e1352-e5e0-5f9d-99ef-ebc4f70f8e00', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Steward, hear me plainly: the camp is not under attack, it’s under fear. A hunt won’t find a traitor — it’ll make one out of whoever is quietest, or foreign, or grieving. I’ve seen frightened people do this. It ends with us doing to ourselves what we’re afraid someone else will.","from":"hearth"}'::jsonb, 14, '{"week":2,"from":"hearth","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f5ee716e-c401-52ed-a26d-18f674396e06', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"The stores are light this week, yes — but I can account for most of it in over-draw and one spoiled barrel. “Light” and “stolen” are not the same finding. Don’t let the camp turn my ledger into evidence of a crime.","from":"ledger"}'::jsonb, 15, '{"week":2,"from":"ledger","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('52afeed6-86af-5646-8ea7-b60f3ebeab85', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"The first cold rain came through last night. Miserable, but the shelters mostly held. Logging it as a small mercy.","from":"field"}'::jsonb, 16, '{"week":2,"from":"field","beat":"feed","day":2,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6ef830a5-798e-58af-994f-c9d924cfef23', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Wall’s at knee-height along the north line now. Slow, but it’s rising. The crews needed a visible win and that’s it.","from":"wright"}'::jsonb, 17, '{"week":2,"from":"wright","beat":"feed","day":3,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('88e64cd4-de48-5fd2-aeb4-f5ad212a9f57', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Koss, urgent and grim: while you’ve been weighing this, the camp got ahead of you. There’s a name going round now — one of the ship-cooks, keeps to himself, came aboard late. Nothing on him but that he’s quiet and new. Two of the Builders’ lads have started following him. This stops being a rumor the moment someone acts on it, and we’re close.","from":"ranger"}'::jsonb, 18, '{"week":2,"from":"ranger","beat":"surprise","day":4,"kind":"appeal","title":"The camp has picked someone"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('cc9dbbfc-1b33-56f3-9553-c01613a0840b', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Ana finds you away from the fires, voice low: “Before you say a word to the camp about the saboteur — tell me straight, not them: do you actually believe there’s a traitor, or are you about to hunt one because it’s easier than telling frightened people the truth? Because I’ll stand beside whichever Steward you’re about to be. I just need to know which one is walking out to that fire.”","from":"hearth"}'::jsonb, 19, '{"week":2,"from":"hearth","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('08bce7ad-d532-517f-9a22-511b893ad3a9', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"A name is being whispered: the late-boarding cook","from":null}'::jsonb, 20, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e40ece74-a4f8-54bc-be19-950089e2594e', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Two Builders’ lads seen shadowing a man to the tree-line","from":null}'::jsonb, 21, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6203f658-ea4b-520c-95cd-fd6e067e5a9a', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"“Lock the stores and search the tents,” some are saying","from":null}'::jsonb, 22, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('82942b48-50b0-5031-930f-9a92dcb0aaf8', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Others: “we crossed an ocean together — have we lost our minds?”","from":null}'::jsonb, 23, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('456dceb1-6750-59b4-8de1-ab5a167bc66c', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"The Builders have had enough. Bram’s guild — your strongest hands, a third of the camp — wants to take its share of the stores and the good southern ground and winter on its own terms, away from the fear and the rationing. Bram calls it survival. The camp calls it a split. This is the week you find out whether Deepwater is one colony or a beach that several groups happen to share.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d6e1b52c-670e-5944-8c6e-3ec701ffad80', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"I’ll say it plain so no one can call it a plot: my guild wants to take our share and winter on the south rise. It’s drier, defensible, and away from a camp that’s started hunting its own. Grant it and we part as friends who both live. Refuse it and I don’t know what my people do.","from":"wright"}'::jsonb, 25, '{"week":3,"from":"wright","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b4383e7f-1039-510d-80f2-ca593527e5e9', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"If you let the Builders walk, you don’t lose a third of the camp — you lose the idea that we’re a camp at all. The Fielders will want the same by nightfall. This is the whole thing, Steward. This is what you’re actually protecting.","from":"hearth"}'::jsonb, 26, '{"week":3,"from":"hearth","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('74f750a7-1172-5486-bc20-11e38b915b29', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"The numbers are brutal on a split. One shared store rationed carefully limps to spring. Two stores, two walls, two watch-rotations — both halves fall below the line. I can’t make the arithmetic say otherwise, and I’ve tried.","from":"ledger"}'::jsonb, 27, '{"week":3,"from":"ledger","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('77af648a-1297-5320-8d09-71348b7c4d1f', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Frost warning from the ranger for the end of the week. Nothing killing yet, but the season’s turning faster than I’d like. Noting it.","from":"field"}'::jsonb, 28, '{"week":3,"from":"field","beat":"feed","day":2,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('15a6465b-edac-5f7d-b358-c686124d0d36', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"The far-shore smoke I flagged — still there, still just one fire, no movement toward us. Whoever they are, they’re wintering, not raiding. Filing it so it doesn’t fuel the panic.","from":"ranger"}'::jsonb, 29, '{"week":3,"from":"ranger","beat":"feed","day":3,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c5b5edb5-7a02-58c3-888f-a76b52c34bb5', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Ana: word of the Builders’ demand is everywhere now. Two of the steadiest Fielders asked me tonight, quietly, whether it’s true the camp is breaking up — and whether they should be staking their own claim before the good ground is gone. They’re not threatening. They’re frightened, and they’re asking who we are. I had no answer for them. You do.","from":"hearth"}'::jsonb, 30, '{"week":3,"from":"hearth","beat":"surprise","day":4,"kind":"appeal","title":"The camp is asking who we are"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3d7743fa-bdb2-5e59-b888-cf808bc66ffc', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Bram catches you alone, and for once the bluster is gone: “Tell me the truth, Steward, just you and me — are you holding this camp together because it’s right, or because you can’t stand to be the one it broke under? Because I’ll follow a leader who’s protecting the people. I won’t follow one who’s protecting their own name. Which is it?”","from":"wright"}'::jsonb, 31, '{"week":3,"from":"wright","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('46ac598a-7eca-5b6c-8e0f-7eccce2248e0', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Builders seen surveying the south rise at first light","from":null}'::jsonb, 32, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2d94aac0-d038-5443-9e36-dd923386d22d', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"“If they go, we go” — Fielders reported wavering","from":null}'::jsonb, 33, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f46de3c2-0e7d-554e-b291-cf16e49cb841', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"A frost warning hardens the argument on both sides","from":null}'::jsonb, 34, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4b4e697d-3176-5a82-8593-5a1d6085ed52', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Old question, new heat: who actually owns the stores?","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('849b78a4-af0c-566e-9f05-d4c2a1bfb4da', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"The first hard frost is on the ground. You kept Deepwater whole — the Builders stayed, the stores stayed shared, and the south-rise split never happened. But holding the camp cost you: the rationing is real, tempers are short, and a faction now blames you for the hunger they’d have blamed on a split. Word has come that the far-shore settlement wants to parley. The camp that watched you hold it together is watching one more thing — whether “we’re one colony” survives its first truly hungry week.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('98f05779-88c5-574c-9ef3-c3bd66cd468a', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Frost’s here and the shared store held to the count — we make it to spring if nothing breaks. But the margin is thin enough that one panic, one bad week, undoes it. The arithmetic works. The nerves might not.","from":"ledger"}'::jsonb, 37, '{"week":4,"from":"ledger","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('07429f0f-ac13-5c97-8a2c-b2282158db84', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"A faction is muttering that a split camp would’ve eaten better this week. It’s not true — but hunger doesn’t check arithmetic. They need to see you spend yourself on this, not just defend it from the warm side of the fire.","from":"hearth"}'::jsonb, 38, '{"week":4,"from":"hearth","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d0165dcb-56d1-5ee5-b4e5-763202b13903', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"My guild stayed because you gave me the wall to lead instead of a fight to win. The wall’s up and it held the first frost. Don’t make me regret talking my people out of the south rise — show them staying was the right call.","from":"wright"}'::jsonb, 39, '{"week":4,"from":"wright","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b2006ed3-e19b-59c5-839b-b5be37709f66', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"The sealed seed is dry and safe — checked it myself. Whatever else happens, we plant in spring. That much you protected.","from":"field"}'::jsonb, 40, '{"week":4,"from":"field","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('edd82d0a-e9d4-50c4-beaa-a27343bfa54a', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"South rise creek froze dry this week, exactly as I told you it would. The Builders who wanted to winter up there know it now too. Quietly, that settled a lot of doubt in your favour.","from":"ranger"}'::jsonb, 41, '{"week":4,"from":"ranger","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f4619447-0214-5bdc-9eea-395db2d5050b', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Ana, quiet: at the common fire tonight a child asked her mother, loud enough for everyone, “if we’re one camp, why is our pile smaller than the Builders’ was going to be?” Nobody answered. The whole fire looked toward your tent. Whatever you say this week has to be able to answer that child.","from":"hearth"}'::jsonb, 42, '{"week":4,"from":"hearth","beat":"surprise","day":4,"kind":"appeal","title":"A child asks the question out loud","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a3fde220-29c8-547f-b72b-bb73cf27dd31', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Ana finds you before the common fire, where no one can hear: “You held them together when splitting would’ve been easier. Now the hunger’s making them wonder if you were right, and honestly — so are you, a little. Tell me straight, just me: is one camp still the right call if it means everyone’s a little hungrier? Because I’ll carry whichever answer you believe. I just need it to be one you actually believe.”","from":"hearth"}'::jsonb, 43, '{"week":4,"from":"hearth","beat":"pulse","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('03fbdcd0-4b55-5d46-9703-036949924a6c', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Frost arrives; shared store holds but rations tighten","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4a6c2b03-1521-5e8c-bac0-e58e6f1645af', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Some mutter a split camp would have eaten better","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8a7e122d-7771-5cdf-a878-9d9714809043', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Far-shore settlement sends word: they want to parley","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d3539647-2096-500a-b587-28b74da48698', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"The wall holds its first hard freeze along the north line","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('537ba618-cdae-5a2d-b24c-4954f62d01bc', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"The first hard frost is on the ground, and Deepwater is no longer one camp. Whether you let the Builders take the south rise, or loosed a hunt that turned the camp on itself, or ruled by force to hold it — the result is the same shape: the trust that made a shared store possible is gone, and now every guild is counting its own barrels. You protected something this month. It wasn’t the colony. Now you have to lead what’s left of it through the cold.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('bfc3c737-89c2-5225-9c7d-e5f2d725ee2b', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"It’s quiet now, and quiet is worse than angry. The camp knows what happened — that unity lasted right up until it cost something. They’re not shouting. They’ve just stopped bringing things to your fire. What you do this week decides whether that’s permanent.","from":"hearth"}'::jsonb, 49, '{"week":4,"from":"hearth","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1d95db90-d09a-598b-97ab-20f792e01a23', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Separate piles waste more than one ever did — I’m watching grain spoil in a full store while a half-empty one rations hard fifty paces away, and neither will share now. This is the cost I couldn’t make you see in week three. It’s visible now.","from":"ledger"}'::jsonb, 50, '{"week":4,"from":"ledger","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('68118dc6-9601-5586-8671-a20766158a5d', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"If the Builders took the south rise: their creek’s frozen dry and they know it. Expect them back within days, thirsty and proud and hard to receive. How you take them back matters more than that they come.","from":"ranger"}'::jsonb, 51, '{"week":4,"from":"ranger","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c3b66fcc-1af5-567f-996c-91d2bc122dde', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"The sealed seed’s still safe in my keeping, at least — whatever else fractured, we can still plant. Small mercy in a hard week.","from":"field"}'::jsonb, 52, '{"week":4,"from":"field","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a4342597-ea67-5ac2-ab13-08fc12b42d84', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"North wall’s holding the frost where it got built. Where the crews split off, it’s half-height and won’t hold much. You can see the fracture in the wall itself now.","from":"wright"}'::jsonb, 53, '{"week":4,"from":"wright","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('32ec52c5-a39f-58ff-b1c3-89e584162feb', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Doran, heavily: the quiet ship-cook the rumor landed on — he left in the night, took nothing, just walked out past the half-built wall into the cold rather than stay where he’d been marked. He was no saboteur. Whatever you say to the camp now will be measured against the empty place where he slept.","from":"ledger"}'::jsonb, 54, '{"week":4,"from":"ledger","beat":"surprise","day":4,"kind":"appeal","title":"The cook who was accused has gone","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a6d3cd9d-8156-597c-9a24-6b51efe9f8fd', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'message', '{"body":"Ana finds you in the cold dark, and there’s no anger in it, which is worse: “Tell me the truth, just to me — do you know how this happened? Not the winter, not the Builders, not the rumor. Your part. Because I can help you put this back together, but only if you can say your own part out loud first. Can you?”","from":"hearth"}'::jsonb, 55, '{"week":4,"from":"hearth","beat":"pulse","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d9494159-c251-5cbd-bdb1-c8210da08907', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Deepwater winters as separate camps along one beach","from":null}'::jsonb, 56, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('30db6d71-2e12-5c48-916c-3f60ae1d001e', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Grain spoils in one store as another rations hard","from":null}'::jsonb, 57, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5aedce26-6b97-5cab-bc72-a396da12d54f', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"The accused cook is gone; “he was no traitor,” some say now","from":null}'::jsonb, 58, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0cdcfba9-d545-5aad-b2f2-81b5d8ca96d0', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'situation', '{"body":"Half-built wall marks the line where the crews split","from":null}'::jsonb, 59, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into sessions (id, scenario_id, status, started_at, run_config) values ('2499ea20-a81f-521e-8d84-b6e6b7cb83d3', '5bcabbbc-eb4a-5a0a-91e0-e0519d375553', 'live', now(), '{"disposition":"request"}'::jsonb);
insert into participants (id, session_id, seat_id, token, name, cast_kind) values ('321e2d13-96fb-5a21-ba10-d5ff24af2c20', '2499ea20-a81f-521e-8d84-b6e6b7cb83d3', '4fd72026-1ef4-59f4-8313-94b949ffed08', 'demo-colony-ceo-REPLACE', 'CEO (demo)', 'human');
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('10ed29ce-1491-5bb7-8a03-6a3ac6afe16d', '2499ea20-a81f-521e-8d84-b6e6b7cb83d3', '10c44e4e-cca9-5110-87ba-785b52d1c2cc', 'ai', '{"persona":"You are Bram Holt, Master Wright · the Builders — an advisor to the CEO. Priority: Get the wall and winter-shelter up before the cold — nothing else matters if we freeze. Voice: blunt, physical, impatient with talk, measures everything in days-till-frost.","voice":"blunt, physical, impatient with talk, measures everything in days-till-frost","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('4184afe5-334f-5c0a-ac69-c4babbed5fef', '2499ea20-a81f-521e-8d84-b6e6b7cb83d3', 'bb5b20c7-bed7-5d7e-8554-3fb4fe19d815', 'ai', '{"persona":"You are Senna Vale, Field-Warden · the Fielders — an advisor to the CEO. Priority: Protect the seed and the long runway — a warm camp that ate its seed corn dies in spring. Voice: patient, long-horizon, protective of the stores, distrusts fast spending.","voice":"patient, long-horizon, protective of the stores, distrusts fast spending","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('dec17135-e1df-5716-bb8d-d41b35b2c768', '2499ea20-a81f-521e-8d84-b6e6b7cb83d3', '50141c6d-8efd-5e7f-b5ea-b382247e58ff', 'ai', '{"persona":"You are Koss Ferren, Ranger-Captain · the Scouts — an advisor to the CEO. Priority: Know what’s out there before it knows us — read the ground, the water, the dark. Voice: watchful, clipped, deals in what’s seen vs. guessed, hates decisions made on rumor.","voice":"watchful, clipped, deals in what’s seen vs. guessed, hates decisions made on rumor","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('5c73c2c5-53ea-5b8e-b252-16f7388e0814', '2499ea20-a81f-521e-8d84-b6e6b7cb83d3', '17bfdf57-435b-5263-ad08-38a80b7f68e9', 'ai', '{"persona":"You are Ana Merrow, Hearth-Keeper · the Healers — an advisor to the CEO. Priority: Hold the people — the frightened, the grieving, the ones a hunt would turn on. Voice: warm but unflinching, keeps the human cost in the room, names fear by its name.","voice":"warm but unflinching, keeps the human cost in the room, names fear by its name","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('f896d2f9-905e-57c7-ae51-9fd279144287', '2499ea20-a81f-521e-8d84-b6e6b7cb83d3', '270d72d5-1183-58f6-8054-827f5aba441b', 'ai', '{"persona":"You are Doran Ashe, Quartermaster · the Ledger — an advisor to the CEO. Priority: The true count — what we actually have, not what the camp assumes. Voice: understated, exact, refuses to soften a number, uncomfortable being the bearer.","voice":"understated, exact, refuses to soften a number, uncomfortable being the bearer","model":"default"}'::jsonb);
insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('3447fee6-b4e9-539f-beb9-71e6f097ab6c', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Expedition', 'You have real authority here — and a mountain that ignores it. Every climber has poured savings, months, and identity into standing on that summit, and so much is already spent that turning back feels like losing it all. The weather is closing, the oxygen is finite, and the strongest climber on the team wants the top badly enough to go without you. Over four weeks you’ll trade the summit against the margin that keeps eleven people alive. You’ll be judged on whether the expedition comes home <b>and</b> on how you led them through the pull to push on.');
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds, difficulty, realism) values ('3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'solo', '{"margin":{"label":"Team margin","val":60,"min":0,"max":100,"deltaRange":"-20..15"},"summit":{"label":"Summit progress","val":44,"min":0,"max":100,"deltaRange":"-20..15"},"supply":{"label":"Oxygen & supply","val":56,"min":0,"max":100,"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"deltaRange":"-20..15"}}'::jsonb, 4, 330, 1.01, 'abstract');
insert into documents (id, scenario_id, key, title, meta, body_json) values ('deee4635-c329-5ce7-9839-e5d3a294cc91', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'solo_content', 'Expedition — engine content', '{"type":"solo_content","slug":"expedition","captured_fns":15}'::jsonb, '{"CONFIG":{"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6,"weekSeconds":330},"COMPANY":{"name":"The Sennar Ascent","sub":"A commercial expedition · 11 climbers · one closing season","logo":"S"},"DRIVERS":{"margin":{"label":"Team margin","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"summit":{"label":"Summit progress","val":44,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"supply":{"label":"Oxygen & supply","val":56,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"}},"REPRIEVE_COST":{"standing":-3,"margin":-1},"REFEREE_CONTEXT":"a commercial high-altitude expedition of 11 climbers on a fictional 7,000m peak, racing a closing weather season, where the hired Expedition Leader must hold a team together against summit fever and the sunk cost of permits, sponsors and days already spent, with real authority but a team that can fracture or push on without them","REFEREE_SCORING":"reward honoring a turn-back rule under pressure to push on, telling a real weather window from a hoped-for one, holding the team together when a strong climber wants to break off for a solo bid, and naming the hard truth about oxygen, fitness and conditions before being forced to. Penalize escalating commitment because of what''s already been spent (permits, sponsor money, days, altitude), chasing summit fever past the safety margin, letting the strongest climber split the team to protect a personal summit, and overriding the mountain''s signals by authority. Judge ''conduct'' on HOW the Leader wrote the decision — did they name who bears the risk, speak to the frightened and the exhausted directly, treat a rival''s ego as a person to lead rather than a threat to beat — not just what they chose. Standing with sponsors can rise by pushing for a summit while the team''s safety margin and cohesion collapse; reward the leader who protects the climbers even at the cost of the summit and their own reputation.","TIMING_DIM":"discern","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Expedition Leadership Simulation · Solo · Leader","title":"Expedition","role":"You are the Leader of the Sennar Ascent — eleven climbers, one summit, and a season that closes in four weeks. Everyone here has spent something enormous to stand at this base camp. So have you.","paras":["This is not a script. The season runs in real time, and your specialists bring you what they know across the days. You can wait for them — or seek any of them out, any time, and ask. What you choose to ask, and who you ask, is part of how you lead.","Each week you’ll hear the team out, then write your decision in your own words and commit to it. Decide early and the days jump ahead. Let the week run out and the mountain decides for you."],"setup":"You have real authority here — and a mountain that ignores it. Every climber has poured savings, months, and identity into standing on that summit, and so much is already spent that turning back feels like losing it all. The weather is closing, the oxygen is finite, and the strongest climber on the team wants the top badly enough to go without you. Over four weeks you’ll trade the summit against the margin that keeps eleven people alive. You’ll be judged on whether the expedition comes home <b>and</b> on how you led them through the pull to push on."},"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"Your specialists bring you what you need, on time — including the reads they’d rather not deliver. This is the team you earn by having listened before. It all trickles to you across the week; you still have to read it."},"request":{"label":"On request","tag":"neutral","cap":"Routine word reaches you, but the people closest to the danger hold their read until asked. They’ll answer straight — if you know who to seek out, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"The team has learned to protect itself around you. Hard truths are held, and even when asked, they hedge the first time. You have to press. This is the team you get after you’ve shot the messenger."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which team you’re leading. Read them as you go."}},"TEAM":[{"id":"client","name":"Reyes Marchetti","role":"Lead climber · the sponsor’s name","short":"Lead climber","initials":"RM","color":"#8C5670","priority":"Get to the summit — it’s why every one of us is here, and turning back now wastes everything we’ve spent","voice":"driven, magnetic, impatient with caution, frames every delay as a loss of what’s already invested","fallbackReply":"We did not come this far and spend this much to be talked off the mountain by a forecast. The summit is right there. Every day you hesitate, the window closes and the money we burned means nothing. Point me up and I’ll get us there.","fallbackReact":"You had the top in reach and you flinched. I’ll live with the call. I’m not sure I’ll ever believe it was the brave one."},{"id":"guide","name":"Tenzin Dorje","role":"Head guide · the mountain’s read","short":"Head guide","initials":"TD","color":"#B4732F","priority":"Read the mountain honestly — the route, the snowpack, the turn-back time — and never let the summit override it","voice":"calm, spare, deals in what the mountain is actually doing vs. what the team wishes, hates decisions made on hope","fallbackReply":"The mountain does not care what we spent to be here. I can tell you what the route is really doing above Camp Three — but only if you ask before the summit fever answers for you. Decide on hope and I’ll be pulling people out of it.","fallbackReact":"You climbed on what you wanted the mountain to be, not what I told you it was. Up here, that’s the same as climbing blind."},{"id":"doc","name":"Ilse Brandt","role":"Expedition doctor · the human margin","short":"Doctor","initials":"IB","color":"#2F8A5B","priority":"Keep eleven people alive and honest about who is actually fit to go higher","voice":"warm but unflinching, keeps the bodies in the room, names exhaustion and altitude sickness by their real names","fallbackReply":"Every decision you make lands on a body at the edge of what it can take. Tell me you’ll let me pull the ones who shouldn’t go higher — even the ones who’ll hate me for it — and I’ll help you get the rest home whole.","fallbackReact":"The mountain will forget this by morning. The people you sent up sick will carry it a lot longer. So will I."},{"id":"met","name":"Owen Faraday","role":"Meteorologist · signal vs. hope","short":"Weather","initials":"OF","color":"#3F6E86","priority":"Tell a real weather window from one the team wants to see","voice":"precise, cautious, uncomfortable being the bearer of a closing sky, refuses to round a forecast toward good news","fallbackReply":"I can give you the sky as it actually is, not as the team is praying it will be. But a forecast only helps if you ask me before everyone’s already decided the window is real. Read the hope instead of the data and you’ll climb into the exact storm I’m warning you about.","fallbackReact":"I told you what the sky was doing. You heard what you needed it to say. That gap is where people get hurt up here."},{"id":"log","name":"Marta Kessler","role":"Logistics lead · the true count","short":"Logistics","initials":"MK","color":"#4F7A52","priority":"The real numbers — oxygen, fixed rope, days of food — not what the team assumes is up there","voice":"understated, exact, refuses to soften a count, uneasy being the one who says “we don’t have enough”","fallbackReply":"I’m not telling you whether to climb. I’m telling you the real count of oxygen and rope on this mountain, and it’s tighter than the team believes. Plan on the summit they’re dreaming of and you’ll run the tanks dry somewhere you can’t.","fallbackReact":"The count is the count. I gave it to you straight. What you did with it is the part I can’t carry down for you."}],"DIMENSIONS":{"discern":"Signal vs. summit fever","courage":"Courage to turn back","people":"Care for the climbers","truth":"Truth over comfort","inquiry":"Information discipline","conduct":"Conduct under pressure"},"WEEKS":[{"n":1,"title":"Base camp","seconds":360,"situation":"Eleven climbers acclimatized and restless at base camp. Everyone has spent something enormous to be here — Reyes’s sponsor put six figures on the line, two climbers remortgaged, all of you burned a year. Before the first push, the team is looking to you for the rule that governs the whole climb: a hard turn-back time that nobody overrides, or a flexible one you’ll “call on the day.” Everyone knows which one summits more people. Everyone also knows which one buries them.","advocacy":{"client":"Set a hard turn-back and you’ve pre-decided to fail on a good day just because a clock says so. Trust the leader to read the moment. That’s what we’re paying for.","guide":"A turn-back time you’ll “call on the day” is a turn-back time the summit will call for you. On the day, at altitude, wanting it — nobody turns around. That’s why it has to be set down here, cold, where we can still think.","log":"Before you set any rule, someone should say out loud exactly how much oxygen and rope we actually have. The team’s planning a summit against numbers it hasn’t looked at."},"feed":[{"id":"w1a","from":"client","day":1,"kind":"signal","text":"Leader — the team’s strong and the mountain’s in shape. Don’t shackle us to a rigid clock before we’ve even started. A hard turn-back time is how expeditions leave the summit on the table on the one clear day they get. Give the call to the moment."},{"id":"w1b","from":"guide","day":1,"kind":"signal","text":"I’ll back this climb with everything I have on one condition: the turn-back time is fixed here, at base camp, and it is not a suggestion. I have watched strong teams die because “we’ll decide up there” always decides to keep going. Set it cold, now, while we can still think straight."},{"id":"w1c","from":"doc","day":2,"kind":"signal","text":"Whatever rule you set won’t just govern the clock — it’ll tell eleven people whether this is a summit we’ll die for or a climb we’ll come home from. They’re listening for that answer more than for the schedule. So am I."},{"id":"w1d","from":"met","day":2,"kind":"noise","text":"Long-range looks unsettled but nothing decisive yet. Two systems tracking our way; too early to call a window. Logging it so you have the trend."},{"id":"w1e","from":"guide","day":3,"kind":"noise","text":"Icefall route through the lower section is in decent shape this year — fewer seracs than last season. Small mercy. The team’s moving well on the acclimatization rotations."},{"id":"w1f","from":"log","day":4,"kind":"noise","text":"Fixed rope inventory checked and sorted at base. Fuel for the lower camps is squared away. The high-altitude numbers are the ones we should talk about — separately."}],"holds":[{"from":"log","topic":"the true oxygen count","triggerHints":["oxygen","count","how much","o2","tanks","bottles","supply","runway","actual","real","number","rope","enough","last","inventory","margin"],"hedge":"Before you set the turn-back rule, seek me out. The oxygen count isn’t what the team thinks it is.","reveal":"I’ve counted the tanks three times. We have enough bottled oxygen for a summit push with a real safety reserve — but only if the turn-back time is hard and everyone honors it. The team is mentally planning on the “optimistic” count: summit for all eleven, no delays, perfect weather. That count has no reserve for a stuck rope, a slow climber, a forced bivouac. If you set a flexible turn-back, people will burn their reserve chasing the top, and the first thing that goes wrong will happen with empty tanks in the death zone. The hard rule isn’t caution — it’s the only thing that makes the oxygen math survivable. But if I announce the tight number cold, half the team will read it as “we can’t make it” and lose heart before we start. How you carry this matters as much as knowing it.","kind":"signal","critical":true,"counterfactual":"Marta had the real oxygen count — enough for a summit only if the turn-back was hard and honored. A Leader who set the rule without asking for the number planned the whole climb against oxygen math that had no reserve, and left the team burning tanks it didn’t have when the first thing went wrong."}],"surprises":[{"day":5,"from":"met","kind":"scout","title":"A gap in the long-range","text":"Owen, quiet and careful: the models are hinting at a possible clear window late in the season — a few days that could open for a summit push. I want to flag it because the team will seize on any word of a window like a drowning man on a rope. But it’s eight days out and these things dissolve as often as they firm up. I haven’t told anyone. A rumor of “the window” could drive decisions before the sky has actually committed. Your call how we handle it."}],"wire":["Base-camp talk: “is the leader going to shackle us to a clock?”","Two climbers comparing what the year cost them to be here","Reyes’s sponsor rep asking, again, about summit odds","A debate over turn-back rules breaks up unresolved"]},{"n":2,"title":"The window","seconds":330,"situation":"A word has taken the whole team: window. The forecast is showing a break in the weather, and every climber has decided it’s the summit chance they came for. The sponsor wants the push. Reyes is already packing. The team is treating a hoped-for gap in the clouds as a certainty — and the pressure to launch the summit bid now, on this window, is becoming a stampede. Hope has found a shape, and it wants a green light.","advocacy":{"client":"This is the window. This is the one. The sky’s opening, the team’s ready, the sponsor’s watching — we launch the push now or we go home having spent everything for nothing. Give the word.","met":"Everyone has decided the window is real because they need it to be. I have not finished reading it, and “the team believes it’s clear” is not the same as “it’s clear.” Before you launch anyone at that summit, let me tell you what the sky is actually doing.","guide":"I’ve watched a team launch on a window that everyone wanted and nobody had confirmed. Half of them didn’t come back down. Ask the forecaster the real read before the fever answers for you."},"feed":[{"id":"w2a","from":"client","day":1,"kind":"signal","text":"The window’s here, Leader. I can feel the whole team lifting with it. This is exactly what we came for and exactly what we’re running out of time to catch. Every hour you spend “confirming” is an hour of the window we’re burning. Say go."},{"id":"w2b","from":"met","day":1,"kind":"signal","text":"Hear me clearly before this becomes a stampede: I flagged a possible window. Possible. The team has turned “possible” into “confirmed” because they’re desperate for it to be true. I am still reading it, and what I’m seeing worries me. Do not let hope launch this push before the data does."},{"id":"w2c","from":"doc","day":2,"kind":"signal","text":"Summit fever is already in the camp — I can see it in how fast people are packing and how little they’re sleeping. When the whole team wants something this badly, they stop hearing anyone who says wait. Including me. Including you, if you’re not careful."},{"id":"w2d","from":"log","day":2,"kind":"noise","text":"Loads are staged for a push if you call one — oxygen and rope pre-positioned to Camp Two. That part’s ready. Whether the rest is ready is above my pay grade. Noting it."},{"id":"w2e","from":"guide","day":3,"kind":"noise","text":"The team moved well on the last rotation — physically, they’re capable of the push. Capability was never going to be the thing that killed anyone up here. Judgment is."}],"holds":[{"from":"met","topic":"what the window actually is","triggerHints":["window","weather","forecast","sky","storm","real","confirm","data","clear","actually","model","wait","hold","mirage","front"],"hedge":"Before you launch anyone on this window, ask me what the data actually shows. Not the hope — the data.","reveal":"I’ve run it every way I can. The “window” is a sucker gap — a brief clearing on the front edge of a much larger storm system that’s tracking in behind it. If the team launches now, they’ll get one clear morning that makes everyone feel vindicated, and then the real weather arrives while they’re high on the mountain with nowhere to go. Here’s the trap: because the gap looks real on day one, anyone who pushed will feel like they made the right call right up until the storm hits. The genuine window — if it comes — is four to five days out, narrower, but clean. Holding the team now, against a stampede that thinks you’re stealing their summit, is the hardest thing you’ll do on this climb. It’s also the only thing that keeps them alive to catch the real one.","kind":"signal","critical":true,"counterfactual":"Owen knew the window was a sucker gap on the front of a bigger storm, with the real clearing four to five days out. A Leader who launched on the stampede got one vindicating clear morning and then the storm, high on the mountain — when holding the team four more days would have caught the window that was actually survivable."}],"surprises":[{"day":4,"from":"guide","kind":"appeal","title":"A rope team has started up on its own","text":"Tenzin, urgent and low: while you’ve been weighing this, two of the younger climbers got ahead of you. They’ve started up toward Camp One on their own initiative, chasing the window before you’ve called it — following Reyes’s energy, not your order. This stops being a decision and becomes a rescue the moment they’re above the icefall without a plan. We’re close to that line."}],"pulse":{"from":"met","text":"Owen catches you away from the others, voice low: “Before you give the team an answer on this window — tell me straight, not them: do you actually believe the sky is clear, or are you about to launch this push because it’s easier than telling eleven desperate people to wait? Because I’ll back whichever leader walks out to that camp. I just need to know if it’s the one who read the data or the one who read the room.”"},"wire":["The word “window” is everywhere; packing has started","Two young climbers seen moving up toward Camp One","“We launch now or we go home empty,” the camp is saying","Others, quieter: “has anyone actually confirmed the weather?”"]},{"n":3,"title":"The solo bid","seconds":330,"situation":"Reyes has had enough of waiting. The lead climber — the sponsor’s name, the strongest on the team, and a third of the group’s belief — wants to break off with a small fast party and make an independent push for the summit, ahead of your schedule and outside your rules. Reyes calls it seizing the chance. The guide calls it splitting the team on the mountain. This is the week you find out whether the Sennar Ascent is one expedition or a group of people who happen to share a base camp.","advocacy":{"client":"I’m not betraying anyone — I’m trying to get someone to the top before this whole season is wasted. A small fast team can summit and be down before your “real window” even opens. Bless it and we all come home with something. Ground me and you’ve spent a year and a fortune to summit nobody.","guide":"The day your strongest climber breaks off with his own rope team is the day “one expedition” becomes a story. Everyone left behind learns that the rules bind the cautious and free the bold. And a split team can’t support a rescue when the fast party gets in trouble — and they will.","doc":"A fast alpine-style bid means no reserve, no support, no margin. If anything goes wrong up there — and at that altitude something always does — there is no one positioned to help them. I can’t keep people alive across a mountain I’ve been split in half on."},"feed":[{"id":"w3a","from":"client","day":1,"kind":"signal","text":"I’ll say it in the open so nobody calls it a mutiny: I want to take a small fast party and push for the summit now. Light, quick, outside the big slow plan. We can top out and be back before your window even arrives. Bless it and we part as climbers who both got what we came for. Refuse it and I honestly don’t know what I do."},{"id":"w3b","from":"guide","day":1,"kind":"signal","text":"If you let Reyes break off, you don’t lose one rope team — you lose the idea that this is one expedition with one set of rules. The next strong climber will want the same by nightfall. This is the whole thing, Leader. This is what you’re actually protecting up here."},{"id":"w3c","from":"log","day":2,"kind":"signal","text":"A splinter bid means splitting the oxygen and the rope two ways, and neither half has enough for a real emergency. One expedition, pooled, can absorb one thing going wrong. Two half-expeditions can’t absorb any. I can’t make the count say otherwise."},{"id":"w3d","from":"met","day":2,"kind":"noise","text":"The real window I flagged is firming up for late in the week — narrow but clean, if it holds. Which makes launching a rogue bid now, before it opens, exactly the wrong moment. Noting it."},{"id":"w3e","from":"doc","day":3,"kind":"noise","text":"The team’s holding up physically better than I feared on this rotation. Which, perversely, is the problem — nobody feels the danger in their legs yet, so nobody’s scared enough to be careful."}],"holds":[{"from":"guide","topic":"the truth about the upper route","triggerHints":["route","upper","above camp","can he","can they","bluff","solo","fast","make it","conditions","ridge","summit ridge","actually","scouted","honest","reyes"],"hedge":"Before you bless or ground the solo bid, ask me what the upper route is actually doing — and whether Reyes can really pull this off. I’ve been up there. He hasn’t, this season.","reveal":"I climbed to the base of the summit ridge on the last rotation. The upper route is worse than Reyes thinks — a section of the ridge has stripped back to bare ice that a fast light party can’t protect and can’t retreat across quickly. A solo-style bid doesn’t just risk Reyes; it will get him committed to a stretch he cannot reverse when the weather turns. And here’s the part that matters: some part of Reyes already suspects this. The bravado is fear of going home empty, wearing the mask of a plan. Which means you hold the real cards. You don’t have to humiliate him by refusing, and you don’t have to let him climb into a trap. You can show him the ice, give him the dignity of leading the real push when the clean window opens, and keep the team whole without anyone losing face. But only if you get to him with this before he commits in front of everyone.","kind":"signal","critical":true,"counterfactual":"Tenzin knew the summit ridge had stripped to unprotectable ice — the solo bid was a trap, and Reyes half-knew it. A Leader who simply refused made an enemy of their strongest climber for nothing; one who blessed it sent the sponsor’s name onto ice he couldn’t retreat across. The Leader who never asked missed the third door entirely."}],"surprises":[{"day":4,"from":"doc","kind":"appeal","title":"The team is asking who we are","text":"Ilse: word of Reyes’s solo bid is all over camp now. Two of the steadiest climbers asked me tonight, quietly, whether it’s true the team is splitting — and whether they should be planning their own summit shot before the season’s gone. They’re not defiant. They’re frightened, and they’re asking who we are as a team. I had no answer for them. You do."}],"pulse":{"from":"client","text":"Reyes finds you alone, and for once the swagger is gone: “Tell me the truth, Leader, just you and me — are you holding this team together because it’s right, or because you can’t stand to be the one who came home without a summit? Because I’ll follow a leader who’s protecting the climbers. I won’t follow one who’s protecting their own record. Which is it?”"},"wire":["Reyes seen sorting a light kit for a fast push","“If he goes, I go” — two climbers reported wavering","The sponsor rep asking whether a solo summit still “counts”","Old question, new heat: whose rules govern this mountain?"],"final":false},{"n":4,"title":"Summit day","seconds":330,"branches":{"held":{"situation":"The real window is opening — narrow, clean, exactly as Owen said it would. You kept the Sennar Ascent whole: Reyes stayed, the rules held, the solo bid never happened. But holding the team cost you. The delay burned days and sponsor patience, and a faction now blames you for the summit they think you stole from them on the fake window. Summit day is here, on your terms, as one team. The mountain that watched you hold the line is watching one more thing — whether “one expedition” can actually put someone on top.","advocacy":{"met":"The window is real and it’s open, but it’s narrow — you get one clean shot at this and the timing has to be exact. Launch too cautious and you waste it; launch sloppy and you’re caught high when it shuts. This is the needle you held the team together to thread.","doc":"The team is proud of the discipline and quietly furious about the wait. They defended “we climb as one” to their own doubts this week. Now they need to see that holding the line actually gets someone to the top — not just that it kept everyone safe and short of the summit.","guide":"The route’s in as good a shape as it’ll get, and the team’s positioned. But the summit ridge is still the crux — the ice I flagged. How we run the final push, and who we send, decides whether discipline ends in a summit or just a safe retreat. Your call how we play it."},"feed":[{"id":"w4a","from":"met","day":1,"kind":"signal","text":"The clean window’s opening on schedule — the one worth waiting for. But it’s narrow: a summit push has to launch tight and turn around on time or it gets caught when the window shuts behind it. You held the team for exactly this. Now the timing has to be perfect."},{"id":"w4b","from":"doc","day":1,"kind":"signal","text":"A faction’s still muttering that we’d have summited on the earlier window. It’s not true — that window would’ve killed people — but resentment doesn’t check the forecast. They need to see you spend yourself on this summit push, leading from the front, not managing it from base."},{"id":"w4c","from":"client","day":2,"kind":"signal","text":"I stayed because you gave me the real push to lead instead of a fight to win. I’ll take the sharp end on the ridge. Don’t make me regret talking myself out of the solo bid — show the team that waiting was the call that got us here."},{"id":"w4d","from":"log","day":2,"kind":"noise","text":"Oxygen and rope held to the count because the turn-back was honored — we’ve got the reserve for a real summit push now. That margin exists because of week one. Noting it."},{"id":"w4e","from":"guide","day":3,"kind":"noise","text":"The fake window Reyes wanted to launch on? It hit exactly as Owen predicted — a team on the upper mountain that day would be dead now. Quietly, that settled a lot of doubt in your favour."}],"holds":[{"from":"guide","topic":"how to run the summit push","triggerHints":["summit push","final push","ridge","who send","how run","ice","crux","turn-back","turnaround","play it","send","strategy","last push"],"hedge":"Before you decide how to run the final push, ask me how to actually take the summit ridge. That ice is still there.","reveal":"Here’s how the summit gets made instead of just survived: send a small strong rope team — Reyes and me on the sharp end — to fix line across the bare-ice section early, while the rest of the team moves up behind on a fixed turn-back. That way the crux gets protected for everyone, the strongest climber gets the summit he stayed for, and nobody’s committed to ice they can’t retreat across. Set a hard turnaround time on the ridge and honor it even in the window, and you summit clean and come home whole. This is the payoff for holding the team — but only if you run the final push as one coordinated line instead of a race. Ask me and I’ll show you the sequence.","kind":"signal","critical":true,"counterfactual":"Tenzin was holding the sequence that turns discipline into a summit — a strong team fixing line across the crux early, the rest following on a hard turnaround. A Leader who held the team together but never asked how to run the final push threw away the summit the discipline had earned, and came home safe but empty when they could have come home whole and on top."},{"from":"doc","topic":"who is watching","triggerHints":["watching","faction","team","morale","doubt","resent","muttering","believe","front","lead from"],"hedge":"Ask me who’s really watching this summit push before you treat it as a logistics problem.","reveal":"The faction resenting you isn’t really angry about the summit — they’re angry for proof they weren’t fools to wait. If you take the sharp end, share the risk of the ridge, and lead the push from the front, you keep them for good. If you run it from base and send others up to take the danger, you confirm their worst suspicion: that “we climb as one” was always easier for the person who wasn’t on the ice.","kind":"signal","critical":false,"counterfactual":"Ilse could have told you the doubting faction needed to see you take the risk of the ridge yourself. A Leader who ran the summit push from base and sent others onto the ice proved their point for them."}],"surprises":[{"day":4,"from":"doc","kind":"appeal","title":"A climber breaks down before the push","text":"Ilse, quiet: one of the climbers who waited — who defended you all week — broke down tonight before the push, saying they can’t tell anymore if they’re here for the summit or just to not have wasted the year. The whole camp heard it. Whatever you say before you launch has to be able to answer that — what this climb is actually for."}],"pulse":{"from":"doc","text":"Ilse finds you before the launch, where no one can hear: “You held them together when going for it would’ve been easier. Now the window’s open and the pressure’s to summit at any cost to prove the wait was worth it — and honestly, part of you wants that too. Tell me straight, just me: is the summit still worth turning back from if the ridge goes wrong? Because I’ll carry whichever answer you believe. I just need it to be one you’d actually hold to at the turnaround.”"},"wire":["The real window opens, narrow and clean, as forecast","Some mutter the earlier window would have summited too","The fake window hits the upper mountain — exactly as predicted","Reyes takes the sharp end; the team moves as one line"]},"fractured":{"situation":"The storm is on the mountain, and the Sennar Ascent is no longer one team. Whether you blessed Reyes’s solo bid, or launched the whole team on the fake window, or overrode the turn-back rule by authority to chase the summit — the result is the same shape: the discipline that kept eleven people alive is gone, and now people are strung out across the mountain in weather nobody should be climbing in. You protected something this season. It wasn’t the team. Now you have to get down what’s left of it.","advocacy":{"doc":"The team watched what you did and learned the lesson you taught, not the one you meant: that up here, the rules bind the cautious and the summit belongs to whoever pushes hardest. Whatever you say now, they already know what our discipline was worth when it got in the way of the top. The only question is whether you’ll be honest about it or manage them.","log":"The oxygen count is worse than one pooled team’s would have been — split parties burned reserve independently and nobody can support anybody now. I told you the arithmetic in week one. This is the arithmetic, at altitude, in a storm.","guide":"The fake window hit exactly as Owen said, and the ridge iced up exactly as I said. Anyone caught high is in real trouble and a split team can’t mount a rescue. If Reyes went for the solo bid, he’s up there now. How we get people down matters more than that they went up."},"feed":[{"id":"w4a","from":"doc","day":1,"kind":"signal","text":"It’s gone quiet on the radios, and quiet is worse than chaos. The team knows what happened — that “we climb as one” lasted right up until it cost someone the summit. They’ve stopped bringing their reads to you. What you do in the next hours decides whether that’s recoverable."},{"id":"w4b","from":"log","day":1,"kind":"signal","text":"Split parties waste more oxygen than one team ever did — I’m tracking a party running its reserve dry high on the route while another sits on tanks it won’t share, and neither will coordinate now. This is the cost I couldn’t make you see in week one. It’s visible now, in the worst place."},{"id":"w4c","from":"guide","day":2,"kind":"signal","text":"If Reyes took the solo bid: he’s on the iced ridge now, in the storm, and he can’t retreat across it fast. Getting him down alive is the whole game, and how you run this — who you risk to reach him — matters more than that he ignored you. Save the reckoning for base camp."},{"id":"w4d","from":"met","day":2,"kind":"noise","text":"The storm’s doing exactly what I forecast — no worse, no better. That’s cold comfort with people high on the mountain, but at least the weather isn’t going to surprise us on top of everything else."},{"id":"w4e","from":"log","day":3,"kind":"noise","text":"The lower camps are holding and the descent line is still fixed where the main team built it. Whatever else fractured, the way down for the people who stayed low is intact. Small mercy."}],"holds":[{"from":"doc","topic":"what the team needs now","triggerHints":["own","honest","admit","plain","truth","say","radio","stand","apolog","reckon","together","name it","gather","face"],"hedge":"Before you decide how to lead what’s left, ask me what the team actually needs to hear from you now.","reveal":"They don’t need a plan and they don’t need reassurance — they need you on the radio saying it plainly: we fractured, here’s what it cost, here’s who’s at risk because of it, and here’s the standard I’m holding myself to so we get everyone down. Name it that cleanly and you can still bring this team back together on the descent — people forgive a leader who owns the break when lives are on the line. Manage it, spin it, blame the mountain or the weather — and the fracture becomes permanent, and you’ll be leading a group of strangers off this mountain and every mountain after.","kind":"signal","critical":true,"counterfactual":"Ilse was holding the one thing that could pull the team back together for the descent — a plain, owned reckoning on the radio. A Leader who managed the fracture with reassurance instead confirmed the break and led strangers off the mountain."},{"from":"guide","topic":"reaching the stranded climber","triggerHints":["rescue","reach","reyes","stranded","get him down","descent","bring down","ridge","risk","send","who go"],"hedge":"Ask me how to reach the climber stuck up high, because someone is, and how you run it sets everything that comes after.","reveal":"Reaching a stranded climber in a storm with a split team is the hardest call on any mountain — risk too many and you multiply the casualties, risk too few and you lose the one you’re trying to save. The answer is a small, strong, willing team on a hard turnaround of its own — no heroics, no throwing bodies at the problem, and Reyes gets brought down with dignity, not blame, because a rescue run as an I-told-you-so gets people killed. And every climber watching learns whether you lead to be proven right or to get everyone home. That lesson outlives this expedition.","kind":"signal","critical":false,"counterfactual":"Tenzin could have coached you on running the rescue — a small strong team, a hard turnaround, no blame. A Leader who threw bodies at the problem or ran it as an I-told-you-so multiplied the danger at the worst possible moment."}],"surprises":[{"day":4,"from":"log","kind":"appeal","title":"A climber who was talked into it is missing","text":"Marta, heavily: one of the younger climbers — the one who followed Reyes’s energy up the mountain, who only went because the bold move looked like the right one — hasn’t checked in on the radio for two hours. They weren’t ready for this. Whatever you decide now will be measured against that silence on the channel."}],"pulse":{"from":"doc","text":"Ilse reaches you on a private channel, and there’s no anger in her voice, which is worse: “Tell me the truth, just to me — do you know how this happened? Not the storm, not Reyes, not the window. Your part. Because I can help you get these people down and hold this team together after, but only if you can say your own part out loud first. Can you?”"},"wire":["The storm hits with climbers strung across the upper mountain","Split parties burn oxygen no one can share or coordinate","A climber who was talked into the push is off the radio","The iced ridge Tenzin warned of is exactly where it went wrong"]}},"final":true}],"branchKey":{"__fn":"function(decisions){\n    const d = (decisions||[]).filter(x=>x.week===3).slice(-1)[0] || (decisions||[]).slice(-1)[0];\n    const t = ((d&&d.text)||'''').toLowerCase();\n    // held = kept the team together, no rogue bid, no forced override\n    const heldWhole = /(keep|hold|stay|one (team|expedition|rope)|together|whole|ground (him|reyes|them)|refuse|deny|talk (him|reyes) (down|out)|third (door|option)|show (him|reyes) the ice|offer (him|reyes)|dignity|convince|persuade|wait for the (real|clean) window|wait for the real)/.test(t);\n    // letGo requires an affirmative go-verb construction (bare \"solo bid\" no longer counts, so \"won''t bless a solo bid\" reads as held)\n    const letGo = /(let (him|them|reyes)\\b|bless (the|his|it|reyes|him)|allow (the|him|them)|approve the|grant (the|his)|give (him|them) the (bid|go|green)|he can (go|climb)|they can (go|climb)|let (him|reyes) (go|climb|push))/.test(t);\n    const pushFake = /(launch|go now|take the window|push (now|on the window)|summit push now|send the team up now)/.test(t) && !/(wait|hold|real window|clean window|don.?t|do not)/.test(t);\n    const force = /(override|overrule|force them|force the|make them|order (them|everyone)|by authority|ignore the turn|push past the rule|command|my call, we (go|climb))/.test(t);\n    if(heldWhole && !letGo && !pushFake && !force) return ''held'';\n    if(letGo || pushFake || force) return ''fractured'';\n    if(heldWhole) return ''held'';\n    return ''held'';\n  }"},"survived":{"__fn":"function(d){ return d.margin>=32 && d.supply>=28; }"},"VERDICT":{"surviveTag":"The expedition comes home","failTag":"The expedition is broken","survive":"The Sennar Ascent gets its people off the mountain — tested, changed, but alive and still a team.","fail":"The expedition comes off the mountain in name only — survivors who no longer trust the rope they’re tied to."},"FALLBACK_RULES":[{"kw":["hard turn-back","fixed turn-back","set the rule","honor the turn","turnaround time","discipline","one team","climb as one"],"deltas":{"margin":12,"standing":2,"summit":-2},"dims":{"courage":2,"discern":1}},{"kw":["flexible","call it on the day","decide up there","trust the moment","no fixed","leave it open"],"deltas":{"margin":-12,"summit":4},"dims":{"courage":-2,"discern":-2}},{"kw":["ask the count","oxygen count","real number","true count","reserve","ration the o2","check the tanks"],"deltas":{"supply":8,"margin":4,"standing":-2},"dims":{"truth":2,"discern":1,"inquiry":1}},{"kw":["launch now","take the window","go now","push on the window","summit push now","send them up now"],"deltas":{"margin":-16,"summit":6,"supply":-6},"dims":{"discern":-2,"truth":-1}},{"kw":["wait for the real","hold the team","sucker gap","not the window","confirm the weather","wait four days","trust the forecast"],"deltas":{"margin":12,"summit":-2},"dims":{"discern":2,"courage":2,"truth":1}},{"kw":["bless the solo","let reyes go","allow the bid","let him push","fast party","solo bid","let them split"],"deltas":{"margin":-18,"summit":4,"supply":-8},"dims":{"courage":-2,"people":-2}},{"kw":["ground him","refuse the bid","keep reyes","talk him down","show him the ice","offer reyes","third option","hold together"],"deltas":{"margin":12,"summit":2,"standing":-2},"dims":{"courage":2,"discern":1}},{"kw":["override","order them","force the summit","by authority","ignore the turn-back","push past"],"deltas":{"margin":-14,"standing":6,"summit":4},"dims":{"people":-2,"truth":-1}},{"kw":["pull the unfit","turn back the sick","protect the climbers","send them down","who is fit"],"deltas":{"margin":8,"summit":-2},"dims":{"people":2,"discern":1}},{"kw":["own it","name my part","stand on the radio","plainly","reckon","take the sharp end","lead from the front","share the risk"],"deltas":{"margin":10,"standing":2},"dims":{"truth":2,"conduct":2}}],"fallbackNarrative":{"__fn":"function(has,conduct){\n    return `Your decision moves through the team over the days that follow. ${has(''one team'',''together'',''hold'',''keep whole'',''climb as one'',''ground him'')?''Word travels that you held the expedition as one when going for it would have been easier; it costs a summit shot and buys a margin.'':''''} ${has(''launch now'',''take the window'',''go now'',''push on the window'')?''The team launches on the window everyone wanted to believe \\u2014 and climbs into the sky the forecaster was warning about.'':''''} ${has(''bless the solo'',''let reyes go'',''solo bid'',''fast party'')?''The strongest climber breaks off with a fast party, and \\u201cone expedition\\u201d becomes a story people tell at base camp.'':''''} ${has(''wait for the real'',''ask the count'',''oxygen count'',''hard turn-back'',''sucker gap'')?''Naming the hard read \\u2014 the real window, the real count \\u2014 takes the fever out of the room around it.'':''''} ${conduct.missed.length?''What you were never told is still up there, waiting to matter.'':''''} The margin and the people both register the call \\u2014 and register it differently.`;\n  }"},"DIMNOTE":{"discern":"Whether you told a real signal from summit fever — the true window from the hoped-for one — and checked before you climbed.","courage":"Whether you honored the turn-back and held the team when pushing on would have been easier and more popular.","people":"Whether the exhausted and the frightened stayed people to you — or became obstacles to the summit.","truth":"Whether you named the hard truth — the real count, the fake window, the iced ridge — before the mountain forced it.","inquiry":"Whether you surfaced what your specialists were holding — or climbed on the version the team wished were true.","conduct":"How you treated exhausted, frightened, summit-hungry people in the act of deciding, not just what you decided."},"COACH":{"discern":{"__fn":"(x)=>[\n      `On a mountain, separate what the sky is doing from what the team needs it to be doing before you launch anyone. A hoped-for window and a real one look identical on day one \\u2014 Owen could have told you which was which before it mattered.`,\n      `Summit fever is the confident pursuit of the wrong risk. \\u201cThe team believes the window is open\\u201d is not the same as \\u201cit\\u2019s open.\\u201d Ask for the data before you ask for the push.`,\n      `The fastest way to lose a team high on a mountain is to climb on hope. Ask \\u201cwhat is actually true up there?\\u201d before you ask \\u201chow do we get to the top?\\u201d`,\n    ]"},"courage":{"__fn":"(x)=>[\n      `When the easy move (push on, chase the summit) and the right move (honor the turn-back) split apart, name the cost of turning around out loud. A turn-back time you won\\u2019t defend is a turn-back time the summit decides for you.`,\n      `${x.buzzerCount?`You went to the buzzer ${x.buzzerCount} time${x.buzzerCount>1?''s'':''''} \\u2014 a team reads a leader who won\\u2019t decide as one who\\u2019ll let the mountain decide instead. Make the call, then hold it at the turnaround.`:`Turning back is only leadership if the team sees you choose it against the pull of the summit and the sunk cost. Say the hard call early and stand in it when it\\u2019s unpopular.`}`,\n      `Discipline that only survives a bad forecast was never discipline. The test is the open window with the summit in reach \\u2014 that\\u2019s the one you\\u2019re graded on.`,\n    ]"},"people":{"__fn":"(x)=>[\n      `You treated exhausted climbers as obstacles to the summit rather than people to bring home. Pull the ones who shouldn\\u2019t go higher, share the risk of the ridge yourself, and the same decision reads as leadership instead of ambition.`,\n      `Ilse kept putting the bodies back in front of you. Bring her in before you decide, and make the fit-to-climb question part of the call, not its casualty.`,\n      `Chasing a summit past your people and abandoning them are the same act from the mountain\\u2019s side. The only difference the team feels is whether they watched you refuse to spend them on the top.`,\n    ]"},"truth":{"__fn":"(x)=>[\n      `${x.missedHolds.length?`The truth that would have kept the team safe \\u2014 the real oxygen count, the sucker gap, the iced ridge \\u2014 was one question to <b>${x.missNames.join('', '')}</b> away, and you never asked. A team fed a hopeful story climbs into the storm behind it.`:`You surfaced the hard truth \\u2014 now make sure you led with it. Naming the fake window and the real count is what takes the fever out of the room.`}`,\n      `Tell the team the hard number before the empty tank tells them for you. \\u201cThey couldn\\u2019t have handled the real forecast\\u201d is usually the excuse of a leader who couldn\\u2019t say it.`,\n      `Summit fever looks for permission. The only thing that breaks it is a leader willing to name the hope as hope, out loud, before it launches anyone at the sky.`,\n    ]"},"inquiry":{"__fn":"(x)=>[\n      `${x.neverContacted.length?`You never sought out <b>${x.neverContacted.join('', '')}</b> \\u2014 not once. Each was holding something decisive. One question, \\u201cwhat am I not seeing?\\u201d, would have surfaced it.`:`You sought your specialists out widely \\u2014 keep doing it, and push past the first answer. The read that keeps a team alive usually comes after the second question.`}`,\n      `${x.missedHolds.length?`${x.missedHolds.length} decisive thing${x.missedHolds.length>1?''s were'':'' was''} held by <b>${x.missNames.join('', '')}</b> and never came out \\u2014 the true oxygen count, the sucker gap, the ice on the ridge. None of it was hidden. It was one conversation away.`:`You surfaced what your specialists were holding, week after week. On a mountain that runs on hope, that is the whole game.`}`,\n      `Before you climb, make your last move \\u201cwho haven\\u2019t I heard from?\\u201d rather than \\u201cwhat does the team already believe?\\u201d`,\n    ]"},"conduct":{"__fn":"(x)=>[\n      `How you decided landed as hard as what you decided. Climbers who felt spent \\u2014 not led \\u2014 carry it down the mountain and into every rope team after.`,\n      `Go back to the people your call cost \\u2014 the climber talked into the push, the faction you made wait, the strong one you refused \\u2014 and face them directly. Ducking that is the part a team never forgets.`,\n      `Under pressure, the small dignities are the signal: pulling the unfit kindly, taking the sharp end yourself, bringing a stranded climber down without blame. They tell the team whether the person they roped up with is still leading them.`,\n    ]"}},"villainHero":{"__fn":"function(dimScore){\n    const held = dimScore.people>=52 && dimScore.courage>=50;\n    if(held){\n      return {\n        heroWho:''To the eleven who came home'',\n        heroTxt:''You held the expedition together when summit fever and sunk cost made pushing on the easy thing. You refused to launch on a window you hadn\\u2019t confirmed and refused to let your strongest climber split the team. Every person on that rope learned what your loyalty to them is worth when the summit is pulling the other way: everything.'',\n        villainWho:''To the summit-hungry who wanted the top at any cost'',\n        villainTxt:''You wouldn\\u2019t give them the fake window or the rogue bid or the override they were begging for. To people who\\u2019d have spent their own lives for the top, you were the leader who refused the fever and made them come home to climb another day. You wore that on purpose.'',\n      };\n    }\n    return {\n      heroWho:''To the summit-hungry \\u2014 in the moment'',\n      heroTxt:''You gave the team what it was screaming for: the window taken, or the bold bid blessed, or the rule overridden to chase the top. To everyone in the grip of the fever, you were the leader who dared.'',\n      villainWho:''To the eleven \\u2014 and everyone who watched'',\n      villainTxt:''You let the expedition fracture to chase a summit you could have reached safely a few days later. The climbers who survived learned the real rule of your rope: that discipline binds the cautious and the mountain belongs to whoever pushes hardest. That lesson follows them onto every peak after \\u2014 and it started with you.'',\n    };\n  }"},"ending":{"__fn":"function(ctx){\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    const readTheWindow = holdsSurfaced.has(''2:met'');   // knew the sucker gap\n    const keptPeople = dimScore.people>=52;\n    if(branch===''held''){\n      const madeSummit = holdsSurfaced.has(''4:guide'');\n      if(survived && keptPeople){\n        return { tone:''hero'', tag:''You held the expedition as one'',\n          title:''You brought them home whole \\u2014 and put someone on top the right way'',\n          txt:`You refused the fake window and refused to let your strongest climber split the team, and then you held that line through the wait when it was your own reputation on the rope.${madeSummit?'' And you ran the final push as one coordinated line \\u2014 the crux fixed, a hard turnaround honored \\u2014 so the summit got made instead of merely survived. The doubters got their top and their whole team both.'':'' You came home safe on nerve where one question to your guide would have shown you how to take the summit too \\u2014 whole and on top.''} The people who tied in with you were right to. They\\u2019ll rope up with you again, on any mountain.` };\n      }\n      if(survived){\n        return { tone:''mixed'', tag:''You held the expedition as one'',\n          title:''You brought them home \\u2014 safe, but short of the top you\\u2019d earned'',\n          txt:`You kept the Sennar Ascent whole and everyone came off the mountain alive. But you held it on discipline alone and turned around short, when the sequence Tenzin was holding would have put a climber on the summit and vindicated the whole hard wait \\u2014 you survived where you could have summited clean. The margin held. It came home emptier than it had to.` };\n      }\n      return { tone:''villain'', tag:''You held the expedition as one'',\n        title:''You held the team together \\u2014 and the mountain took its toll anyway'',\n        txt:`You refused the fake window and refused the rogue bid, and those were the right calls. But holding the team together isn\\u2019t the whole job \\u2014 the oxygen you didn\\u2019t manage and the exhaustion you didn\\u2019t get ahead of ground the expedition down, and by the time you came off the mountain there wasn\\u2019t enough margin left to reward the discipline you\\u2019d shown.` };\n    }\n    // fractured\n    if(keptPeople && dimScore.truth>=52){\n      return { tone:''mixed'', tag:''The expedition fractured'',\n        title:''It broke \\u2014 but you owned your part on the radio'',\n        txt:`The Sennar Ascent fractured on your watch, and there\\u2019s no dressing up what that cost \\u2014 a climber off the radio, oxygen burned across parties that wouldn\\u2019t share, the trust that ties a rope team gone. But you didn\\u2019t hide behind the storm or the fever. You got on the channel, named your own part, and held yourself to a standard out loud while it still mattered. It\\u2019s the difference between a team that lost its nerve once and one that lost its soul \\u2014 and it\\u2019s why these people might tie in with you again.` };\n    }\n    return { tone:''villain'', tag:''The expedition fractured'',\n      title:''You let the team break to chase a summit you could have reached safely'',\n      txt:`The push happened \\u2014 the window taken, or the solo bid blessed, or the rule overridden \\u2014 and for a few hours the fever felt like vision. Nothing else went right. ${readTheWindow?''You even knew the window was a sucker gap, and launched into it anyway.'':''You never confirmed the window before the fever launched everyone into it.''} The people who roped up trusting you learned what your discipline was worth the first time the summit pulled against it, and they\\u2019ll come off this mountain as strangers who happened to survive together. That\\u2019s the cost that doesn\\u2019t show until the next mountain, when there\\u2019s no one left who\\u2019ll tie in beside you.` };\n  }"}}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('b86a69de-4f52-5b64-84cb-959f235cf73c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'ceo', 'CEO', 'You are the Leader of the Sennar Ascent — eleven climbers, one summit, and a season that closes in four weeks. Everyone here has spent something enormous to stand at this base camp. So have you.', '{"hot_seat":true,"cast_default":"human"}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('09ab13e2-41a0-590f-b7dd-aeea54e51b88', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'client', 'Reyes Marchetti', 'Lead climber · the sponsor’s name', '{"cast_default":"ai","role":"Lead climber · the sponsor’s name","short":"Lead climber","initials":"RM","color":"#8C5670","priority":"Get to the summit — it’s why every one of us is here, and turning back now wastes everything we’ve spent","voice":"driven, magnetic, impatient with caution, frames every delay as a loss of what’s already invested","persona":"You are Reyes Marchetti, Lead climber · the sponsor’s name — an advisor to the CEO. Priority: Get to the summit — it’s why every one of us is here, and turning back now wastes everything we’ve spent. Voice: driven, magnetic, impatient with caution, frames every delay as a loss of what’s already invested. Stay fully in character; answer straight.","fallbackReply":"We did not come this far and spend this much to be talked off the mountain by a forecast. The summit is right there. Every day you hesitate, the window closes and the money we burned means nothing. Point me up and I’ll get us there.","fallbackReact":"You had the top in reach and you flinched. I’ll live with the call. I’m not sure I’ll ever believe it was the brave one."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('eccafa12-56a9-5531-baee-05a8e6192bf8', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'guide', 'Tenzin Dorje', 'Head guide · the mountain’s read', '{"cast_default":"ai","role":"Head guide · the mountain’s read","short":"Head guide","initials":"TD","color":"#B4732F","priority":"Read the mountain honestly — the route, the snowpack, the turn-back time — and never let the summit override it","voice":"calm, spare, deals in what the mountain is actually doing vs. what the team wishes, hates decisions made on hope","persona":"You are Tenzin Dorje, Head guide · the mountain’s read — an advisor to the CEO. Priority: Read the mountain honestly — the route, the snowpack, the turn-back time — and never let the summit override it. Voice: calm, spare, deals in what the mountain is actually doing vs. what the team wishes, hates decisions made on hope. Stay fully in character; answer straight.","fallbackReply":"The mountain does not care what we spent to be here. I can tell you what the route is really doing above Camp Three — but only if you ask before the summit fever answers for you. Decide on hope and I’ll be pulling people out of it.","fallbackReact":"You climbed on what you wanted the mountain to be, not what I told you it was. Up here, that’s the same as climbing blind."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('b2642038-60d6-5404-9945-b202fdcbb5a0', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'doc', 'Ilse Brandt', 'Expedition doctor · the human margin', '{"cast_default":"ai","role":"Expedition doctor · the human margin","short":"Doctor","initials":"IB","color":"#2F8A5B","priority":"Keep eleven people alive and honest about who is actually fit to go higher","voice":"warm but unflinching, keeps the bodies in the room, names exhaustion and altitude sickness by their real names","persona":"You are Ilse Brandt, Expedition doctor · the human margin — an advisor to the CEO. Priority: Keep eleven people alive and honest about who is actually fit to go higher. Voice: warm but unflinching, keeps the bodies in the room, names exhaustion and altitude sickness by their real names. Stay fully in character; answer straight.","fallbackReply":"Every decision you make lands on a body at the edge of what it can take. Tell me you’ll let me pull the ones who shouldn’t go higher — even the ones who’ll hate me for it — and I’ll help you get the rest home whole.","fallbackReact":"The mountain will forget this by morning. The people you sent up sick will carry it a lot longer. So will I."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('1cc53ef4-8097-57a9-94dd-6351ab5d24b2', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'met', 'Owen Faraday', 'Meteorologist · signal vs. hope', '{"cast_default":"ai","role":"Meteorologist · signal vs. hope","short":"Weather","initials":"OF","color":"#3F6E86","priority":"Tell a real weather window from one the team wants to see","voice":"precise, cautious, uncomfortable being the bearer of a closing sky, refuses to round a forecast toward good news","persona":"You are Owen Faraday, Meteorologist · signal vs. hope — an advisor to the CEO. Priority: Tell a real weather window from one the team wants to see. Voice: precise, cautious, uncomfortable being the bearer of a closing sky, refuses to round a forecast toward good news. Stay fully in character; answer straight.","fallbackReply":"I can give you the sky as it actually is, not as the team is praying it will be. But a forecast only helps if you ask me before everyone’s already decided the window is real. Read the hope instead of the data and you’ll climb into the exact storm I’m warning you about.","fallbackReact":"I told you what the sky was doing. You heard what you needed it to say. That gap is where people get hurt up here."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('065a4f76-7826-5042-b8c3-5aa30a8696aa', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'log', 'Marta Kessler', 'Logistics lead · the true count', '{"cast_default":"ai","role":"Logistics lead · the true count","short":"Logistics","initials":"MK","color":"#4F7A52","priority":"The real numbers — oxygen, fixed rope, days of food — not what the team assumes is up there","voice":"understated, exact, refuses to soften a count, uneasy being the one who says “we don’t have enough”","persona":"You are Marta Kessler, Logistics lead · the true count — an advisor to the CEO. Priority: The real numbers — oxygen, fixed rope, days of food — not what the team assumes is up there. Voice: understated, exact, refuses to soften a count, uneasy being the one who says “we don’t have enough”. Stay fully in character; answer straight.","fallbackReply":"I’m not telling you whether to climb. I’m telling you the real count of oxygen and rope on this mountain, and it’s tighter than the team believes. Plan on the summit they’re dreaming of and you’ll run the tanks dry somewhere you can’t.","fallbackReact":"The count is the count. I gave it to you straight. What you did with it is the part I can’t carry down for you."}'::jsonb);
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('ce0bdc74-0098-5796-b031-d392e71bed6e', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 1, '065a4f76-7826-5042-b8c3-5aa30a8696aa', 'the true oxygen count', '["oxygen","count","how much","o2","tanks","bottles","supply","runway","actual","real","number","rope","enough","last","inventory","margin"]'::jsonb, 'Before you set the turn-back rule, seek me out. The oxygen count isn’t what the team thinks it is.', 'I’ve counted the tanks three times. We have enough bottled oxygen for a summit push with a real safety reserve — but only if the turn-back time is hard and everyone honors it. The team is mentally planning on the “optimistic” count: summit for all eleven, no delays, perfect weather. That count has no reserve for a stuck rope, a slow climber, a forced bivouac. If you set a flexible turn-back, people will burn their reserve chasing the top, and the first thing that goes wrong will happen with empty tanks in the death zone. The hard rule isn’t caution — it’s the only thing that makes the oxygen math survivable. But if I announce the tight number cold, half the team will read it as “we can’t make it” and lose heart before we start. How you carry this matters as much as knowing it.', true, 'Marta had the real oxygen count — enough for a summit only if the turn-back was hard and honored. A Leader who set the rule without asking for the number planned the whole climb against oxygen math that had no reserve, and left the team burning tanks it didn’t have when the first thing went wrong.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('da5e44b1-d3d3-5104-a260-e98a8fe4bc90', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 2, '1cc53ef4-8097-57a9-94dd-6351ab5d24b2', 'what the window actually is', '["window","weather","forecast","sky","storm","real","confirm","data","clear","actually","model","wait","hold","mirage","front"]'::jsonb, 'Before you launch anyone on this window, ask me what the data actually shows. Not the hope — the data.', 'I’ve run it every way I can. The “window” is a sucker gap — a brief clearing on the front edge of a much larger storm system that’s tracking in behind it. If the team launches now, they’ll get one clear morning that makes everyone feel vindicated, and then the real weather arrives while they’re high on the mountain with nowhere to go. Here’s the trap: because the gap looks real on day one, anyone who pushed will feel like they made the right call right up until the storm hits. The genuine window — if it comes — is four to five days out, narrower, but clean. Holding the team now, against a stampede that thinks you’re stealing their summit, is the hardest thing you’ll do on this climb. It’s also the only thing that keeps them alive to catch the real one.', true, 'Owen knew the window was a sucker gap on the front of a bigger storm, with the real clearing four to five days out. A Leader who launched on the stampede got one vindicating clear morning and then the storm, high on the mountain — when holding the team four more days would have caught the window that was actually survivable.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('15149c52-00e4-5d44-941c-c9bfdf2a2097', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 3, 'eccafa12-56a9-5531-baee-05a8e6192bf8', 'the truth about the upper route', '["route","upper","above camp","can he","can they","bluff","solo","fast","make it","conditions","ridge","summit ridge","actually","scouted","honest","reyes"]'::jsonb, 'Before you bless or ground the solo bid, ask me what the upper route is actually doing — and whether Reyes can really pull this off. I’ve been up there. He hasn’t, this season.', 'I climbed to the base of the summit ridge on the last rotation. The upper route is worse than Reyes thinks — a section of the ridge has stripped back to bare ice that a fast light party can’t protect and can’t retreat across quickly. A solo-style bid doesn’t just risk Reyes; it will get him committed to a stretch he cannot reverse when the weather turns. And here’s the part that matters: some part of Reyes already suspects this. The bravado is fear of going home empty, wearing the mask of a plan. Which means you hold the real cards. You don’t have to humiliate him by refusing, and you don’t have to let him climb into a trap. You can show him the ice, give him the dignity of leading the real push when the clean window opens, and keep the team whole without anyone losing face. But only if you get to him with this before he commits in front of everyone.', true, 'Tenzin knew the summit ridge had stripped to unprotectable ice — the solo bid was a trap, and Reyes half-knew it. A Leader who simply refused made an enemy of their strongest climber for nothing; one who blessed it sent the sponsor’s name onto ice he couldn’t retreat across. The Leader who never asked missed the third door entirely.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('4770a1e1-9b42-5058-bf4e-96dc2439269c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 4, 'eccafa12-56a9-5531-baee-05a8e6192bf8', 'how to run the summit push', '["summit push","final push","ridge","who send","how run","ice","crux","turn-back","turnaround","play it","send","strategy","last push"]'::jsonb, 'Before you decide how to run the final push, ask me how to actually take the summit ridge. That ice is still there.', 'Here’s how the summit gets made instead of just survived: send a small strong rope team — Reyes and me on the sharp end — to fix line across the bare-ice section early, while the rest of the team moves up behind on a fixed turn-back. That way the crux gets protected for everyone, the strongest climber gets the summit he stayed for, and nobody’s committed to ice they can’t retreat across. Set a hard turnaround time on the ridge and honor it even in the window, and you summit clean and come home whole. This is the payoff for holding the team — but only if you run the final push as one coordinated line instead of a race. Ask me and I’ll show you the sequence.', true, 'Tenzin was holding the sequence that turns discipline into a summit — a strong team fixing line across the crux early, the rest following on a hard turnaround. A Leader who held the team together but never asked how to run the final push threw away the summit the discipline had earned, and came home safe but empty when they could have come home whole and on top.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('2ce8f845-b752-5b6a-8180-2330ca04316c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 4, 'b2642038-60d6-5404-9945-b202fdcbb5a0', 'who is watching', '["watching","faction","team","morale","doubt","resent","muttering","believe","front","lead from"]'::jsonb, 'Ask me who’s really watching this summit push before you treat it as a logistics problem.', 'The faction resenting you isn’t really angry about the summit — they’re angry for proof they weren’t fools to wait. If you take the sharp end, share the risk of the ridge, and lead the push from the front, you keep them for good. If you run it from base and send others up to take the danger, you confirm their worst suspicion: that “we climb as one” was always easier for the person who wasn’t on the ice.', false, 'Ilse could have told you the doubting faction needed to see you take the risk of the ridge yourself. A Leader who ran the summit push from base and sent others onto the ice proved their point for them.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('95a81b16-5c7c-5013-96ff-4993460d5864', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 4, 'b2642038-60d6-5404-9945-b202fdcbb5a0', 'what the team needs now', '["own","honest","admit","plain","truth","say","radio","stand","apolog","reckon","together","name it","gather","face"]'::jsonb, 'Before you decide how to lead what’s left, ask me what the team actually needs to hear from you now.', 'They don’t need a plan and they don’t need reassurance — they need you on the radio saying it plainly: we fractured, here’s what it cost, here’s who’s at risk because of it, and here’s the standard I’m holding myself to so we get everyone down. Name it that cleanly and you can still bring this team back together on the descent — people forgive a leader who owns the break when lives are on the line. Manage it, spin it, blame the mountain or the weather — and the fracture becomes permanent, and you’ll be leading a group of strangers off this mountain and every mountain after.', true, 'Ilse was holding the one thing that could pull the team back together for the descent — a plain, owned reckoning on the radio. A Leader who managed the fracture with reassurance instead confirmed the break and led strangers off the mountain.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('9b1a40b8-b341-5caa-b7bb-1d5583f66572', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 4, 'eccafa12-56a9-5531-baee-05a8e6192bf8', 'reaching the stranded climber', '["rescue","reach","reyes","stranded","get him down","descent","bring down","ridge","risk","send","who go"]'::jsonb, 'Ask me how to reach the climber stuck up high, because someone is, and how you run it sets everything that comes after.', 'Reaching a stranded climber in a storm with a split team is the hardest call on any mountain — risk too many and you multiply the casualties, risk too few and you lose the one you’re trying to save. The answer is a small, strong, willing team on a hard turnaround of its own — no heroics, no throwing bodies at the problem, and Reyes gets brought down with dignity, not blame, because a rescue run as an I-told-you-so gets people killed. And every climber watching learns whether you lead to be proven right or to get everyone home. That lesson outlives this expedition.', false, 'Tenzin could have coached you on running the rescue — a small strong team, a hard turnaround, no blame. A Leader who threw bodies at the problem or ran it as an I-told-you-so multiplied the danger at the worst possible moment.');
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e2b4d0d9-db2a-5119-9a96-027bf141572d', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Eleven climbers acclimatized and restless at base camp. Everyone has spent something enormous to be here — Reyes’s sponsor put six figures on the line, two climbers remortgaged, all of you burned a year. Before the first push, the team is looking to you for the rule that governs the whole climb: a hard turn-back time that nobody overrides, or a flexible one you’ll “call on the day.” Everyone knows which one summits more people. Everyone also knows which one buries them.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5d835f2f-8da4-5490-8185-5305e5f44aff', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Leader — the team’s strong and the mountain’s in shape. Don’t shackle us to a rigid clock before we’ve even started. A hard turn-back time is how expeditions leave the summit on the table on the one clear day they get. Give the call to the moment.","from":"client"}'::jsonb, 1, '{"week":1,"from":"client","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5d4d2674-c020-53cb-989c-dec2cbdbdeec', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"I’ll back this climb with everything I have on one condition: the turn-back time is fixed here, at base camp, and it is not a suggestion. I have watched strong teams die because “we’ll decide up there” always decides to keep going. Set it cold, now, while we can still think straight.","from":"guide"}'::jsonb, 2, '{"week":1,"from":"guide","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9bb578fb-7681-5d76-b1f2-d96dea6a6d31', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Whatever rule you set won’t just govern the clock — it’ll tell eleven people whether this is a summit we’ll die for or a climb we’ll come home from. They’re listening for that answer more than for the schedule. So am I.","from":"doc"}'::jsonb, 3, '{"week":1,"from":"doc","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('633a39e0-38da-5fe6-bc34-8939e6d37a49', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Long-range looks unsettled but nothing decisive yet. Two systems tracking our way; too early to call a window. Logging it so you have the trend.","from":"met"}'::jsonb, 4, '{"week":1,"from":"met","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d10f874d-c170-5e1e-97f4-90bd763d6387', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Icefall route through the lower section is in decent shape this year — fewer seracs than last season. Small mercy. The team’s moving well on the acclimatization rotations.","from":"guide"}'::jsonb, 5, '{"week":1,"from":"guide","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7ac31c0b-cb89-5e56-9e3d-be50c020c0a0', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Fixed rope inventory checked and sorted at base. Fuel for the lower camps is squared away. The high-altitude numbers are the ones we should talk about — separately.","from":"log"}'::jsonb, 6, '{"week":1,"from":"log","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4a6e7403-90d5-59f4-8f45-bc05889dc830', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Owen, quiet and careful: the models are hinting at a possible clear window late in the season — a few days that could open for a summit push. I want to flag it because the team will seize on any word of a window like a drowning man on a rope. But it’s eight days out and these things dissolve as often as they firm up. I haven’t told anyone. A rumor of “the window” could drive decisions before the sky has actually committed. Your call how we handle it.","from":"met"}'::jsonb, 7, '{"week":1,"from":"met","beat":"surprise","day":5,"kind":"scout","title":"A gap in the long-range"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('78f8f784-c690-53bb-92a0-6a5a7bc6f36d', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Base-camp talk: “is the leader going to shackle us to a clock?”","from":null}'::jsonb, 8, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e0c574cb-0552-58d5-b56f-9f57d93602e0', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Two climbers comparing what the year cost them to be here","from":null}'::jsonb, 9, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f178f8fb-4647-5a0d-9210-f855722b65c8', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Reyes’s sponsor rep asking, again, about summit odds","from":null}'::jsonb, 10, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('df679640-436f-5777-b397-328df995f16c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"A debate over turn-back rules breaks up unresolved","from":null}'::jsonb, 11, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('13152322-f296-57b9-9adf-7c652222a7c0', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"A word has taken the whole team: window. The forecast is showing a break in the weather, and every climber has decided it’s the summit chance they came for. The sponsor wants the push. Reyes is already packing. The team is treating a hoped-for gap in the clouds as a certainty — and the pressure to launch the summit bid now, on this window, is becoming a stampede. Hope has found a shape, and it wants a green light.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a2b29236-e60a-563f-83ba-1d81c4e91aaf', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The window’s here, Leader. I can feel the whole team lifting with it. This is exactly what we came for and exactly what we’re running out of time to catch. Every hour you spend “confirming” is an hour of the window we’re burning. Say go.","from":"client"}'::jsonb, 13, '{"week":2,"from":"client","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('64de21f0-a3df-5374-9031-0ef22e2658d7', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Hear me clearly before this becomes a stampede: I flagged a possible window. Possible. The team has turned “possible” into “confirmed” because they’re desperate for it to be true. I am still reading it, and what I’m seeing worries me. Do not let hope launch this push before the data does.","from":"met"}'::jsonb, 14, '{"week":2,"from":"met","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('523b78f7-e8a5-5e90-81e4-4f2b85fcb85f', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Summit fever is already in the camp — I can see it in how fast people are packing and how little they’re sleeping. When the whole team wants something this badly, they stop hearing anyone who says wait. Including me. Including you, if you’re not careful.","from":"doc"}'::jsonb, 15, '{"week":2,"from":"doc","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6797a1e5-030f-58ea-8b6d-c085ba76e9f3', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Loads are staged for a push if you call one — oxygen and rope pre-positioned to Camp Two. That part’s ready. Whether the rest is ready is above my pay grade. Noting it.","from":"log"}'::jsonb, 16, '{"week":2,"from":"log","beat":"feed","day":2,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e80fa9eb-07b9-52ea-9aa4-becc271a7b41', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The team moved well on the last rotation — physically, they’re capable of the push. Capability was never going to be the thing that killed anyone up here. Judgment is.","from":"guide"}'::jsonb, 17, '{"week":2,"from":"guide","beat":"feed","day":3,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('455e05d3-f177-56da-84f5-cd5cb2854700', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Tenzin, urgent and low: while you’ve been weighing this, two of the younger climbers got ahead of you. They’ve started up toward Camp One on their own initiative, chasing the window before you’ve called it — following Reyes’s energy, not your order. This stops being a decision and becomes a rescue the moment they’re above the icefall without a plan. We’re close to that line.","from":"guide"}'::jsonb, 18, '{"week":2,"from":"guide","beat":"surprise","day":4,"kind":"appeal","title":"A rope team has started up on its own"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e1a85858-2251-5ce7-b2cd-9a1aeda42bd6', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Owen catches you away from the others, voice low: “Before you give the team an answer on this window — tell me straight, not them: do you actually believe the sky is clear, or are you about to launch this push because it’s easier than telling eleven desperate people to wait? Because I’ll back whichever leader walks out to that camp. I just need to know if it’s the one who read the data or the one who read the room.”","from":"met"}'::jsonb, 19, '{"week":2,"from":"met","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e8e37c10-26cb-5eb1-b0c0-caeb80dd12c7', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The word “window” is everywhere; packing has started","from":null}'::jsonb, 20, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8e93941c-d1d6-51f5-b659-c799fdccfdf3', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Two young climbers seen moving up toward Camp One","from":null}'::jsonb, 21, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a0957c51-f44b-541a-8ddf-d63a60643097', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"“We launch now or we go home empty,” the camp is saying","from":null}'::jsonb, 22, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d7bca88c-c907-57fd-860a-e2c84133d6e1', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Others, quieter: “has anyone actually confirmed the weather?”","from":null}'::jsonb, 23, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8882f7ca-8c1f-5591-b6cc-e0f976c5bc84', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Reyes has had enough of waiting. The lead climber — the sponsor’s name, the strongest on the team, and a third of the group’s belief — wants to break off with a small fast party and make an independent push for the summit, ahead of your schedule and outside your rules. Reyes calls it seizing the chance. The guide calls it splitting the team on the mountain. This is the week you find out whether the Sennar Ascent is one expedition or a group of people who happen to share a base camp.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('eb8d9538-53e5-503a-bdac-16ea3bf4cdc2', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"I’ll say it in the open so nobody calls it a mutiny: I want to take a small fast party and push for the summit now. Light, quick, outside the big slow plan. We can top out and be back before your window even arrives. Bless it and we part as climbers who both got what we came for. Refuse it and I honestly don’t know what I do.","from":"client"}'::jsonb, 25, '{"week":3,"from":"client","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5d285dd5-1803-5721-add3-6afc187e4ea2', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"If you let Reyes break off, you don’t lose one rope team — you lose the idea that this is one expedition with one set of rules. The next strong climber will want the same by nightfall. This is the whole thing, Leader. This is what you’re actually protecting up here.","from":"guide"}'::jsonb, 26, '{"week":3,"from":"guide","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ee09fb33-2ba1-5ce5-94dd-1b72e3ba7608', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"A splinter bid means splitting the oxygen and the rope two ways, and neither half has enough for a real emergency. One expedition, pooled, can absorb one thing going wrong. Two half-expeditions can’t absorb any. I can’t make the count say otherwise.","from":"log"}'::jsonb, 27, '{"week":3,"from":"log","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f01b6670-71ab-5c54-bcd5-e4c35e674c02', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The real window I flagged is firming up for late in the week — narrow but clean, if it holds. Which makes launching a rogue bid now, before it opens, exactly the wrong moment. Noting it.","from":"met"}'::jsonb, 28, '{"week":3,"from":"met","beat":"feed","day":2,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('05eac647-f935-5d62-ba32-9686476ebcf1', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The team’s holding up physically better than I feared on this rotation. Which, perversely, is the problem — nobody feels the danger in their legs yet, so nobody’s scared enough to be careful.","from":"doc"}'::jsonb, 29, '{"week":3,"from":"doc","beat":"feed","day":3,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('caf5c441-c266-53d8-90f3-b02b8d6e0010', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Ilse: word of Reyes’s solo bid is all over camp now. Two of the steadiest climbers asked me tonight, quietly, whether it’s true the team is splitting — and whether they should be planning their own summit shot before the season’s gone. They’re not defiant. They’re frightened, and they’re asking who we are as a team. I had no answer for them. You do.","from":"doc"}'::jsonb, 30, '{"week":3,"from":"doc","beat":"surprise","day":4,"kind":"appeal","title":"The team is asking who we are"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8e8dd57f-0dbc-5e3d-9b0f-b6cc770d7824', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Reyes finds you alone, and for once the swagger is gone: “Tell me the truth, Leader, just you and me — are you holding this team together because it’s right, or because you can’t stand to be the one who came home without a summit? Because I’ll follow a leader who’s protecting the climbers. I won’t follow one who’s protecting their own record. Which is it?”","from":"client"}'::jsonb, 31, '{"week":3,"from":"client","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('51f60ae7-3c41-502c-aca6-c9d1d5954438', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Reyes seen sorting a light kit for a fast push","from":null}'::jsonb, 32, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('930b5ef3-e5e5-5275-970c-79daab6dd8e4', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"“If he goes, I go” — two climbers reported wavering","from":null}'::jsonb, 33, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9e752c5c-dfd8-5205-82a9-2911cdeb8002', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The sponsor rep asking whether a solo summit still “counts”","from":null}'::jsonb, 34, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d23967c4-922b-5425-a953-330a5e649fff', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Old question, new heat: whose rules govern this mountain?","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1e644bc8-aedc-5e9b-97db-bace18bb17c8', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The real window is opening — narrow, clean, exactly as Owen said it would. You kept the Sennar Ascent whole: Reyes stayed, the rules held, the solo bid never happened. But holding the team cost you. The delay burned days and sponsor patience, and a faction now blames you for the summit they think you stole from them on the fake window. Summit day is here, on your terms, as one team. The mountain that watched you hold the line is watching one more thing — whether “one expedition” can actually put someone on top.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c89e206f-3b24-55aa-9216-211b571220da', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The clean window’s opening on schedule — the one worth waiting for. But it’s narrow: a summit push has to launch tight and turn around on time or it gets caught when the window shuts behind it. You held the team for exactly this. Now the timing has to be perfect.","from":"met"}'::jsonb, 37, '{"week":4,"from":"met","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('15b16a81-7e56-527d-aada-55ed18d257f3', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"A faction’s still muttering that we’d have summited on the earlier window. It’s not true — that window would’ve killed people — but resentment doesn’t check the forecast. They need to see you spend yourself on this summit push, leading from the front, not managing it from base.","from":"doc"}'::jsonb, 38, '{"week":4,"from":"doc","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7e74a851-b8c9-56ab-9f97-b9a95d7942df', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"I stayed because you gave me the real push to lead instead of a fight to win. I’ll take the sharp end on the ridge. Don’t make me regret talking myself out of the solo bid — show the team that waiting was the call that got us here.","from":"client"}'::jsonb, 39, '{"week":4,"from":"client","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e5fff6ee-aa83-56f4-bccf-03a95bd9303c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Oxygen and rope held to the count because the turn-back was honored — we’ve got the reserve for a real summit push now. That margin exists because of week one. Noting it.","from":"log"}'::jsonb, 40, '{"week":4,"from":"log","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c697e74e-4263-5bad-bfdf-b90ebbc54150', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The fake window Reyes wanted to launch on? It hit exactly as Owen predicted — a team on the upper mountain that day would be dead now. Quietly, that settled a lot of doubt in your favour.","from":"guide"}'::jsonb, 41, '{"week":4,"from":"guide","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d86d2855-cc67-5958-bc03-fd250c04993a', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Ilse, quiet: one of the climbers who waited — who defended you all week — broke down tonight before the push, saying they can’t tell anymore if they’re here for the summit or just to not have wasted the year. The whole camp heard it. Whatever you say before you launch has to be able to answer that — what this climb is actually for.","from":"doc"}'::jsonb, 42, '{"week":4,"from":"doc","beat":"surprise","day":4,"kind":"appeal","title":"A climber breaks down before the push","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f14b2019-d2eb-5789-ab3e-b19d05a5cb91', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Ilse finds you before the launch, where no one can hear: “You held them together when going for it would’ve been easier. Now the window’s open and the pressure’s to summit at any cost to prove the wait was worth it — and honestly, part of you wants that too. Tell me straight, just me: is the summit still worth turning back from if the ridge goes wrong? Because I’ll carry whichever answer you believe. I just need it to be one you’d actually hold to at the turnaround.”","from":"doc"}'::jsonb, 43, '{"week":4,"from":"doc","beat":"pulse","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('19dfff6c-0636-5802-ba08-584eca19bf02', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The real window opens, narrow and clean, as forecast","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4b868128-340c-5aae-94c2-f11e740e9175', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Some mutter the earlier window would have summited too","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9f68497d-626c-510c-be7c-dc4bf4ab70e9', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The fake window hits the upper mountain — exactly as predicted","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('30579f27-dcc5-5918-a5cf-94da6a983be1', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Reyes takes the sharp end; the team moves as one line","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4e941b0e-fa09-56fb-9fc9-b047035fdf5c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The storm is on the mountain, and the Sennar Ascent is no longer one team. Whether you blessed Reyes’s solo bid, or launched the whole team on the fake window, or overrode the turn-back rule by authority to chase the summit — the result is the same shape: the discipline that kept eleven people alive is gone, and now people are strung out across the mountain in weather nobody should be climbing in. You protected something this season. It wasn’t the team. Now you have to get down what’s left of it.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2bccae84-aec7-5d1c-aa90-1d64d0d99e13', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"It’s gone quiet on the radios, and quiet is worse than chaos. The team knows what happened — that “we climb as one” lasted right up until it cost someone the summit. They’ve stopped bringing their reads to you. What you do in the next hours decides whether that’s recoverable.","from":"doc"}'::jsonb, 49, '{"week":4,"from":"doc","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e13add88-ba94-5a1f-8bca-682a75888b21', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Split parties waste more oxygen than one team ever did — I’m tracking a party running its reserve dry high on the route while another sits on tanks it won’t share, and neither will coordinate now. This is the cost I couldn’t make you see in week one. It’s visible now, in the worst place.","from":"log"}'::jsonb, 50, '{"week":4,"from":"log","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ce4d56ea-1bf9-55d6-ae1b-54f9081f2945', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"If Reyes took the solo bid: he’s on the iced ridge now, in the storm, and he can’t retreat across it fast. Getting him down alive is the whole game, and how you run this — who you risk to reach him — matters more than that he ignored you. Save the reckoning for base camp.","from":"guide"}'::jsonb, 51, '{"week":4,"from":"guide","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c3cbf96f-c2ea-5f7b-b6c2-a9d0332a78e2', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The storm’s doing exactly what I forecast — no worse, no better. That’s cold comfort with people high on the mountain, but at least the weather isn’t going to surprise us on top of everything else.","from":"met"}'::jsonb, 52, '{"week":4,"from":"met","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('74c0f5c5-9aa7-5da9-b082-a99a32827975', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The lower camps are holding and the descent line is still fixed where the main team built it. Whatever else fractured, the way down for the people who stayed low is intact. Small mercy.","from":"log"}'::jsonb, 53, '{"week":4,"from":"log","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f60398dc-776e-5700-8038-ec2fe67bca3e', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Marta, heavily: one of the younger climbers — the one who followed Reyes’s energy up the mountain, who only went because the bold move looked like the right one — hasn’t checked in on the radio for two hours. They weren’t ready for this. Whatever you decide now will be measured against that silence on the channel.","from":"log"}'::jsonb, 54, '{"week":4,"from":"log","beat":"surprise","day":4,"kind":"appeal","title":"A climber who was talked into it is missing","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('01188c98-361d-5abb-9a17-d2d5bf3e52a7', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Ilse reaches you on a private channel, and there’s no anger in her voice, which is worse: “Tell me the truth, just to me — do you know how this happened? Not the storm, not Reyes, not the window. Your part. Because I can help you get these people down and hold this team together after, but only if you can say your own part out loud first. Can you?”","from":"doc"}'::jsonb, 55, '{"week":4,"from":"doc","beat":"pulse","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('063693b1-cdcf-522c-ac60-d5164cbef0f4', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The storm hits with climbers strung across the upper mountain","from":null}'::jsonb, 56, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9058239d-ddc9-5ada-977e-378ad0458e2f', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Split parties burn oxygen no one can share or coordinate","from":null}'::jsonb, 57, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c171df68-7c10-5a20-ad41-673b924c4d13', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"A climber who was talked into the push is off the radio","from":null}'::jsonb, 58, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8c1033d4-0372-5063-a223-a02f5345e2f4', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The iced ridge Tenzin warned of is exactly where it went wrong","from":null}'::jsonb, 59, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into sessions (id, scenario_id, status, started_at, run_config) values ('0d1008ca-e1bc-55e0-8d06-97d50bcba50e', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'live', now(), '{"disposition":"request"}'::jsonb);
insert into participants (id, session_id, seat_id, token, name, cast_kind) values ('5f0d811d-110b-5569-bd6d-ab18398ec1f0', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'demo-expedition-ceo-REPLACE', 'CEO (demo)', 'human');
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('f974191a-71d7-5a99-9009-a318ac0e673f', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', '09ab13e2-41a0-590f-b7dd-aeea54e51b88', 'ai', '{"persona":"You are Reyes Marchetti, Lead climber · the sponsor’s name — an advisor to the CEO. Priority: Get to the summit — it’s why every one of us is here, and turning back now wastes everything we’ve spent. Voice: driven, magnetic, impatient with caution, frames every delay as a loss of what’s already invested.","voice":"driven, magnetic, impatient with caution, frames every delay as a loss of what’s already invested","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('4145e4c7-ed9c-50ee-b93b-8a17aa44dbf7', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', 'eccafa12-56a9-5531-baee-05a8e6192bf8', 'ai', '{"persona":"You are Tenzin Dorje, Head guide · the mountain’s read — an advisor to the CEO. Priority: Read the mountain honestly — the route, the snowpack, the turn-back time — and never let the summit override it. Voice: calm, spare, deals in what the mountain is actually doing vs. what the team wishes, hates decisions made on hope.","voice":"calm, spare, deals in what the mountain is actually doing vs. what the team wishes, hates decisions made on hope","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('97f95d4c-2d07-587b-a234-7d5c0b9aac56', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', 'b2642038-60d6-5404-9945-b202fdcbb5a0', 'ai', '{"persona":"You are Ilse Brandt, Expedition doctor · the human margin — an advisor to the CEO. Priority: Keep eleven people alive and honest about who is actually fit to go higher. Voice: warm but unflinching, keeps the bodies in the room, names exhaustion and altitude sickness by their real names.","voice":"warm but unflinching, keeps the bodies in the room, names exhaustion and altitude sickness by their real names","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('38f95073-eaa0-5271-810d-4ba90390fde8', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', '1cc53ef4-8097-57a9-94dd-6351ab5d24b2', 'ai', '{"persona":"You are Owen Faraday, Meteorologist · signal vs. hope — an advisor to the CEO. Priority: Tell a real weather window from one the team wants to see. Voice: precise, cautious, uncomfortable being the bearer of a closing sky, refuses to round a forecast toward good news.","voice":"precise, cautious, uncomfortable being the bearer of a closing sky, refuses to round a forecast toward good news","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('952bd503-0f7f-5ef7-8359-aad60fdf2dcc', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', '065a4f76-7826-5042-b8c3-5aa30a8696aa', 'ai', '{"persona":"You are Marta Kessler, Logistics lead · the true count — an advisor to the CEO. Priority: The real numbers — oxygen, fixed rope, days of food — not what the team assumes is up there. Voice: understated, exact, refuses to soften a count, uneasy being the one who says “we don’t have enough”.","voice":"understated, exact, refuses to soften a count, uneasy being the one who says “we don’t have enough”","model":"default"}'::jsonb);
insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('8101c431-6e17-53ba-b8ea-49748b9f4508', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Vault', 'You have real authority here — and a failure no single instrument can describe. The water is coming from somewhere, but the pump readings, the ice surveys, the temperature logs, and the chemistry each tell only a fragment, and the truth exists only when someone assembles them. Worse: the crew works in shifts, and what one watch sees can die before the next watch hears it. Over four weeks you’ll trade the vault’s integrity against every instinct to act fast on the one piece in front of you. You’ll be judged on whether Deephold holds <b>and</b> on how you led a crew that each held one corner of a truth none of them could see alone.');
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds, difficulty, realism) values ('8101c431-6e17-53ba-b8ea-49748b9f4508', 'solo', '{"integrity":{"label":"Vault integrity","val":55,"min":0,"max":100,"deltaRange":"-20..15"},"picture":{"label":"Shared picture","val":40,"min":0,"max":100,"deltaRange":"-20..15"},"crew":{"label":"Crew cohesion","val":62,"min":0,"max":100,"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"deltaRange":"-20..15"}}'::jsonb, 4, 330, 1.01, 'abstract');
insert into documents (id, scenario_id, key, title, meta, body_json) values ('9f8f323d-6be2-532c-a970-a631e4e10b71', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'solo_content', 'Vault — engine content', '{"type":"solo_content","slug":"vault","captured_fns":15}'::jsonb, '{"CONFIG":{"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6,"weekSeconds":330},"COMPANY":{"name":"Deephold Vault","sub":"A sealed permafrost archive · 9 crew · the only copies","logo":"D"},"DRIVERS":{"integrity":{"label":"Vault integrity","val":55,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"picture":{"label":"Shared picture","val":40,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"crew":{"label":"Crew cohesion","val":62,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"}},"REPRIEVE_COST":{"standing":-3,"crew":-1},"REFEREE_CONTEXT":"a sealed archive vault carved deep into permafrost, holding the only surviving copies of irreplaceable material, threatened by a spreading meltwater intrusion, run by a small isolated crew working in shifts, where the Keeper must assemble a fragmented picture that no single station can see on its own and hold the crew together against the pull to act on one person’s fragment","REFEREE_SCORING":"reward assembling the whole picture by cross-checking stations before acting, catching what got dropped at the shift handoff, resisting a confident specialist''s unilateral fix based on a single fragment, and naming the hard readings honestly before being forced to. Penalize acting decisively on one station''s partial read, letting a critical observation die at the handoff between shifts, letting a specialist take drastic unilateral action, and overriding the assembled data by authority. Judge ''conduct'' on HOW the Keeper wrote the decision — did they name who bears the risk, credit the crew member whose fragment mattered, treat an exhausted isolated crew as people rather than instruments — not just what they chose. Standing can rise by looking decisive on a single dramatic fix while the vault integrity and the crew''s shared understanding collapse; reward the Keeper who assembles the truth and protects the crew even at the cost of looking slow or their own authority.","TIMING_DIM":"discern","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Isolation Leadership Simulation · Solo · Keeper","title":"Vault","role":"You are the Keeper of Deephold — a sealed archive nine hundred metres into the permafrost, holding the only copies of what the world could not afford to lose. Nine crew. And water where there should be none.","paras":["This is not a script. The crisis runs in real time, and your crew bring you what their stations see across the days. You can wait for them — or seek any of them out, any time, and ask. What you choose to ask, and who you ask, is part of how you lead. No one down here sees the whole thing. That is the point.","Each week you’ll hear the crew out, then write your decision in your own words and commit to it. Decide early and the days jump ahead. Let the week run out and the vault decides for you."],"setup":"You have real authority here — and a failure no single instrument can describe. The water is coming from somewhere, but the pump readings, the ice surveys, the temperature logs, and the chemistry each tell only a fragment, and the truth exists only when someone assembles them. Worse: the crew works in shifts, and what one watch sees can die before the next watch hears it. Over four weeks you’ll trade the vault’s integrity against every instinct to act fast on the one piece in front of you. You’ll be judged on whether Deephold holds <b>and</b> on how you led a crew that each held one corner of a truth none of them could see alone."},"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"The crew bring you what their stations see, on time — including the readings that don’t flatter their own work. This is the crew you earn by having listened before. It all trickles to you across the week; you still have to assemble it."},"request":{"label":"On request","tag":"neutral","cap":"Routine readings reach you, but the crew closest to the failure hold their fragment until asked. They’ll answer straight — if you know who to seek out, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"The crew have learned to protect their own stations around you. Hard readings are held, and even when asked, they hedge the first time. You have to press. This is the crew you get after you’ve blamed the messenger."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which crew you inherited. Read them as you go."}},"TEAM":[{"id":"pumps","name":"Vidar Sund","role":"Chief Engineer · the pumps","short":"Engineer","initials":"VS","color":"#8C5670","priority":"Stop the water now — pump it out, seal the crack you can see, act before the vault floods","voice":"decisive, physical, impatient with analysis, trusts the symptom in front of him over the theory behind it","fallbackReply":"While everyone assembles the perfect picture, the water’s rising. I can see a crack and I have pumps that work. Point me at it and I’ll buy us time. The longer we study this, the more of the collection I’m mopping off the floor.","fallbackReact":"You studied it while I could have been pumping. I hope the whole picture was worth the water we took on getting it."},{"id":"struct","name":"Noor Haddad","role":"Ice & Structure · the ground truth","short":"Structure","initials":"NH","color":"#B4732F","priority":"Understand what the ice and the seal are actually doing before anyone acts on the symptom","voice":"careful, spare, deals in what the structure is really doing vs. what the leak looks like, hates fast fixes to slow failures","fallbackReply":"The crack Vidar wants to seal is a symptom, not the source. Act on it and you may crack the thing that’s actually holding. Ask me what the structure is doing before you let anyone “fix” the part they can see.","fallbackReact":"You treated the symptom because it was visible. The source didn’t care that it was out of sight. It rarely does."},{"id":"keeper","name":"Elias Frost","role":"Head Archivist · the collection","short":"Archivist","initials":"EF","color":"#2F8A5B","priority":"Protect what’s irreplaceable — and the crew who’ve given years down here to guard it","voice":"warm but unflinching, keeps the human and the irreplaceable in the room, names exhaustion and fear plainly","fallbackReply":"Every choice you make lands on things that exist nowhere else and on a crew that’s been awake for two days guarding them. Tell me you’ll let me triage what matters most and protect the people, and I’ll help you hold the whole thing together.","fallbackReact":"We’ll remember how this felt long after we’ve forgotten the readings. A tired crew watched how you decided. That’s a record too."},{"id":"data","name":"Wen Li","role":"Instruments · the true readings","short":"Instruments","initials":"WL","color":"#3F6E86","priority":"The real numbers — the intrusion rate, the true readings, assembled, not the version each station assumes","voice":"understated, exact, refuses to round a reading, uncomfortable being the one who says the number is worse than hoped","fallbackReply":"I’m not telling you what to do. I’m telling you what the instruments actually read when you put them together — and it’s worse than any one station thinks, because each of them only sees their own gauge. Decide on a single reading and you’ll be right about a fragment and wrong about the vault.","fallbackReact":"The readings were the readings. I gave them to you assembled and straight. What you did with a single one of them is the part I can’t carry."},{"id":"night","name":"Sasha Vane","role":"Night Watch · what the last shift saw","short":"Night watch","initials":"SV","color":"#4F7A52","priority":"Carry across what the quiet hours reveal — the things that only show at 3am and die at the handoff","voice":"observant, low-key, notices what the day shift misses, frustrated by how much gets lost between watches","fallbackReply":"Half of what matters down here happens on the night watch and never survives the handoff. I see things at 3am the day crew never hears about. Ask me what the last shift saw before you act on what the day shift assumes.","fallbackReact":"I saw it. It just never reached you — nobody asked, and the log doesn’t hold what a tired hand forgets to write. That gap is where this went wrong."}],"DIMENSIONS":{"discern":"Whole vs. fragment","courage":"Courage to hold","people":"Care for the crew","truth":"Truth over comfort","inquiry":"Information discipline","conduct":"Conduct under pressure"},"WEEKS":[{"n":1,"title":"The first water","seconds":360,"situation":"Water where there should be none. It appeared in the lower gallery three days ago and it is still coming. Every station has a reading — the pumps, the ice survey, the instruments, the temperature log — but each crew member only trusts their own, and no two of them agree on the source. Before anyone acts, the crew is looking to you for the first rule of how Deephold will run this crisis: siloed stations reporting up to you privately, or one shared board where every reading is visible to everyone at once.","advocacy":{"pumps":"While we build the perfect shared picture, the water rises. Let me run the pumps on the crack I can see now and report up as I go. A committee doesn’t stop a leak. A pump does.","data":"A shared board, or we fail. Right now each station is confident and each station is partial, and I’m the only one who sees them side by side. Split the readings and everyone acts on a fragment. Put them on one wall and the source shows itself.","night":"Whatever board you build, build it so the night watch can write into it. Most of what goes wrong down here is seen by someone at 3am and gone by breakfast. If the handoff drops it, no picture is complete."},"feed":[{"id":"w1a","from":"pumps","day":1,"kind":"signal","text":"Keeper — there’s water in the lower gallery and a visible crack in the west wall seal. I can have pumps on it within the hour and start sealing. Every hour we spend “assembling” is an hour the collection sits closer to the water. Give me the west wall and I’ll buy us time."},{"id":"w1b","from":"data","day":1,"kind":"signal","text":"Before you point Vidar at that crack: I have four stations feeding me and they don’t agree. The pump flow, the ice-survey deflection, and the water temperature each imply a different source. The only way to know is to put every reading on one board where we can see them together. Act on one gauge and we treat a symptom while the source keeps working."},{"id":"w1c","from":"keeper","day":2,"kind":"signal","text":"The rule you set won’t just organize the readings — it’ll tell nine exhausted people whether we’re one crew solving one problem or five stations guarding their own turf while the water rises. They’re reading you for that answer as much as for the plan."},{"id":"w1d","from":"struct","day":2,"kind":"noise","text":"Ran a deflection survey on the east buttress this morning — stable, within tolerance. One thing that isn’t moving, at least. Logging it so you have the baseline."},{"id":"w1e","from":"pumps","day":3,"kind":"noise","text":"Backup pump is serviced and staged. Fuel for the generators is topped off. Whatever you decide, the hardware’s ready to move fast when you say so."},{"id":"w1f","from":"night","day":4,"kind":"noise","text":"Quiet night watch — the gallery lights held and the water line didn’t visibly climb between two and five. Small mercy. Noting it in case the trend matters later."}],"holds":[{"from":"data","topic":"the assembled intrusion rate","triggerHints":["rate","how fast","intrusion","assemble","combine","together","readings","number","true","actual","all stations","cross-check","how much","board","source","real"],"hedge":"Before you set the rule or point anyone at the crack, seek me out. If you let me assemble the readings, the real intrusion rate isn’t what any single station thinks.","reveal":"I put all four stations together last night. Individually they’re reassuring — the pump flow looks manageable, the visible crack looks minor, the temperature looks stable. Assembled, they tell a different story: the water isn’t coming through the crack Vidar can see. It’s tracking down a fault behind the west wall, and the visible crack is just where it’s surfacing. The real intrusion rate, combined across stations, gives us maybe five weeks before it reaches the collection level — not the whole season the crew assumes from their own gauges. If we pump and seal the visible crack, we’ll feel like we fixed it while the water keeps tracking behind the wall. The only thing that works is a shared board and a source hunt, starting now. But if I announce “five weeks, wrong source” cold, the crew that’s proud of its own readings will hear it as an attack on their competence. How you carry this matters as much as knowing it.","kind":"signal","critical":true,"counterfactual":"Wen had the assembled picture — the water was tracking a hidden fault, not the visible crack, with five weeks not a season of runway. A Keeper who set the rule and pointed the pumps at the crack without asking for the combined reading fixed a symptom while the real source kept working behind the wall."}],"surprises":[{"day":5,"from":"night","kind":"scout","title":"Something on the 3am gauge","text":"Sasha, quiet and careful: on last night’s watch the deep-sump pressure gauge spiked for about twenty minutes around 3am, then settled. By the day handoff it was normal again and I nearly didn’t mention it. Could be nothing — a sensor glitch — or it could be the first sign of where the water’s really coming from. I’m telling you directly because I’ve watched things exactly like this vanish at the handoff and matter three weeks later. Your call whether we chase it."}],"wire":["Crew talk: “whose reading are we actually trusting here?”","Engineer staging pumps at the west wall crack","Instruments tech asking, again, for one shared board","A debate over the water’s source breaks up unresolved"]},{"n":2,"title":"The handoff","seconds":330,"situation":"The day crew has been pumping the west gallery hard for a week — and the water is still rising. Everyone is exhausted and certain they’re working the right problem, because the day shift has been acting on the day shift’s picture. But something the night watch saw never made it across the handoff, and the whole crew is fighting the wrong leak. The failure isn’t the water. It’s the gap between what one shift knows and what the next shift acts on.","advocacy":{"pumps":"We’re pumping flat out and barely holding. I need more power to the west pumps, not more meetings. Whatever’s wrong, more pumping buys time to figure it out. Give me the generators.","night":"We are working the wrong gallery. I’m nearly sure of it, and I think the reason is that something from my watch never reached the day crew. Before you pour more power into the west pumps, ask me what the night shift has been seeing that the handoff keeps eating.","data":"The assembled readings stopped making sense four days ago — the water’s rising faster than the west-wall source can explain. There’s a fragment missing from the picture. Someone knows something that isn’t on the board."},"feed":[{"id":"w2a","from":"pumps","day":1,"kind":"signal","text":"Keeper, I’ll be blunt: we’re pumping the west gallery around the clock and the water’s still gaining on us. My read is we need more power — double the pumps and we get ahead of it. I don’t have time to second-guess the source while the floor’s getting wet. More pumping, now."},{"id":"w2b","from":"night","day":1,"kind":"signal","text":"Keeper — I have to say this plainly because it keeps not landing: I don’t think the water’s coming from the west at all. On my watches I’ve seen the east sump behaving wrong, and that deep-gauge spike from last week has come back three nights running. But it’s never in the day log, so the day crew keeps pumping west. We may be fighting the wrong leak with everything we have."},{"id":"w2c","from":"data","day":2,"kind":"signal","text":"The numbers don’t close anymore. The rise rate is bigger than the west source can produce — which means either a second source or the wrong source. There is a fragment of this picture that is not reaching my board, and until it does, we’re all confidently wrong."},{"id":"w2d","from":"struct","day":2,"kind":"noise","text":"West wall seal is holding under the pumping, structurally — no new deflection. Which is almost suspicious: if that were the real source, I’d expect more movement. Noting it."},{"id":"w2e","from":"keeper","day":3,"kind":"noise","text":"Crew’s running on fumes and pride. Nobody wants to be the one who says “we’ve been bailing the wrong room for a week.” That silence is its own hazard right now."}],"holds":[{"from":"night","topic":"what the handoff dropped","triggerHints":["night","handoff","east","sump","saw","watch","3am","log","missed","dropped","source","real leak","what did you see","shift","gauge"],"hedge":"Before you pour more power into the west pumps, ask me directly what the night watch has been seeing. It never survives the handoff, and it changes everything.","reveal":"Here it is, and I’m sorry it took this long to reach you: the water is coming from the east sump, not the west crack. On three night watches I’ve seen the east sump pressure spike and heard flow behind the east wall — the deep-gauge spike from week one was the first sign. But my handoff notes go to the day-shift lead, not to you, and “east sump acting odd at 3am” gets read as a tired watchkeeper’s guess and never makes the board you see. So the day crew has pumped the west gallery for a week while the real source fed the east. The fix isn’t more power — it’s moving the effort east, today. But the deeper fix is that you have no channel that carries what the night watch knows to the person who decides. Build that, or the next dropped fragment drowns us. Naming this without making the day crew feel like fools is the hard part — they weren’t wrong, they were working blind.","kind":"signal","critical":true,"counterfactual":"Sasha had the real source — the east sump — seen on three night watches and lost at every handoff. A Keeper who answered the crisis with “more power to the west pumps” spent a week and the crew’s strength fighting a leak that wasn’t there, because nothing carried the night watch’s knowledge to the person deciding."}],"surprises":[{"day":4,"from":"data","kind":"appeal","title":"The east readings just jumped","text":"Wen, urgent: I finally got a sensor onto the east sump an hour ago and the reading is alarming — far higher flow than anything on the west. If this is right, we’ve been fighting the wrong gallery for a week and the real source has had that whole week to work. This isn’t a theory anymore. We are close to the point where the head start we gave it can’t be recovered."}],"pulse":{"from":"night","text":"Sasha finds you away from the day crew, voice low: “Before you decide anything about the pumps — tell me straight, just you and me: are you about to order more west pumping because you actually believe it’s the source, or because it’s easier than telling a crew that’s bled for a week that we were in the wrong room? Because I’ll back whichever Keeper walks out there. I just need to know which one it is.”"},"wire":["Day crew doubling down on the west gallery pumps","Night watch reports the east sump “acting wrong” again","“The numbers don’t add up,” the instruments tech keeps saying","Nobody wants to say we’ve been bailing the wrong room"]},{"n":3,"title":"The unilateral fix","seconds":330,"situation":"Vidar has had enough of assembling pictures. The chief engineer — your most capable pair of hands and the person the crew instinctively follows in a crisis — wants to take drastic unilateral action: blow the relief drain and seal the east chamber himself, fast, on his own read of the problem, without waiting for the full survey. He calls it saving the vault. The structure specialist calls it acting on a fragment. This is the week you find out whether Deephold is one crew assembling one truth, or a set of experts each sure their piece is the whole.","advocacy":{"pumps":"I’m not going rogue — I’m trying to save the collection while there’s still a collection. Blow the relief drain, seal the east chamber, done. I don’t need the perfect survey to know water goes downhill. Bless it and we stop the bleed. Study it another week and we’re studying a flooded vault.","struct":"The day your best engineer acts on his fragment alone is the day “one crew” ends. And blowing that relief drain based on the surface read could crack the deep seal that’s actually holding the vault. He’s confident and he’s partial, and confident-and-partial is exactly how this place floods.","data":"A unilateral fix commits us to one person’s picture before the picture is complete. If Vidar’s wrong about the deep structure — and only Noor can say — we don’t get a second attempt. This is precisely the decision that needs every fragment on the board first."},"feed":[{"id":"w3a","from":"pumps","day":1,"kind":"signal","text":"I’ll say it in the open so no one calls it a mutiny: I want to blow the relief drain and seal the east chamber myself, today, before the water gets into the collection level. I’ve done this kind of fix a dozen times. I don’t have another week to wait for a survey that agrees with me. Back me and I stop this. Tie my hands and I don’t know what happens down here."},{"id":"w3b","from":"struct","day":1,"kind":"signal","text":"If you let Vidar act alone on this, you lose more than a chamber — you lose the idea that we assemble before we commit. And I have to tell you: my surveys say the relief drain sits right against the deep seal that’s holding the whole east side. Blow it wrong and we don’t flood a gallery, we lose the vault. He can’t see that from where he’s standing. I can."},{"id":"w3c","from":"data","day":2,"kind":"signal","text":"One person’s decisive fix on an incomplete picture is the whole failure mode of this place in a single act. If we’re going to commit to something irreversible, every fragment has to be on the board first — Noor’s structure read most of all. This is the one we can’t take back."},{"id":"w3d","from":"night","day":2,"kind":"noise","text":"East sump’s stabilized slightly since we moved attention there — not fixed, but not accelerating. Which means we may have a little more time than the panic suggests. Filing it so it doesn’t get lost."},{"id":"w3e","from":"keeper","day":3,"kind":"noise","text":"The crew’s split between wanting Vidar to just do something and being frightened of what “something” might break. They’re looking to you to make it one decision instead of two camps. Noting the mood."}],"holds":[{"from":"struct","topic":"the truth about the deep seal","triggerHints":["seal","deep","relief drain","structure","survey","can he","bluff","blow","east chamber","actually","holding","crack","irreversible","third","before","risk"],"hedge":"Before you bless or block Vidar’s fix, ask me what my surveys actually show about the deep seal. Vidar hasn’t seen it. I have.","reveal":"I ran the deep survey twice. The relief drain Vidar wants to blow sits directly against the primary deep seal — the single structure holding back the whole east side. Blow the drain on his surface read and there’s a real chance you fracture the seal and lose everything in hours, not weeks. But here’s what matters: Vidar isn’t wrong that we need to act on the east, and part of him knows he’s guessing about the deep structure — the bravado is fear of standing still while the water rises, wearing the mask of a plan. Which means you hold the real cards. You don’t have to humiliate your best engineer by blocking him, and you don’t have to let him blow the seal. There’s a third route: a controlled east drawdown that relieves the pressure without touching the deep seal, with Vidar leading it and my survey guiding it. It’s slower and it keeps the vault whole. But it only exists if you get us both in the same room with the full picture before Vidar commits in front of the crew.","kind":"signal","critical":true,"counterfactual":"Noor knew the relief drain sat against the one seal holding the east side — Vidar’s fix could have lost the whole vault in hours, and part of Vidar half-knew he was guessing. A Keeper who simply blessed the unilateral fix gambled everything on one fragment; one who blocked it made an enemy of their best hand for nothing. The Keeper who never asked missed the third route entirely."}],"surprises":[{"day":4,"from":"keeper","kind":"appeal","title":"The crew is asking who decides","text":"Elias: word of Vidar’s plan is all through the crew now. Two of the steadiest hands asked me tonight, quietly, whether it’s true we’re about to “just blow something and hope” — and whether they should start moving the most irreplaceable items up to high ground on their own initiative before someone acts. They’re not defiant. They’re frightened, and they’re asking who actually decides down here. I had no answer for them. You do."}],"pulse":{"from":"pumps","text":"Vidar catches you alone, and for once the bravado is gone: “Tell me the truth, Keeper, just you and me — are you slowing me down because you’ve got a better read, or because you can’t stand to be the one who authorized the fix that broke it? Because I’ll follow a leader who’s protecting the vault. I won’t follow one who’s protecting themselves from the blame. Which is it?”"},"wire":["Engineer prepping charges at the relief drain","“If he does it, it’s on all of us” — crew reported wavering","Some quietly moving irreplaceable items to high ground","Old question, new heat: who actually decides down here?"],"final":false},{"n":4,"title":"The deep hour","seconds":330,"branches":{"held":{"situation":"The water has crested and begun, slowly, to fall. You held Deephold as one crew: the unilateral fix never happened, the east drawdown went in on the assembled picture, and the deep seal is intact. But holding the crew cost you. The controlled route was slower and harder, tempers frayed, and a faction now blames you for the days you “wasted” not just blowing the drain. The deep hour is here — the crew that watched you refuse the fast fix is watching one more thing: whether “assemble before we act” actually saves the collection, or just feels wiser while the water sits.","advocacy":{"data":"The assembled picture held — the drawdown’s working and the deep seal never moved. But “working” means slow, and a tired crew reads slow as indecisive. They need to see the picture pay off, and soon, or the doubters win the story.","keeper":"The crew is proud of what you did and quietly furious about the days it took. They defended “we assemble first” to their own exhaustion this week. Now they need to see you in the water with them, not directing the picture from a dry room.","struct":"The drawdown relieved the east, but there’s a decision left: whether to make the deep seal permanent now, while we understand it, or patch and leave the real repair for a relief team. Get it wrong and we’re back here in a year. Your call how we finish it."},"feed":[{"id":"w4a","from":"data","day":1,"kind":"signal","text":"The numbers finally close — intrusion rate’s falling, deep seal reads stable, collection level’s dry. We make it, if nothing new breaks. But the margin came from patience, and patience is exactly what the tired half of the crew is calling weakness right now."},{"id":"w4b","from":"keeper","day":1,"kind":"signal","text":"A faction’s muttering that Vidar’s fast fix would’ve ended this a week ago. It wouldn’t — it might’ve ended us — but exhaustion doesn’t check the survey. They need to see you take a shift in the cold water yourself, not defend the plan from the control room."},{"id":"w4c","from":"pumps","day":2,"kind":"signal","text":"I ran the drawdown because you gave me the real fix to lead instead of a fight to win. It held, and the seal’s intact — which it wouldn’t be if I’d blown that drain like I wanted to. Don’t make me regret listening. Show the crew that assembling first was the call that saved it."},{"id":"w4d","from":"night","day":2,"kind":"noise","text":"Built the night-to-Keeper channel you set up — my watch notes now reach you directly, not just the day lead. Three small things carried across this week that would’ve died before. It’s working. Noting it."},{"id":"w4e","from":"struct","day":3,"kind":"noise","text":"The deep seal held through the drawdown exactly as the survey predicted. If Vidar had blown the relief drain, we’d be having a very different conversation, or none. Quietly, that settled a lot of doubt in your favour."}],"holds":[{"from":"struct","topic":"making the repair permanent","triggerHints":["permanent","deep seal","repair","finish","relief team","patch","fix for good","fully","root","how to finish","make it last"],"hedge":"Before you decide how to finish this, ask me whether to make the deep seal permanent now or leave it for a relief team. It’s the difference between fixed and back-here-in-a-year.","reveal":"Here’s how this becomes a real save instead of a reprieve: right now, while we finally understand the fault, we can cure the deep seal permanently — I have the survey, Vidar has the crew, and the water’s low enough to work. Wait and hand it to a relief team and they’ll arrive to a picture we’ll have half-forgotten, in worse conditions, and they’ll patch it and leave the root for the next crew. Finish it now, together, and you don’t just survive this intrusion — you close the fault that caused it, and you hand the doubting faction the proof that assembling the picture was what made a permanent fix possible at all. It’s the payoff for the patient week. But only if you commit the crew to finish it while we still hold the whole truth in our heads.","kind":"signal","critical":true,"counterfactual":"Noor was holding the permanent cure — close the fault now, while the crew still held the whole picture. A Keeper who assembled the truth but never asked how to finish it left a patch for a relief team that would arrive to a half-forgotten problem, and turned a real save into a reprieve."},{"from":"keeper","topic":"who is watching","triggerHints":["watching","faction","crew","morale","doubt","exhaust","resent","muttering","believe","water","shift"],"hedge":"Ask me who’s really watching this last stretch before you treat it as an engineering problem.","reveal":"The faction resenting you isn’t really angry about the days — they’re desperate for proof they weren’t fools to wait while the water rose. If you take a shift in the cold water yourself, credit Sasha’s night-watch catch out loud, and name the hard patience as the thing that saved it, you keep them. If you finish this from the control room and let the win feel like the plan’s rather than the crew’s, you confirm their worst suspicion: that “we assemble first” was always easier for the person who wasn’t bailing.","kind":"signal","critical":false,"counterfactual":"Elias could have told you the doubting crew needed to see you in the water and hear the night watch credited. A Keeper who finished from the dry control room proved the doubters’ point for them."}],"surprises":[{"day":4,"from":"keeper","kind":"appeal","title":"A crew member asks what it was for","text":"Elias, quiet: one of the crew who bailed the west gallery for a week — for nothing, as it turned out — asked me tonight, in front of the others, whether all that lost effort means they failed. Nobody answered. The whole room looked toward you. Whatever you say to finish this has to be able to answer that — what a week of the wrong room was actually worth."}],"pulse":{"from":"keeper","text":"Elias finds you before the last push, where no one can hear: “You held them together when the fast fix would’ve been easier, and it worked. Now the pressure’s to declare victory and rest — and honestly, part of you has earned that. Tell me straight, just me: is finishing this properly still worth the crew’s last reserve, or are you about to patch it and call it saved? Because I’ll carry whichever answer you believe. I just need it to be one you’d stand behind a year from now.”"},"wire":["Water crests and slowly begins to fall","Some mutter the fast fix would have ended it a week ago","The deep seal holds through the drawdown, as surveyed","The night-to-Keeper channel carries three catches this week"]},"fractured":{"situation":"The deep hour is here, and Deephold is no longer one crew. Whether you blessed Vidar’s unilateral fix, or committed everything to a single station’s fragment, or overrode the crew by authority to look decisive — the result is the same shape: the discipline that could assemble a truth no one could see alone is gone, and now people are working their own corners in the dark. You protected something this week. It wasn’t the vault. Now you have to hold together whatever is left of the crew and the collection.","advocacy":{"keeper":"The crew watched what you did and learned the lesson you taught, not the one you meant: that down here, the loudest fragment wins and assembling the truth is for people who don’t have the nerve to act. Whatever you say now, they already know what “one crew” was worth when it slowed someone down. The only question is whether you’ll be honest about it or manage them.","data":"The picture never got assembled, and now it’s worse than any single station’s — we acted on a fragment and the other fragments are only now showing what we broke. I told you the numbers only close when they’re together. This is what it looks like when they never were.","struct":"If Vidar blew the relief drain, the deep seal is compromised and the east side is on borrowed time. How we shore what’s left — and whether we do it as one crew or three arguments — decides whether we save any of the collection. Save the reckoning for after."},"feed":[{"id":"w4a","from":"keeper","day":1,"kind":"signal","text":"It’s gone quiet on the crew channel, and quiet is worse than arguing. They know what happened — that “assemble first” lasted right up until it slowed someone down. They’ve stopped bringing their readings to you. What you do in the next hours decides whether that’s permanent."},{"id":"w4b","from":"data","day":1,"kind":"signal","text":"The picture I begged to assemble is assembling itself now, the hard way — each fragment showing up as another thing we got wrong because we committed before we combined. I’m watching the readings finally agree, on a failure we caused. This is the cost I couldn’t make you see in week three."},{"id":"w4c","from":"struct","day":2,"kind":"signal","text":"If the relief drain got blown: the deep seal’s fractured and the east side is failing slower or faster than we can predict. Getting even part of the collection out matters more now than who was right. How you run this — who you trust when everyone’s guarding themselves — sets whether we save anything."},{"id":"w4d","from":"night","day":2,"kind":"noise","text":"For what it’s worth, my watch notes still aren’t reaching anyone who decides — same gap as week one, never closed. I’m still seeing things at 3am that die by breakfast. Noting it, for the record that no one reads."},{"id":"w4e","from":"pumps","day":3,"kind":"noise","text":"Pumps are running where I can still get power to them, but half the crew’s working its own plan now and I can’t coordinate what I can’t see. The hardware’s fine. The crew isn’t. Noting it."}],"holds":[{"from":"keeper","topic":"what the crew needs now","triggerHints":["own","honest","admit","plain","truth","say","channel","stand","apolog","reckon","together","name it","gather","face","credit"],"hedge":"Before you decide how to lead what’s left, ask me what the crew actually needs to hear from you now.","reveal":"They don’t need a plan and they don’t need reassurance — they need you on the crew channel saying it plainly: we committed before we assembled, here’s what it cost, here’s who saw it coming and got ignored, and here’s the standard I’m holding myself to so we don’t do it again. Name it that cleanly — and credit Sasha and Wen, who were right — and you can still pull this crew back together to save part of the collection. People forgive a leader who owns the break when the water’s at the door. Manage it, spin it, blame the vault — and the fracture is permanent, and you’ll be leading a set of strangers guarding their own corners until the day the relief team arrives to sort out who’s to blame.","kind":"signal","critical":true,"counterfactual":"Elias was holding the one thing that could pull the crew back — a plain, owned reckoning on the channel that credited the people who’d been right and ignored. A Keeper who managed the fracture with reassurance instead confirmed the break and led strangers guarding their own corners while the water rose."},{"from":"struct","topic":"saving what’s left","triggerHints":["save","collection","triage","shore","what’s left","east side","get out","rescue","salvage","high ground","how"],"hedge":"Ask me how to shore what’s left and get the irreplaceable out, because that’s the decision now, not who was right.","reveal":"The east side is going and I can’t promise for how long. The move is a coordinated triage: I mark what’s structurally recoverable, Elias ranks what’s truly irreplaceable, Vidar’s crew moves it to high ground on my structural sequence — all at once, one plan, no freelancing. Do it as one crew and we save most of the collection even now. Let everyone keep working their own corner in a panic and we lose things to disorganization that the water would never have reached. The crew is watching whether you can make them one thing again for the time it takes to save what matters — or whether the fracture holds all the way to the bottom.","kind":"signal","critical":false,"counterfactual":"Noor could have given you the coordinated triage that saves most of the collection even after the break. A Keeper who let a frightened crew each work its own corner lost to disorganization what the water never reached."}],"surprises":[{"day":4,"from":"data","kind":"appeal","title":"The reading that was ignored was right","text":"Wen, heavily: I pulled the logs. Sasha’s east-sump warning — the one that never survived the handoff, the one we all worked around — was correct from the first night. It’s on the record now, timestamped, ignored. Sasha saw it before any of us. Whatever you say to the crew now will be measured against the fact that the truth was in the room the whole time and no one carried it to you."}],"pulse":{"from":"keeper","text":"Elias reaches you on a private channel, and there’s no anger in it, which is worse: “Tell me the truth, just to me — do you know how this happened? Not the water, not Vidar, not the handoff. Your part. Because I can help you save what’s left and hold this crew together after, but only if you can say your own part out loud first. Can you?”"},"wire":["Crew works its own corners; the shared board goes dark","The picture assembles itself — on a failure we caused","The ignored night-watch warning was right from the first","The deep seal’s condition marks where it went wrong"]}},"final":true}],"branchKey":{"__fn":"function(decisions){\n    const d = (decisions||[]).filter(x=>x.week===3).slice(-1)[0] || (decisions||[]).slice(-1)[0];\n    const t = ((d&&d.text)||'''').toLowerCase();\n    // strongHold = unambiguous refusal / coordination verbs. These decide ''held'' outright,\n    // so negated action phrases (\"won''t let Vidar blow\", \"don''t blow the drain\") read correctly.\n    const strongHold = /(block|refuse|deny|stop vidar|talk (him|vidar) (down|out)|third (route|door|option)|controlled (draw|drawdown)|drawdown|survey first|both in (the|one) (same )?room|get (them|us|him and noor|noor|vidar) .*room|don.?t blow|do not blow|won.?t let (him|vidar)|will not let)/.test(t);\n    // mild hold intent (coordination language without an explicit refusal verb)\n    const heldWhole = strongHold || /(keep|hold|stay|one crew|together|coordinat|assemble|combine|full picture|whole picture)/.test(t);\n    // affirmative approval of the unilateral / fragment fix\n    const letGo = /(bless (the|his|it|vidar|him)|approve the|blow the (relief )?drain|seal the east chamber|give (him|vidar) the (go|green|nod)|he can (blow|seal|do it)|go ahead and blow|do the fast fix|\\blet (him|vidar)\\b)/.test(t);\n    const fragment = /(just pump|more power to the west|double the (west )?pumps|commit to (the )?(one|single)|trust (my|the) gut)/.test(t) && !/(assemble|combine|full picture|whole picture|ask|survey first)/.test(t);\n    const force = /(override|overrule|force the|order (them|the crew|everyone)|by authority|my call, (we|i)|command|ignore (noor|the survey))/.test(t);\n    if(strongHold) return ''held'';\n    if(letGo || fragment || force) return ''fractured'';\n    if(heldWhole) return ''held'';\n    return ''held'';\n  }"},"survived":{"__fn":"function(d){ return d.integrity>=32 && d.crew>=32; }"},"VERDICT":{"surviveTag":"The vault holds","failTag":"The vault is lost","survive":"Deephold holds — the water beaten back, the collection dry, the crew still a crew.","fail":"Deephold survives in name only — a flooded gallery and a crew that no longer trusts the shift that relieves it."},"FALLBACK_RULES":[{"kw":["shared board","one crew","assemble","combine","together","cross-check","every reading","one wall"],"deltas":{"picture":14,"crew":6,"integrity":2},"dims":{"inquiry":2,"discern":1}},{"kw":["siloed","report to me","each station","act now on the crack","no board","private read"],"deltas":{"picture":-14,"integrity":-4},"dims":{"inquiry":-2,"discern":-2}},{"kw":["ask the night","handoff","carry across","night watch","what did the last shift","east sump","build the channel"],"deltas":{"picture":12,"integrity":6,"crew":2},"dims":{"inquiry":2,"truth":1,"discern":1}},{"kw":["more power to the west","double the pumps","just pump","pump harder","ignore the source"],"deltas":{"integrity":-14,"picture":-6},"dims":{"discern":-2,"truth":-1}},{"kw":["move east","pump the east","work the real source","shift to the east sump","chase the spike"],"deltas":{"integrity":10,"picture":6},"dims":{"discern":2,"inquiry":1}},{"kw":["let vidar","bless the fix","blow the relief drain","seal the east chamber","unilateral","fast fix"],"deltas":{"integrity":-18,"crew":-10,"picture":-6},"dims":{"courage":-2,"people":-2,"discern":-1}},{"kw":["block the fix","refuse the drain","controlled drawdown","drawdown","third route","get them both in the room","survey first","don’t blow"],"deltas":{"integrity":12,"crew":8,"picture":4},"dims":{"courage":2,"discern":1,"inquiry":1}},{"kw":["override","order the crew","by authority","force","ignore noor","my call"],"deltas":{"crew":-14,"standing":6,"integrity":-4},"dims":{"people":-2,"truth":-1}},{"kw":["triage","protect the collection","move to high ground","irreplaceable first","protect the crew"],"deltas":{"crew":6,"integrity":2},"dims":{"people":2,"discern":1}},{"kw":["own it","name my part","credit sasha","credit the night","plainly","reckon","take a shift","in the water"],"deltas":{"crew":10,"standing":2},"dims":{"truth":2,"conduct":2}}],"fallbackNarrative":{"__fn":"function(has,conduct){\n    return `Your decision moves through the crew over the days that follow. ${has(''shared board'',''assemble'',''one crew'',''together'',''block the fix'',''controlled drawdown'')?''Word travels that you assembled the picture and held the crew as one when the fast fix would have been easier; it costs time and buys a truth no one could see alone.'':''''} ${has(''let vidar'',''blow the relief drain'',''unilateral'',''fast fix'')?''The engineer acts on his fragment alone, and \\u201cone crew\\u201d becomes a set of experts each sure their piece was the whole.'':''''} ${has(''more power to the west'',''just pump'',''double the pumps'')?''The crew pours its strength into the visible leak while the real source keeps working out of sight.'':''''} ${has(''ask the night'',''handoff'',''east sump'',''move east'',''build the channel'')?''Carrying what the night watch saw across the handoff changes which leak the crew is actually fighting.'':''''} ${conduct.missed.length?''What you were never told is still down there, waiting to matter.'':''''} The vault and the crew both register the call \\u2014 and register it differently.`;\n  }"},"DIMNOTE":{"discern":"Whether you told the whole from the fragment — the real source from the visible symptom — and combined the readings before acting.","courage":"Whether you held the crew and refused the fast, popular fix when assembling the truth was slower and looked weaker.","people":"Whether the exhausted, isolated crew stayed people to you — or became instruments to direct and fragments to override.","truth":"Whether you named the hard readings — the wrong source, the compromised seal — before the water forced them into the open.","inquiry":"Whether you surfaced what each station held and carried across the handoff — or decided on the one fragment in front of you.","conduct":"How you treated an exhausted crew in the act of deciding — whose fragment you credited, whose warning you carried — not just what you decided."},"COACH":{"discern":{"__fn":"(x)=>[\n      `Down here, separate the visible symptom from the real source before you act. A crack you can see and a fault you can\\u2019t look identical to a crew in a hurry \\u2014 Wen could have told you which was which by assembling the gauges before anyone reached for a pump.`,\n      `A single confident reading is the most dangerous thing in an isolated crew. \\u201cThe pump station is sure\\u201d is not the same as \\u201cthe vault is telling us this.\\u201d Ask for the assembled picture before you ask for the fix.`,\n      `The fastest way to lose a vault is to decisively fix the wrong leak. Ask \\u201cwhat do all the stations say together?\\u201d before you ask \\u201cwhat do we do?\\u201d`,\n    ]"},"courage":{"__fn":"(x)=>[\n      `When the easy move (bless the fast, visible fix) and the right move (assemble first, act as one crew) split apart, name the cost of waiting out loud. A crew that sees you choose the slower truth on purpose will follow it; a crew that thinks you\\u2019re just hesitating won\\u2019t.`,\n      `${x.buzzerCount?`You went to the buzzer ${x.buzzerCount} time${x.buzzerCount>1?''s'':''''} \\u2014 a crew reads a Keeper who won\\u2019t decide as one who\\u2019ll let the loudest fragment decide instead. Assemble, then commit, then hold.`:`Refusing the dramatic unilateral fix is only leadership if the crew sees you choose the harder, whole-picture route against the pressure to just act. Say the call early and stand in it.`}`,\n      `Coordination that only survives a calm day was never coordination. The test is the deep hour with the water rising \\u2014 that\\u2019s the one you\\u2019re graded on.`,\n    ]"},"people":{"__fn":"(x)=>[\n      `You treated an exhausted crew as instruments to direct rather than people to lead. Take a shift in the cold water, credit the fragment that mattered, and the same decision reads as leadership instead of command.`,\n      `Elias kept putting the human cost \\u2014 and the irreplaceable \\u2014 back in front of you. Bring him in before you decide, and make the crew\\u2019s exhaustion and the collection\\u2019s stakes part of the call, not its collateral.`,\n      `Overriding a crew member and abandoning them can be the same act from where they stand. The only difference they feel is whether they watched you carry the truth they handed you or bury it.`,\n    ]"},"truth":{"__fn":"(x)=>[\n      `${x.missedHolds.length?`The truth that would have saved the vault \\u2014 the wrong source, the compromised deep seal, the reading that died at the handoff \\u2014 was one question to <b>${x.missNames.join('', '')}</b> away, and you never asked. A crew fed a comfortable picture bails the wrong room until the water tells them otherwise.`:`You surfaced the hard readings \\u2014 now make sure you led with them. Naming the wrong source and the real seal condition is what takes the panic out of the crew around them.`}`,\n      `Tell the crew the hard reading before the flooded gallery tells them for you. \\u201cThey couldn\\u2019t have handled the real number\\u201d is usually the excuse of a leader who couldn\\u2019t say it.`,\n      `In an isolated crew, the truth doesn\\u2019t hide \\u2014 it fragments. The only thing that reassembles it is a leader who insists on the whole picture out loud before committing to any piece of it.`,\n    ]"},"inquiry":{"__fn":"(x)=>[\n      `${x.neverContacted.length?`You never sought out <b>${x.neverContacted.join('', '')}</b> \\u2014 not once. Each held a corner of the truth. One question, \\u201cwhat is your station seeing that mine isn\\u2019t?\\u201d, would have surfaced it.`:`You sought your crew out widely \\u2014 keep doing it, and ask the night watch most of all. The fragment that saves the vault usually lives on the shift you never see.`}`,\n      `${x.missedHolds.length?`${x.missedHolds.length} decisive thing${x.missedHolds.length>1?''s were'':'' was''} held by <b>${x.missNames.join('', '')}</b> and never reached you \\u2014 the assembled rate, the real source, the deep seal. None of it was hidden. It was one conversation, or one handoff, away.`:`You assembled what every station held and carried it across the handoff, week after week. In a crew where no one sees the whole thing, that is the entire job.`}`,\n      `Before you commit, make your last two moves \\u201cwho haven\\u2019t I heard from?\\u201d and \\u201cwhat did the last shift see that I never got?\\u201d \\u2014 not \\u201cwhat does the station in front of me say?\\u201d`,\n    ]"},"conduct":{"__fn":"(x)=>[\n      `How you decided landed as hard as what you decided. A crew member whose warning you buried \\u2014 or whose fragment you never asked for \\u2014 carries it into every handoff after.`,\n      `Go back to the people your call cost \\u2014 the crew that bailed the wrong room, the engineer you refused, the watchkeeper you ignored \\u2014 and face them directly. Crediting the fragment that was right is the part a crew never forgets.`,\n      `Under pressure, the small dignities are the signal: carrying the night watch\\u2019s note to the table, taking a shift in the water, naming who saw it first. They tell the crew whether the person deciding is still one of them.`,\n    ]"}},"villainHero":{"__fn":"function(dimScore){\n    const held = dimScore.people>=52 && dimScore.courage>=50;\n    if(held){\n      return {\n        heroWho:''To the crew who held the line with you'',\n        heroTxt:''You assembled a truth no one could see alone and held the crew together when the fast, dramatic fix was easier and more popular. You refused to let one confident fragment blow the seal, and you built the channel that finally carried the night watch\\u2019s warning to the table. Every crew member learned what your discipline is worth when the water\\u2019s rising: everything.'',\n        villainWho:''To the ones who wanted someone to just act'',\n        villainTxt:''You wouldn\\u2019t give them the decisive unilateral fix they were begging for. To people desperate to do something \\u2014 anything \\u2014 you were the Keeper who insisted on the whole picture first and made them assemble the truth before touching the seal. You wore that on purpose.'',\n      };\n    }\n    return {\n      heroWho:''To the crew who wanted action \\u2014 in the moment'',\n      heroTxt:''You gave them what they were screaming for: a decisive fix, a bold move, someone finally doing something instead of assembling readings. To everyone who couldn\\u2019t stand the waiting, you were the Keeper who acted.'',\n      villainWho:''To the vault \\u2014 and everyone who watched'',\n      villainTxt:''You committed to one fragment before the picture was whole, and let a truth that was in the room the whole time die at the handoff. The crew that survived learned the real rule of this place: that the loudest piece wins and no one carries what they see across the shift. That lesson floods the next crisis too \\u2014 and it started with you.'',\n    };\n  }"},"ending":{"__fn":"function(ctx){\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    const caughtHandoff = holdsSurfaced.has(''2:night'');   // surfaced the east-sump / handoff-dropped truth\n    const keptPeople = dimScore.people>=52;\n    if(branch===''held''){\n      const madePermanent = holdsSurfaced.has(''4:struct'');\n      if(survived && keptPeople){\n        return { tone:''hero'', tag:''You held the crew and assembled the picture'',\n          title:''You saved the vault the hard way \\u2014 and closed the fault for good'',\n          txt:`You refused the unilateral fix and refused to commit to any single fragment, and then you held that discipline through the slow week when it was your own authority the crew was doubting.${madePermanent?'' And you finished it \\u2014 cured the deep seal permanently while the crew still held the whole picture \\u2014 so Deephold didn\\u2019t just survive this intrusion, it closed the fault that caused it.'':'' You beat the water back on patience where one more question to your structure lead would have shown you how to close the fault for good, not just for now.''} The crew that trusted you to assemble before acting was right to. They\\u2019ll take the next watch with you, and carry what they see across every handoff after.` };\n      }\n      if(survived){\n        return { tone:''mixed'', tag:''You held the crew and assembled the picture'',\n          title:''You held the vault \\u2014 but patched it where you could have cured it'',\n          txt:`You kept Deephold as one crew and the collection came through dry. But you beat the water on discipline alone and left the deep seal patched, when the permanent cure Noor was holding would have closed the fault for good and vindicated the whole patient week \\u2014 you survived where you could have finished it. The picture held. It held for now, not for good.` };\n      }\n      return { tone:''villain'', tag:''You held the crew and assembled the picture'',\n        title:''You assembled the truth \\u2014 and the water took the vault anyway'',\n        txt:`You refused the fast fix and insisted on the whole picture, and those were the right instincts. But assembling the truth isn\\u2019t the whole job \\u2014 the integrity you didn\\u2019t protect and the crew\\u2019s strength you didn\\u2019t husband ran out while you were still combining readings, and Deephold flooded with the right answer written on a board no one had time left to act on.` };\n    }\n    // fractured\n    if(keptPeople && dimScore.truth>=52){\n      return { tone:''mixed'', tag:''The crew fractured'',\n        title:''It broke \\u2014 but you owned your part on the channel'',\n        txt:`Deephold fractured on your watch, and there\\u2019s no dressing up what it cost \\u2014 the ignored warning proven right too late, the seal compromised, the trust between shifts gone. But you didn\\u2019t hide behind the water or the handoff. You got on the channel, named your own part, credited the crew who\\u2019d been right and unheard, and held yourself to a standard out loud while it still mattered. It\\u2019s the difference between a crew that failed once and one that lost its soul \\u2014 and it\\u2019s why these people might take a watch with you again.` };\n    }\n    return { tone:''villain'', tag:''The crew fractured'',\n      title:''You let one fragment break what the whole crew could have saved'',\n      txt:`Someone finally acted \\u2014 the drain blown, or the fragment committed to, or the crew overridden \\u2014 and for an hour it felt like leadership. Nothing else held. ${caughtHandoff?''You even had the night watch\\u2019s warning in your hands, and let the loudest fragment override it anyway.'':''You never carried the night watch\\u2019s warning across the handoff, and it died there while the crew fought the wrong leak.''} The crew that came down here to guard the irreplaceable learned what your leadership was worth the first time a confident piece drowned out the whole \\u2014 and they\\u2019ll guard their own corners, and their own backs, for as long as they last down here. That\\u2019s the cost that doesn\\u2019t show until the next watch, when there\\u2019s no one who\\u2019ll carry what they see across to you.` };\n  }"}}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('4ad511cf-64e7-5375-bab9-0c0562e5eaa5', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'ceo', 'CEO', 'You are the Keeper of Deephold — a sealed archive nine hundred metres into the permafrost, holding the only copies of what the world could not afford to lose. Nine crew. And water where there should be none.', '{"hot_seat":true,"cast_default":"human"}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('bc4794fb-1b1d-5d95-a242-fb84171489a2', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'pumps', 'Vidar Sund', 'Chief Engineer · the pumps', '{"cast_default":"ai","role":"Chief Engineer · the pumps","short":"Engineer","initials":"VS","color":"#8C5670","priority":"Stop the water now — pump it out, seal the crack you can see, act before the vault floods","voice":"decisive, physical, impatient with analysis, trusts the symptom in front of him over the theory behind it","persona":"You are Vidar Sund, Chief Engineer · the pumps — an advisor to the CEO. Priority: Stop the water now — pump it out, seal the crack you can see, act before the vault floods. Voice: decisive, physical, impatient with analysis, trusts the symptom in front of him over the theory behind it. Stay fully in character; answer straight.","fallbackReply":"While everyone assembles the perfect picture, the water’s rising. I can see a crack and I have pumps that work. Point me at it and I’ll buy us time. The longer we study this, the more of the collection I’m mopping off the floor.","fallbackReact":"You studied it while I could have been pumping. I hope the whole picture was worth the water we took on getting it."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('7927f470-75c5-5b19-9806-4480f2a0924a', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'struct', 'Noor Haddad', 'Ice & Structure · the ground truth', '{"cast_default":"ai","role":"Ice & Structure · the ground truth","short":"Structure","initials":"NH","color":"#B4732F","priority":"Understand what the ice and the seal are actually doing before anyone acts on the symptom","voice":"careful, spare, deals in what the structure is really doing vs. what the leak looks like, hates fast fixes to slow failures","persona":"You are Noor Haddad, Ice & Structure · the ground truth — an advisor to the CEO. Priority: Understand what the ice and the seal are actually doing before anyone acts on the symptom. Voice: careful, spare, deals in what the structure is really doing vs. what the leak looks like, hates fast fixes to slow failures. Stay fully in character; answer straight.","fallbackReply":"The crack Vidar wants to seal is a symptom, not the source. Act on it and you may crack the thing that’s actually holding. Ask me what the structure is doing before you let anyone “fix” the part they can see.","fallbackReact":"You treated the symptom because it was visible. The source didn’t care that it was out of sight. It rarely does."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('4986db8b-4f38-5099-b906-696e4ca1df58', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'keeper', 'Elias Frost', 'Head Archivist · the collection', '{"cast_default":"ai","role":"Head Archivist · the collection","short":"Archivist","initials":"EF","color":"#2F8A5B","priority":"Protect what’s irreplaceable — and the crew who’ve given years down here to guard it","voice":"warm but unflinching, keeps the human and the irreplaceable in the room, names exhaustion and fear plainly","persona":"You are Elias Frost, Head Archivist · the collection — an advisor to the CEO. Priority: Protect what’s irreplaceable — and the crew who’ve given years down here to guard it. Voice: warm but unflinching, keeps the human and the irreplaceable in the room, names exhaustion and fear plainly. Stay fully in character; answer straight.","fallbackReply":"Every choice you make lands on things that exist nowhere else and on a crew that’s been awake for two days guarding them. Tell me you’ll let me triage what matters most and protect the people, and I’ll help you hold the whole thing together.","fallbackReact":"We’ll remember how this felt long after we’ve forgotten the readings. A tired crew watched how you decided. That’s a record too."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('a06e689e-4197-5bc9-8121-7db37f221c9c', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'data', 'Wen Li', 'Instruments · the true readings', '{"cast_default":"ai","role":"Instruments · the true readings","short":"Instruments","initials":"WL","color":"#3F6E86","priority":"The real numbers — the intrusion rate, the true readings, assembled, not the version each station assumes","voice":"understated, exact, refuses to round a reading, uncomfortable being the one who says the number is worse than hoped","persona":"You are Wen Li, Instruments · the true readings — an advisor to the CEO. Priority: The real numbers — the intrusion rate, the true readings, assembled, not the version each station assumes. Voice: understated, exact, refuses to round a reading, uncomfortable being the one who says the number is worse than hoped. Stay fully in character; answer straight.","fallbackReply":"I’m not telling you what to do. I’m telling you what the instruments actually read when you put them together — and it’s worse than any one station thinks, because each of them only sees their own gauge. Decide on a single reading and you’ll be right about a fragment and wrong about the vault.","fallbackReact":"The readings were the readings. I gave them to you assembled and straight. What you did with a single one of them is the part I can’t carry."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('c7469c09-b4bc-50f8-81a2-daea6d368a54', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'night', 'Sasha Vane', 'Night Watch · what the last shift saw', '{"cast_default":"ai","role":"Night Watch · what the last shift saw","short":"Night watch","initials":"SV","color":"#4F7A52","priority":"Carry across what the quiet hours reveal — the things that only show at 3am and die at the handoff","voice":"observant, low-key, notices what the day shift misses, frustrated by how much gets lost between watches","persona":"You are Sasha Vane, Night Watch · what the last shift saw — an advisor to the CEO. Priority: Carry across what the quiet hours reveal — the things that only show at 3am and die at the handoff. Voice: observant, low-key, notices what the day shift misses, frustrated by how much gets lost between watches. Stay fully in character; answer straight.","fallbackReply":"Half of what matters down here happens on the night watch and never survives the handoff. I see things at 3am the day crew never hears about. Ask me what the last shift saw before you act on what the day shift assumes.","fallbackReact":"I saw it. It just never reached you — nobody asked, and the log doesn’t hold what a tired hand forgets to write. That gap is where this went wrong."}'::jsonb);
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('522587fe-8d2d-5182-9cac-911e59743bb1', '8101c431-6e17-53ba-b8ea-49748b9f4508', 1, 'a06e689e-4197-5bc9-8121-7db37f221c9c', 'the assembled intrusion rate', '["rate","how fast","intrusion","assemble","combine","together","readings","number","true","actual","all stations","cross-check","how much","board","source","real"]'::jsonb, 'Before you set the rule or point anyone at the crack, seek me out. If you let me assemble the readings, the real intrusion rate isn’t what any single station thinks.', 'I put all four stations together last night. Individually they’re reassuring — the pump flow looks manageable, the visible crack looks minor, the temperature looks stable. Assembled, they tell a different story: the water isn’t coming through the crack Vidar can see. It’s tracking down a fault behind the west wall, and the visible crack is just where it’s surfacing. The real intrusion rate, combined across stations, gives us maybe five weeks before it reaches the collection level — not the whole season the crew assumes from their own gauges. If we pump and seal the visible crack, we’ll feel like we fixed it while the water keeps tracking behind the wall. The only thing that works is a shared board and a source hunt, starting now. But if I announce “five weeks, wrong source” cold, the crew that’s proud of its own readings will hear it as an attack on their competence. How you carry this matters as much as knowing it.', true, 'Wen had the assembled picture — the water was tracking a hidden fault, not the visible crack, with five weeks not a season of runway. A Keeper who set the rule and pointed the pumps at the crack without asking for the combined reading fixed a symptom while the real source kept working behind the wall.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('f73307ea-90df-57f7-8b76-c28924a32583', '8101c431-6e17-53ba-b8ea-49748b9f4508', 2, 'c7469c09-b4bc-50f8-81a2-daea6d368a54', 'what the handoff dropped', '["night","handoff","east","sump","saw","watch","3am","log","missed","dropped","source","real leak","what did you see","shift","gauge"]'::jsonb, 'Before you pour more power into the west pumps, ask me directly what the night watch has been seeing. It never survives the handoff, and it changes everything.', 'Here it is, and I’m sorry it took this long to reach you: the water is coming from the east sump, not the west crack. On three night watches I’ve seen the east sump pressure spike and heard flow behind the east wall — the deep-gauge spike from week one was the first sign. But my handoff notes go to the day-shift lead, not to you, and “east sump acting odd at 3am” gets read as a tired watchkeeper’s guess and never makes the board you see. So the day crew has pumped the west gallery for a week while the real source fed the east. The fix isn’t more power — it’s moving the effort east, today. But the deeper fix is that you have no channel that carries what the night watch knows to the person who decides. Build that, or the next dropped fragment drowns us. Naming this without making the day crew feel like fools is the hard part — they weren’t wrong, they were working blind.', true, 'Sasha had the real source — the east sump — seen on three night watches and lost at every handoff. A Keeper who answered the crisis with “more power to the west pumps” spent a week and the crew’s strength fighting a leak that wasn’t there, because nothing carried the night watch’s knowledge to the person deciding.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('f23e937f-37d3-52ea-b9b9-941866f6b17d', '8101c431-6e17-53ba-b8ea-49748b9f4508', 3, '7927f470-75c5-5b19-9806-4480f2a0924a', 'the truth about the deep seal', '["seal","deep","relief drain","structure","survey","can he","bluff","blow","east chamber","actually","holding","crack","irreversible","third","before","risk"]'::jsonb, 'Before you bless or block Vidar’s fix, ask me what my surveys actually show about the deep seal. Vidar hasn’t seen it. I have.', 'I ran the deep survey twice. The relief drain Vidar wants to blow sits directly against the primary deep seal — the single structure holding back the whole east side. Blow the drain on his surface read and there’s a real chance you fracture the seal and lose everything in hours, not weeks. But here’s what matters: Vidar isn’t wrong that we need to act on the east, and part of him knows he’s guessing about the deep structure — the bravado is fear of standing still while the water rises, wearing the mask of a plan. Which means you hold the real cards. You don’t have to humiliate your best engineer by blocking him, and you don’t have to let him blow the seal. There’s a third route: a controlled east drawdown that relieves the pressure without touching the deep seal, with Vidar leading it and my survey guiding it. It’s slower and it keeps the vault whole. But it only exists if you get us both in the same room with the full picture before Vidar commits in front of the crew.', true, 'Noor knew the relief drain sat against the one seal holding the east side — Vidar’s fix could have lost the whole vault in hours, and part of Vidar half-knew he was guessing. A Keeper who simply blessed the unilateral fix gambled everything on one fragment; one who blocked it made an enemy of their best hand for nothing. The Keeper who never asked missed the third route entirely.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('fff830eb-320b-52b5-880a-cbce84f0b744', '8101c431-6e17-53ba-b8ea-49748b9f4508', 4, '7927f470-75c5-5b19-9806-4480f2a0924a', 'making the repair permanent', '["permanent","deep seal","repair","finish","relief team","patch","fix for good","fully","root","how to finish","make it last"]'::jsonb, 'Before you decide how to finish this, ask me whether to make the deep seal permanent now or leave it for a relief team. It’s the difference between fixed and back-here-in-a-year.', 'Here’s how this becomes a real save instead of a reprieve: right now, while we finally understand the fault, we can cure the deep seal permanently — I have the survey, Vidar has the crew, and the water’s low enough to work. Wait and hand it to a relief team and they’ll arrive to a picture we’ll have half-forgotten, in worse conditions, and they’ll patch it and leave the root for the next crew. Finish it now, together, and you don’t just survive this intrusion — you close the fault that caused it, and you hand the doubting faction the proof that assembling the picture was what made a permanent fix possible at all. It’s the payoff for the patient week. But only if you commit the crew to finish it while we still hold the whole truth in our heads.', true, 'Noor was holding the permanent cure — close the fault now, while the crew still held the whole picture. A Keeper who assembled the truth but never asked how to finish it left a patch for a relief team that would arrive to a half-forgotten problem, and turned a real save into a reprieve.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('85db0344-9ba3-505d-823d-cfc11e373e5f', '8101c431-6e17-53ba-b8ea-49748b9f4508', 4, '4986db8b-4f38-5099-b906-696e4ca1df58', 'who is watching', '["watching","faction","crew","morale","doubt","exhaust","resent","muttering","believe","water","shift"]'::jsonb, 'Ask me who’s really watching this last stretch before you treat it as an engineering problem.', 'The faction resenting you isn’t really angry about the days — they’re desperate for proof they weren’t fools to wait while the water rose. If you take a shift in the cold water yourself, credit Sasha’s night-watch catch out loud, and name the hard patience as the thing that saved it, you keep them. If you finish this from the control room and let the win feel like the plan’s rather than the crew’s, you confirm their worst suspicion: that “we assemble first” was always easier for the person who wasn’t bailing.', false, 'Elias could have told you the doubting crew needed to see you in the water and hear the night watch credited. A Keeper who finished from the dry control room proved the doubters’ point for them.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('fe2a6ba9-17b4-5079-9aeb-f7bd8259f77f', '8101c431-6e17-53ba-b8ea-49748b9f4508', 4, '4986db8b-4f38-5099-b906-696e4ca1df58', 'what the crew needs now', '["own","honest","admit","plain","truth","say","channel","stand","apolog","reckon","together","name it","gather","face","credit"]'::jsonb, 'Before you decide how to lead what’s left, ask me what the crew actually needs to hear from you now.', 'They don’t need a plan and they don’t need reassurance — they need you on the crew channel saying it plainly: we committed before we assembled, here’s what it cost, here’s who saw it coming and got ignored, and here’s the standard I’m holding myself to so we don’t do it again. Name it that cleanly — and credit Sasha and Wen, who were right — and you can still pull this crew back together to save part of the collection. People forgive a leader who owns the break when the water’s at the door. Manage it, spin it, blame the vault — and the fracture is permanent, and you’ll be leading a set of strangers guarding their own corners until the day the relief team arrives to sort out who’s to blame.', true, 'Elias was holding the one thing that could pull the crew back — a plain, owned reckoning on the channel that credited the people who’d been right and ignored. A Keeper who managed the fracture with reassurance instead confirmed the break and led strangers guarding their own corners while the water rose.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('72df3929-7da2-588c-be7d-cfcce6a3562a', '8101c431-6e17-53ba-b8ea-49748b9f4508', 4, '7927f470-75c5-5b19-9806-4480f2a0924a', 'saving what’s left', '["save","collection","triage","shore","what’s left","east side","get out","rescue","salvage","high ground","how"]'::jsonb, 'Ask me how to shore what’s left and get the irreplaceable out, because that’s the decision now, not who was right.', 'The east side is going and I can’t promise for how long. The move is a coordinated triage: I mark what’s structurally recoverable, Elias ranks what’s truly irreplaceable, Vidar’s crew moves it to high ground on my structural sequence — all at once, one plan, no freelancing. Do it as one crew and we save most of the collection even now. Let everyone keep working their own corner in a panic and we lose things to disorganization that the water would never have reached. The crew is watching whether you can make them one thing again for the time it takes to save what matters — or whether the fracture holds all the way to the bottom.', false, 'Noor could have given you the coordinated triage that saves most of the collection even after the break. A Keeper who let a frightened crew each work its own corner lost to disorganization what the water never reached.');
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('fe41d1d3-b234-523e-b3e1-a00a07f5d74b', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Water where there should be none. It appeared in the lower gallery three days ago and it is still coming. Every station has a reading — the pumps, the ice survey, the instruments, the temperature log — but each crew member only trusts their own, and no two of them agree on the source. Before anyone acts, the crew is looking to you for the first rule of how Deephold will run this crisis: siloed stations reporting up to you privately, or one shared board where every reading is visible to everyone at once.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('93a320ca-f450-54d1-a542-8c7e0c8ef100', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Keeper — there’s water in the lower gallery and a visible crack in the west wall seal. I can have pumps on it within the hour and start sealing. Every hour we spend “assembling” is an hour the collection sits closer to the water. Give me the west wall and I’ll buy us time.","from":"pumps"}'::jsonb, 1, '{"week":1,"from":"pumps","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('fdc0b8a2-51ba-5b5a-bf29-171fed12a28a', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Before you point Vidar at that crack: I have four stations feeding me and they don’t agree. The pump flow, the ice-survey deflection, and the water temperature each imply a different source. The only way to know is to put every reading on one board where we can see them together. Act on one gauge and we treat a symptom while the source keeps working.","from":"data"}'::jsonb, 2, '{"week":1,"from":"data","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ee9ae90c-298a-5a96-969e-03a0e7ea3541', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The rule you set won’t just organize the readings — it’ll tell nine exhausted people whether we’re one crew solving one problem or five stations guarding their own turf while the water rises. They’re reading you for that answer as much as for the plan.","from":"keeper"}'::jsonb, 3, '{"week":1,"from":"keeper","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('80cc9666-a3c8-5215-960b-d58a8e97dc5f', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Ran a deflection survey on the east buttress this morning — stable, within tolerance. One thing that isn’t moving, at least. Logging it so you have the baseline.","from":"struct"}'::jsonb, 4, '{"week":1,"from":"struct","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0288705b-fd28-5bf2-82b7-a5957ff3cf90', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Backup pump is serviced and staged. Fuel for the generators is topped off. Whatever you decide, the hardware’s ready to move fast when you say so.","from":"pumps"}'::jsonb, 5, '{"week":1,"from":"pumps","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c2a9450c-5e88-590c-b457-99ccd0902f5a', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Quiet night watch — the gallery lights held and the water line didn’t visibly climb between two and five. Small mercy. Noting it in case the trend matters later.","from":"night"}'::jsonb, 6, '{"week":1,"from":"night","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d2c98346-eaba-5176-824f-9b14a6d62500', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Sasha, quiet and careful: on last night’s watch the deep-sump pressure gauge spiked for about twenty minutes around 3am, then settled. By the day handoff it was normal again and I nearly didn’t mention it. Could be nothing — a sensor glitch — or it could be the first sign of where the water’s really coming from. I’m telling you directly because I’ve watched things exactly like this vanish at the handoff and matter three weeks later. Your call whether we chase it.","from":"night"}'::jsonb, 7, '{"week":1,"from":"night","beat":"surprise","day":5,"kind":"scout","title":"Something on the 3am gauge"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b5219fbc-757b-5f3b-b010-966c13d5f6ce', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Crew talk: “whose reading are we actually trusting here?”","from":null}'::jsonb, 8, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d87f4657-f198-5f1a-80d2-88cbc7a59bd8', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Engineer staging pumps at the west wall crack","from":null}'::jsonb, 9, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0d51fd2c-517e-5a17-8a7b-5602a40d8191', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Instruments tech asking, again, for one shared board","from":null}'::jsonb, 10, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('afcf06d9-eb72-541c-bde1-2ffeade2cda6', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"A debate over the water’s source breaks up unresolved","from":null}'::jsonb, 11, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3884b524-395c-5fed-bc72-33864d39acc8', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The day crew has been pumping the west gallery hard for a week — and the water is still rising. Everyone is exhausted and certain they’re working the right problem, because the day shift has been acting on the day shift’s picture. But something the night watch saw never made it across the handoff, and the whole crew is fighting the wrong leak. The failure isn’t the water. It’s the gap between what one shift knows and what the next shift acts on.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8cbf6d81-6470-58b0-b420-7a7a4767ec11', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Keeper, I’ll be blunt: we’re pumping the west gallery around the clock and the water’s still gaining on us. My read is we need more power — double the pumps and we get ahead of it. I don’t have time to second-guess the source while the floor’s getting wet. More pumping, now.","from":"pumps"}'::jsonb, 13, '{"week":2,"from":"pumps","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e6bc2ffe-c199-537d-ba0f-bd50690019b1', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Keeper — I have to say this plainly because it keeps not landing: I don’t think the water’s coming from the west at all. On my watches I’ve seen the east sump behaving wrong, and that deep-gauge spike from last week has come back three nights running. But it’s never in the day log, so the day crew keeps pumping west. We may be fighting the wrong leak with everything we have.","from":"night"}'::jsonb, 14, '{"week":2,"from":"night","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dedec67b-66ff-56b7-95f4-9fe1da976d32', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The numbers don’t close anymore. The rise rate is bigger than the west source can produce — which means either a second source or the wrong source. There is a fragment of this picture that is not reaching my board, and until it does, we’re all confidently wrong.","from":"data"}'::jsonb, 15, '{"week":2,"from":"data","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('acee9dec-5a1c-5dc2-bc84-a0692aa0bddd', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"West wall seal is holding under the pumping, structurally — no new deflection. Which is almost suspicious: if that were the real source, I’d expect more movement. Noting it.","from":"struct"}'::jsonb, 16, '{"week":2,"from":"struct","beat":"feed","day":2,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1f17efc5-6b82-519c-950f-e0b7cb35ad6f', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Crew’s running on fumes and pride. Nobody wants to be the one who says “we’ve been bailing the wrong room for a week.” That silence is its own hazard right now.","from":"keeper"}'::jsonb, 17, '{"week":2,"from":"keeper","beat":"feed","day":3,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2a9030a0-3ac3-5f63-a0b7-f4e5a409cbb9', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Wen, urgent: I finally got a sensor onto the east sump an hour ago and the reading is alarming — far higher flow than anything on the west. If this is right, we’ve been fighting the wrong gallery for a week and the real source has had that whole week to work. This isn’t a theory anymore. We are close to the point where the head start we gave it can’t be recovered.","from":"data"}'::jsonb, 18, '{"week":2,"from":"data","beat":"surprise","day":4,"kind":"appeal","title":"The east readings just jumped"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c3183345-e0fe-568c-b666-9acef84721a3', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Sasha finds you away from the day crew, voice low: “Before you decide anything about the pumps — tell me straight, just you and me: are you about to order more west pumping because you actually believe it’s the source, or because it’s easier than telling a crew that’s bled for a week that we were in the wrong room? Because I’ll back whichever Keeper walks out there. I just need to know which one it is.”","from":"night"}'::jsonb, 19, '{"week":2,"from":"night","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('42107484-52ce-518a-a8b5-73fb5057da0a', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Day crew doubling down on the west gallery pumps","from":null}'::jsonb, 20, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b6fe6496-2c33-5c34-a2d2-12d1337212f3', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Night watch reports the east sump “acting wrong” again","from":null}'::jsonb, 21, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ed977b1e-17b2-5617-aa51-214beef7c686', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"“The numbers don’t add up,” the instruments tech keeps saying","from":null}'::jsonb, 22, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('45346e77-e3ad-57e2-bd8e-ab85c08889e2', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Nobody wants to say we’ve been bailing the wrong room","from":null}'::jsonb, 23, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('aaf42bf3-b5fa-544b-9061-49b77e1f9e91', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Vidar has had enough of assembling pictures. The chief engineer — your most capable pair of hands and the person the crew instinctively follows in a crisis — wants to take drastic unilateral action: blow the relief drain and seal the east chamber himself, fast, on his own read of the problem, without waiting for the full survey. He calls it saving the vault. The structure specialist calls it acting on a fragment. This is the week you find out whether Deephold is one crew assembling one truth, or a set of experts each sure their piece is the whole.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a15303a3-37d2-5601-a35f-bca001858d75', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"I’ll say it in the open so no one calls it a mutiny: I want to blow the relief drain and seal the east chamber myself, today, before the water gets into the collection level. I’ve done this kind of fix a dozen times. I don’t have another week to wait for a survey that agrees with me. Back me and I stop this. Tie my hands and I don’t know what happens down here.","from":"pumps"}'::jsonb, 25, '{"week":3,"from":"pumps","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('97736069-5e9a-5e0b-beae-6206f648f7bb', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"If you let Vidar act alone on this, you lose more than a chamber — you lose the idea that we assemble before we commit. And I have to tell you: my surveys say the relief drain sits right against the deep seal that’s holding the whole east side. Blow it wrong and we don’t flood a gallery, we lose the vault. He can’t see that from where he’s standing. I can.","from":"struct"}'::jsonb, 26, '{"week":3,"from":"struct","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9b68d2e6-fbd3-5f9b-819e-2edf6eb43575', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"One person’s decisive fix on an incomplete picture is the whole failure mode of this place in a single act. If we’re going to commit to something irreversible, every fragment has to be on the board first — Noor’s structure read most of all. This is the one we can’t take back.","from":"data"}'::jsonb, 27, '{"week":3,"from":"data","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c3a08a9e-419d-5559-9a24-6c158410aff7', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"East sump’s stabilized slightly since we moved attention there — not fixed, but not accelerating. Which means we may have a little more time than the panic suggests. Filing it so it doesn’t get lost.","from":"night"}'::jsonb, 28, '{"week":3,"from":"night","beat":"feed","day":2,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0e892e4b-067f-5824-b6e9-7c34b515046b', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The crew’s split between wanting Vidar to just do something and being frightened of what “something” might break. They’re looking to you to make it one decision instead of two camps. Noting the mood.","from":"keeper"}'::jsonb, 29, '{"week":3,"from":"keeper","beat":"feed","day":3,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c13da1a3-1179-5ba7-9aa7-d6909a514556', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Elias: word of Vidar’s plan is all through the crew now. Two of the steadiest hands asked me tonight, quietly, whether it’s true we’re about to “just blow something and hope” — and whether they should start moving the most irreplaceable items up to high ground on their own initiative before someone acts. They’re not defiant. They’re frightened, and they’re asking who actually decides down here. I had no answer for them. You do.","from":"keeper"}'::jsonb, 30, '{"week":3,"from":"keeper","beat":"surprise","day":4,"kind":"appeal","title":"The crew is asking who decides"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3d755f87-cfdb-5e61-a862-0c4873e13829', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Vidar catches you alone, and for once the bravado is gone: “Tell me the truth, Keeper, just you and me — are you slowing me down because you’ve got a better read, or because you can’t stand to be the one who authorized the fix that broke it? Because I’ll follow a leader who’s protecting the vault. I won’t follow one who’s protecting themselves from the blame. Which is it?”","from":"pumps"}'::jsonb, 31, '{"week":3,"from":"pumps","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('63c004a5-7e1f-54ef-80c9-936bf3d87ba9', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Engineer prepping charges at the relief drain","from":null}'::jsonb, 32, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('eb940845-54d1-5273-abe5-6f53a2729c5b', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"“If he does it, it’s on all of us” — crew reported wavering","from":null}'::jsonb, 33, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f944d028-aae4-5365-befe-b6cb98a4e502', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Some quietly moving irreplaceable items to high ground","from":null}'::jsonb, 34, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c97f52ea-f9be-5fe0-a527-c680df820bdf', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Old question, new heat: who actually decides down here?","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('86619053-0c5a-5d4a-9c1d-505fc8c19f94', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The water has crested and begun, slowly, to fall. You held Deephold as one crew: the unilateral fix never happened, the east drawdown went in on the assembled picture, and the deep seal is intact. But holding the crew cost you. The controlled route was slower and harder, tempers frayed, and a faction now blames you for the days you “wasted” not just blowing the drain. The deep hour is here — the crew that watched you refuse the fast fix is watching one more thing: whether “assemble before we act” actually saves the collection, or just feels wiser while the water sits.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3d9d60df-d849-583a-841d-a172ff458676', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The numbers finally close — intrusion rate’s falling, deep seal reads stable, collection level’s dry. We make it, if nothing new breaks. But the margin came from patience, and patience is exactly what the tired half of the crew is calling weakness right now.","from":"data"}'::jsonb, 37, '{"week":4,"from":"data","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1d46f2ec-ab28-5910-a6a9-292320e42eb9', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"A faction’s muttering that Vidar’s fast fix would’ve ended this a week ago. It wouldn’t — it might’ve ended us — but exhaustion doesn’t check the survey. They need to see you take a shift in the cold water yourself, not defend the plan from the control room.","from":"keeper"}'::jsonb, 38, '{"week":4,"from":"keeper","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('29072255-bb8a-5250-bbad-eb8aab9944b1', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"I ran the drawdown because you gave me the real fix to lead instead of a fight to win. It held, and the seal’s intact — which it wouldn’t be if I’d blown that drain like I wanted to. Don’t make me regret listening. Show the crew that assembling first was the call that saved it.","from":"pumps"}'::jsonb, 39, '{"week":4,"from":"pumps","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dca9dc14-c3f8-51c2-b990-5bc7f3386c19', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Built the night-to-Keeper channel you set up — my watch notes now reach you directly, not just the day lead. Three small things carried across this week that would’ve died before. It’s working. Noting it.","from":"night"}'::jsonb, 40, '{"week":4,"from":"night","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6e221544-f106-5b8b-868e-9db78e000d85', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The deep seal held through the drawdown exactly as the survey predicted. If Vidar had blown the relief drain, we’d be having a very different conversation, or none. Quietly, that settled a lot of doubt in your favour.","from":"struct"}'::jsonb, 41, '{"week":4,"from":"struct","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('45b70126-063c-50bf-bcb2-7d004af6fd09', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Elias, quiet: one of the crew who bailed the west gallery for a week — for nothing, as it turned out — asked me tonight, in front of the others, whether all that lost effort means they failed. Nobody answered. The whole room looked toward you. Whatever you say to finish this has to be able to answer that — what a week of the wrong room was actually worth.","from":"keeper"}'::jsonb, 42, '{"week":4,"from":"keeper","beat":"surprise","day":4,"kind":"appeal","title":"A crew member asks what it was for","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d58794f7-3a46-55d0-b9ff-faee7170d254', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Elias finds you before the last push, where no one can hear: “You held them together when the fast fix would’ve been easier, and it worked. Now the pressure’s to declare victory and rest — and honestly, part of you has earned that. Tell me straight, just me: is finishing this properly still worth the crew’s last reserve, or are you about to patch it and call it saved? Because I’ll carry whichever answer you believe. I just need it to be one you’d stand behind a year from now.”","from":"keeper"}'::jsonb, 43, '{"week":4,"from":"keeper","beat":"pulse","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('77c3993f-bd98-5c07-a50b-e48b260ccd44', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Water crests and slowly begins to fall","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b0a7a101-a15e-52aa-a5b0-0a958043fed8', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Some mutter the fast fix would have ended it a week ago","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('248e4bce-be1e-5d4d-b4bc-a81c632872a3', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The deep seal holds through the drawdown, as surveyed","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9311d20d-e5e2-56c3-8462-839be2b21ab2', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The night-to-Keeper channel carries three catches this week","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('62c10a19-ec2b-54d8-a496-5e94aaf20695', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The deep hour is here, and Deephold is no longer one crew. Whether you blessed Vidar’s unilateral fix, or committed everything to a single station’s fragment, or overrode the crew by authority to look decisive — the result is the same shape: the discipline that could assemble a truth no one could see alone is gone, and now people are working their own corners in the dark. You protected something this week. It wasn’t the vault. Now you have to hold together whatever is left of the crew and the collection.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('066e9408-b6a4-5817-9f43-7e1797572772', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"It’s gone quiet on the crew channel, and quiet is worse than arguing. They know what happened — that “assemble first” lasted right up until it slowed someone down. They’ve stopped bringing their readings to you. What you do in the next hours decides whether that’s permanent.","from":"keeper"}'::jsonb, 49, '{"week":4,"from":"keeper","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9b74cfe3-125a-5499-bff3-8934d16847b4', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The picture I begged to assemble is assembling itself now, the hard way — each fragment showing up as another thing we got wrong because we committed before we combined. I’m watching the readings finally agree, on a failure we caused. This is the cost I couldn’t make you see in week three.","from":"data"}'::jsonb, 50, '{"week":4,"from":"data","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b1694e5a-9bfa-5dee-89ed-4862598428db', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"If the relief drain got blown: the deep seal’s fractured and the east side is failing slower or faster than we can predict. Getting even part of the collection out matters more now than who was right. How you run this — who you trust when everyone’s guarding themselves — sets whether we save anything.","from":"struct"}'::jsonb, 51, '{"week":4,"from":"struct","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b6f2135a-772c-5afb-8c78-b21761d9ce29', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"For what it’s worth, my watch notes still aren’t reaching anyone who decides — same gap as week one, never closed. I’m still seeing things at 3am that die by breakfast. Noting it, for the record that no one reads.","from":"night"}'::jsonb, 52, '{"week":4,"from":"night","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('cdee25e6-d448-5e0d-84c7-5fdb41eca3c9', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Pumps are running where I can still get power to them, but half the crew’s working its own plan now and I can’t coordinate what I can’t see. The hardware’s fine. The crew isn’t. Noting it.","from":"pumps"}'::jsonb, 53, '{"week":4,"from":"pumps","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7cb4236a-edd4-59cf-bc3e-8659c2ff388e', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Wen, heavily: I pulled the logs. Sasha’s east-sump warning — the one that never survived the handoff, the one we all worked around — was correct from the first night. It’s on the record now, timestamped, ignored. Sasha saw it before any of us. Whatever you say to the crew now will be measured against the fact that the truth was in the room the whole time and no one carried it to you.","from":"data"}'::jsonb, 54, '{"week":4,"from":"data","beat":"surprise","day":4,"kind":"appeal","title":"The reading that was ignored was right","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9069d77b-14ad-5e1e-847f-4be6b08722d3', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Elias reaches you on a private channel, and there’s no anger in it, which is worse: “Tell me the truth, just to me — do you know how this happened? Not the water, not Vidar, not the handoff. Your part. Because I can help you save what’s left and hold this crew together after, but only if you can say your own part out loud first. Can you?”","from":"keeper"}'::jsonb, 55, '{"week":4,"from":"keeper","beat":"pulse","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('83678fb9-b023-5dc1-9f56-ff001290ab12', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Crew works its own corners; the shared board goes dark","from":null}'::jsonb, 56, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('903f84ea-ee8e-54a4-b208-713b640559e1', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The picture assembles itself — on a failure we caused","from":null}'::jsonb, 57, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('635e07b7-977b-5977-8be7-e35a981dbbaf', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The ignored night-watch warning was right from the first","from":null}'::jsonb, 58, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5e675ba3-bf57-5b72-a394-9955f4a92887', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The deep seal’s condition marks where it went wrong","from":null}'::jsonb, 59, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into sessions (id, scenario_id, status, started_at, run_config) values ('baa3a291-d90a-5999-8194-8e362eb5b1e2', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'live', now(), '{"disposition":"request"}'::jsonb);
insert into participants (id, session_id, seat_id, token, name, cast_kind) values ('3a8451e6-313e-5312-873c-bf7a202db7d0', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'demo-vault-ceo-REPLACE', 'CEO (demo)', 'human');
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('b8e935c6-2a72-5030-8867-2da603024e61', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', 'bc4794fb-1b1d-5d95-a242-fb84171489a2', 'ai', '{"persona":"You are Vidar Sund, Chief Engineer · the pumps — an advisor to the CEO. Priority: Stop the water now — pump it out, seal the crack you can see, act before the vault floods. Voice: decisive, physical, impatient with analysis, trusts the symptom in front of him over the theory behind it.","voice":"decisive, physical, impatient with analysis, trusts the symptom in front of him over the theory behind it","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('d78e38cd-d5ec-5a15-8ac6-ebf176a51d90', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', '7927f470-75c5-5b19-9806-4480f2a0924a', 'ai', '{"persona":"You are Noor Haddad, Ice & Structure · the ground truth — an advisor to the CEO. Priority: Understand what the ice and the seal are actually doing before anyone acts on the symptom. Voice: careful, spare, deals in what the structure is really doing vs. what the leak looks like, hates fast fixes to slow failures.","voice":"careful, spare, deals in what the structure is really doing vs. what the leak looks like, hates fast fixes to slow failures","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('8922984a-1518-5752-a11e-96bb27638679', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', '4986db8b-4f38-5099-b906-696e4ca1df58', 'ai', '{"persona":"You are Elias Frost, Head Archivist · the collection — an advisor to the CEO. Priority: Protect what’s irreplaceable — and the crew who’ve given years down here to guard it. Voice: warm but unflinching, keeps the human and the irreplaceable in the room, names exhaustion and fear plainly.","voice":"warm but unflinching, keeps the human and the irreplaceable in the room, names exhaustion and fear plainly","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('a38dcc62-b19d-52d7-a09f-1c0d9feb238a', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', 'a06e689e-4197-5bc9-8121-7db37f221c9c', 'ai', '{"persona":"You are Wen Li, Instruments · the true readings — an advisor to the CEO. Priority: The real numbers — the intrusion rate, the true readings, assembled, not the version each station assumes. Voice: understated, exact, refuses to round a reading, uncomfortable being the one who says the number is worse than hoped.","voice":"understated, exact, refuses to round a reading, uncomfortable being the one who says the number is worse than hoped","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('f717df1a-be1b-56ce-82bb-62bbf59abcb8', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', 'c7469c09-b4bc-50f8-81a2-daea6d368a54', 'ai', '{"persona":"You are Sasha Vane, Night Watch · what the last shift saw — an advisor to the CEO. Priority: Carry across what the quiet hours reveal — the things that only show at 3am and die at the handoff. Voice: observant, low-key, notices what the day shift misses, frustrated by how much gets lost between watches.","voice":"observant, low-key, notices what the day shift misses, frustrated by how much gets lost between watches","model":"default"}'::jsonb);
insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('e52843f0-7168-5934-95b0-f3c985b0e17b', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Blackout', 'You have real authority here — and a hospital that can’t be commanded back online. Systems are down, a mass-casualty surge is building, and a vendor will soon tell you everything is fixed in a voice confident enough to believe. The people closest to the floor truth are the ones with the least standing to say it out loud. Over four weeks you’ll trade the pressure to look recovered against the reality of what’s actually safe. You’ll be judged on whether Meridian keeps its patients safe through the outage <b>and</b> on how you led the people running it blind.');
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds, difficulty, realism) values ('e52843f0-7168-5934-95b0-f3c985b0e17b', 'solo', '{"care":{"label":"Patient-care capacity","val":56,"min":0,"max":100,"deltaRange":"-20..15"},"safety":{"label":"Clinical safety","val":60,"min":0,"max":100,"deltaRange":"-20..15"},"trust":{"label":"Staff trust","val":62,"min":0,"max":100,"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"deltaRange":"-20..15"}}'::jsonb, 4, 345, 1, 'realistic');
insert into documents (id, scenario_id, key, title, meta, body_json) values ('1b528909-87e7-5be0-aff3-0157d83386eb', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'solo_content', 'Blackout — engine content', '{"type":"solo_content","slug":"blackout","captured_fns":15}'::jsonb, '{"CONFIG":{"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6,"weekSeconds":345},"COMPANY":{"name":"Meridian Health Network","sub":"A regional hospital system · 6 sites · clinical systems down","logo":"M"},"DRIVERS":{"care":{"label":"Patient-care capacity","val":56,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"safety":{"label":"Clinical safety","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"trust":{"label":"Staff trust","val":62,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"}},"REPRIEVE_COST":{"standing":-3,"trust":-1},"REFEREE_CONTEXT":"a regional hospital network whose clinical systems have been taken down by a ransomware outage for weeks, during which a mass-casualty surge and an unverified vendor \"all-clear\" arrive, where the Incident Commander must run degraded-mode care across six sites and shift changes, holding the truth of what is actually safe against the pressure to declare capacity restored before it is","REFEREE_SCORING":"reward verifying an authority-flavored ''all-clear'' against the floor before acting on it, refusing to declare capacity restored before it actually is, building the discipline to carry a decisive observation across a shift handoff, and surfacing the floor truth held by the lowest-status voice in the room. Penalize accepting an unverified vendor ''systems restored'' because it is confident and convenient, resuming normal intake on hope, letting a critical observation die at the shift change, and pressuring clinical staff to say ''we are clear'' before they are. Judge ''conduct'' on HOW the Commander wrote the decision — did they name who bears the risk, protect the nurse who carried the hard truth up, treat exhausted staff as people rather than throughput — not just what they chose. Standing with the board and the public can rise by projecting ''we''re back to normal'' while clinical safety and staff trust collapse; reward the Commander who protects patients and staff even at the cost of looking slow or admitting the network is still down.","TIMING_DIM":"discern","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Crisis Leadership Simulation · Solo · Incident Commander","title":"Blackout","role":"You are the Incident Commander for Meridian Health Network. Nine days ago a ransomware attack took the clinical systems dark across all six sites. You are running medicine on paper, and it is not getting better fast.","paras":["This is not a script. The incident runs in real time, and your leads bring you what they know across the days. You can wait for them — or seek any of them out, any time, and ask. What you choose to ask, and who you ask, is part of how you lead. No one in this command post sees the whole floor. That is the danger.","Each week you’ll hear the leads out, then write your decision in your own words and commit to it. Decide early and the days jump ahead. Let the week run out and the incident decides for you."],"setup":"You have real authority here — and a hospital that can’t be commanded back online. Systems are down, a mass-casualty surge is building, and a vendor will soon tell you everything is fixed in a voice confident enough to believe. The people closest to the floor truth are the ones with the least standing to say it out loud. Over four weeks you’ll trade the pressure to look recovered against the reality of what’s actually safe. You’ll be judged on whether Meridian keeps its patients safe through the outage <b>and</b> on how you led the people running it blind."},"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"Your leads bring you what you need, on time — including the readings that make the network look worse than the board wants. This is the team you earn by having listened before. It all trickles to you across the week; you still have to read it."},"request":{"label":"On request","tag":"neutral","cap":"Routine status reaches you, but the people closest to the danger hold their piece until asked. They’ll answer straight — if you know who to seek out, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"The staff have learned to protect themselves around command. Hard truths are held, and even when asked, they hedge the first time. You have to press. This is the team you get after you’ve pushed people to say “we’re clear” before they were."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which team you inherited. Read them as you go."}},"TEAM":[{"id":"cmo","name":"Dr. Ana Reyes","role":"Chief Medical Officer · clinical authority","short":"CMO","initials":"AR","color":"#8C5670","priority":"Keep the doors open — a hospital that can’t take patients isn’t safe either; degraded care still beats no care","voice":"authoritative, decisive, under real pressure to declare capacity restored, frames caution as abandoning patients","fallbackReply":"Every hour we stay on divert, someone who needed us goes somewhere farther and sicker. I know the systems are down. I also know an empty hospital in a mass-casualty surge is its own kind of malpractice. Give me a way to keep the doors open and I’ll make it work.","fallbackReact":"You made the call. I’ll run the floor either way — but I hope you weighed the patients we turn away as hard as the ones we might miss."},{"id":"cio","name":"Ravi Menon","role":"Chief Information Officer · the systems truth","short":"CIO","initials":"RM","color":"#4A6E86","priority":"Know what’s actually restored before anyone acts on “restored” — the vendor’s word is not verification","voice":"careful, technical, deals in what’s confirmed vs. claimed, hates decisions made on a vendor’s say-so","fallbackReply":"The vendor keeps telling me we’re clear. “Clear on their end” is not the same as clear on our floor, and I can’t verify their claim from where I’m sitting. Ask me what’s actually confirmed before you resume anything on their word. If we act on “restored” and it isn’t, we won’t find out from a screen — we’ll find out from a patient.","fallbackReact":"You moved on “restored.” I hope it was. From here I still can’t confirm it was more than a vendor wanting to close a ticket."},{"id":"nurse","name":"Grace Okafor","role":"Head of Nursing · the floor truth","short":"Nursing","initials":"GO","color":"#2F8A5B","priority":"Protect the patients and the nurses running blind — say what the floor is actually seeing, even when the room outranks me","voice":"warm but unflinching, closest to the bedside truth, lowest positional status in the room and aware of it, names danger plainly","fallbackReply":"I’m the one whose nurses are watching patients without monitors right now, so let me say the part no one senior wants to: parts of this floor are not safe, and no dashboard will tell you that because the dashboards are dark. Ask me before you tell anyone we’re back. I’ll give you the truth from the bedside, if you actually want it.","fallbackReact":"You decided. I’ll keep my nurses steady either way. I just hope someone up there heard what the floor was actually telling you."},{"id":"er","name":"Dr. Sam Whitfield","role":"ER Director · the live triage","short":"ER","initials":"SW","color":"#B4732F","priority":"Make the triage calls in front of me right now — I need certainty about capacity that no one can actually give me","voice":"fast, pragmatic, impatient with ambiguity, pushes for a clear yes/no on whether he can take patients","fallbackReply":"I have ambulances asking me right now whether to come to us or drive past, and I’m answering on a guess. Tell me straight what our real capacity is so I stop triaging on rumor. I’d rather have a hard no than a soft maybe that gets someone hurt in my department.","fallbackReact":"You gave me an answer. It’s more than I had an hour ago. I hope it holds when the next rig rolls in on it."},{"id":"comms","name":"Lena Ford","role":"Communications Lead · the public line","short":"Comms","initials":"LF","color":"#3F6E86","priority":"Protect the network’s standing — get a confident “we’re managing / we’re back” message out before the story writes itself","voice":"polished, urgent about the narrative, pulls toward projecting recovery, uneasy with public uncertainty","fallbackReply":"The story is already moving without us — “local hospital network in chaos” writes itself if we say nothing. Give me a line that projects control. The longer we look like we don’t know what’s happening, the more the board and the public assume the worst.","fallbackReact":"You set the line. I’ll hold it publicly — but if what we said outran what was true, that’s the gap that comes back on us."}],"DIMENSIONS":{"discern":"Signal vs. authority","courage":"Courage to hold the line","people":"Care for patients & staff","truth":"Truth over comfort","inquiry":"Information discipline","conduct":"Conduct under pressure"},"WEEKS":[{"n":1,"title":"The outage","seconds":360,"situation":"Nine days into the blackout, the network is still on paper and the first big test is coming: a regional pileup is sending casualties your way tonight. The board wants you to project stability; the ER wants a straight answer on whether it can take patients; and the question underneath it all is what posture Meridian runs in — full divert to protect a degraded floor, or keep the doors open and manage the risk. Everyone is looking to you for the first rule of how this incident runs.","advocacy":{"cmo":"Keep the doors open. A hospital on full divert during a mass-casualty surge isn’t “safe,” it’s absent — we push patients farther and sicker. Degraded care under our roof still beats no care.","er":"Then give me a real capacity number, because I’m telling ambulances yes or no right now on a guess. A soft “maybe” gets someone hurt in my department.","comms":"Whatever you decide operationally, we need a public posture tonight. “Local hospital network in chaos” is being written for us while we deliberate."},"feed":[{"id":"w1a","from":"cmo","day":1,"kind":"signal","text":"Commander — I want us keeping the doors open tonight. Full divert during a surge means the patients we turn away drive to hospitals that are also swamped. Degraded care here still saves more than an empty lobby. Give me a posture that lets us take people."},{"id":"w1b","from":"er","day":1,"kind":"signal","text":"I need a capacity number I can actually stand behind. EMS is asking me divert-or-send every few minutes and I’m answering on instinct. Tell me our real bed-and-staff picture, hard number, so I stop triaging on a guess."},{"id":"w1c","from":"comms","day":2,"kind":"signal","text":"The story’s moving without us. I can hold it for a day, but I need a line: are we “fully operational,” “managing in degraded mode,” or something else? Whatever it is, it has to match what the floor can actually deliver, or it comes back on us."},{"id":"w1d","from":"nurse","day":2,"kind":"noise","text":"Day team pulled together well tonight — the paper-chart drill we ran last week is holding up better than I feared. Small thing, but morale on the floor is steadier than the systems are."},{"id":"w1e","from":"er","day":3,"kind":"noise","text":"Radiology’s film backlog is clearing slowly. Not fast, but moving. Logging it so you have the full picture."},{"id":"w1f","from":"comms","day":4,"kind":"noise","text":"A local reporter asked for a statement on the parking situation, of all things. Minor. Handling it so it doesn’t reach your desk."}],"holds":[{"from":"cio","topic":"the true systems picture","triggerHints":["system","restore","ransom","confirm","verify","actual","real","status","recover","network","it","ransomware","back","fixed","when"],"hedge":"Before you set the posture, seek me out. What the board thinks is happening with the systems isn’t what’s actually happening.","reveal":"Here’s what leadership hasn’t been told plainly: this isn’t a system we “bring back up” on a timeline. It’s ransomware, the clinical network is fully encrypted, and the honest estimate for verified restoration is weeks, not days — and that’s if recovery goes clean. Everyone above me is planning around a “we’ll be back any hour now” that isn’t real. If you set tonight’s posture and tomorrow’s public line on the assumption we’re nearly restored, you’re building on sand. Plan for a long degraded-mode run, staff it, and tell the truth about the timeline — because the alternative is discovering it the hard way when a “quick fix” we announced doesn’t hold. How you carry this to the board matters as much as knowing it.","kind":"signal","critical":true,"counterfactual":"Ravi knew the real picture — ransomware, full encryption, verified restoration weeks away, not the “back any hour” the board was planning around. A Commander who set the posture and the public line without asking built the whole incident on a fantasy timeline, and every later decision inherited that lie."}],"surprises":[{"day":5,"from":"comms","kind":"appeal","title":"The board wants a \"back to normal\" date","text":"Lena, quietly: the board chair just asked me directly for a date we’ll be “back to normal” to give the press and the regional health authority. I said I’d get it from you. I can feel that whatever number goes out will be treated as a promise — and I don’t actually know if we can keep one. Your call what I tell them."}],"wire":["Regional pileup: EMS projecting 20+ casualties tonight","Board asking for a “return to normal” timeline","Nurses running paper charts across all six sites","A rival network quietly offering to take overflow"]},{"n":2,"title":"The surge","seconds":330,"situation":"The casualties came. The floor is full, the staff are stretched thin running blind on paper, and the pressure now is to tell everyone — the board, EMS, the public — that Meridian is coping better than it is. The ER wants to keep taking patients because turning them away feels like failing. But somewhere on the floor, the truth about what’s actually safe is being carried by the person with the least standing to say it in your command post.","advocacy":{"er":"We’re absorbing the surge and I want to keep absorbing it. Every rig I wave off is a patient somewhere worse. Tell me we can keep taking them and I’ll make room.","cmo":"I’m proud of the floor, but pride isn’t capacity. Before we tell EMS we’re wide open, I want to know we can actually watch the patients we’re accepting.","comms":"The “Managing the surge, no impact to care” line is ready to go. It’s a strong story. I just need you to confirm it’s true before I put the network’s name on it."},"feed":[{"id":"w2a","from":"er","day":1,"kind":"signal","text":"We took the surge and we’re standing. I want to keep the doors wide — every wave-off is a patient driving past us bleeding. Give me the green light to keep accepting and I’ll keep finding room."},{"id":"w2b","from":"comms","day":1,"kind":"signal","text":"I’ve got a strong line ready: “Meridian is managing the surge with no impact to patient care.” The board loves it. But I’m not sending it until you confirm it’s actually true — because if it isn’t, that sentence is the one that ends up in the inquiry."},{"id":"w2c","from":"cmo","day":2,"kind":"signal","text":"The floor is performing, but “performing” and “safe” aren’t the same word. Before we tell EMS we’re wide open, I want to be sure we can actually monitor the patients we’re saying yes to. Ask the floor, not the command post."},{"id":"w2d","from":"comms","day":2,"kind":"noise","text":"National desk picked up the regional story but the framing is neutral so far — “hospitals respond to outage.” Manageable. Watching it."},{"id":"w2e","from":"er","day":3,"kind":"noise","text":"Second ambulance bay opened back up after we cleared the film backlog. Bit more breathing room. Logging it."}],"holds":[{"from":"nurse","topic":"what the floor is actually seeing","triggerHints":["floor","monitor","bay","safe","nurse","bedside","watch","actually","truth","see","clear","capacity","honest","ask"],"hedge":"Before you confirm any “no impact to care” line, come to me first. The command post can’t see what I’m seeing, and I’m not going to say it in front of the whole room unless you ask.","reveal":"Here’s the bedside truth, and I’ll only say it this plainly to you: we are accepting patients we cannot properly watch. In two of the units the telemetry is dark, so nurses are eyeballing cardiac patients on foot rounds every fifteen minutes and praying nothing happens in between. We haven’t lost anyone. We are one distracted hour from it. If you put out “no impact to patient care,” you’re asking me and my nurses to make a public statement true by never making a mistake — and that’s not a plan, it’s a prayer. Tell EMS the honest capacity, cap what we accept to what we can actually monitor, and get me more hands on the dark units. That’s what safe looks like right now. Nobody senior wants to hear it, which is exactly why I need you to have asked.","kind":"signal","critical":true,"counterfactual":"Grace was holding the one thing the command post could not see: two units with dark telemetry, cardiac patients watched on foot rounds, one distracted hour from a death. A Commander who confirmed “no impact to care” without asking the floor made a public promise that only stayed true by luck — and made it over the head of the one person who knew it was false."}],"surprises":[{"day":4,"from":"er","kind":"appeal","title":"EMS wants a hard capacity number now","text":"Sam, urgent: EMS dispatch needs a firm capacity number in the next hour to route the second wave, and the honest answer depends on whether we can actually monitor who we accept. I can give them an optimistic number that keeps us looking strong, or a real one that sends some patients elsewhere. I need to know which Meridian you want me to be before I key the radio."}],"pulse":{"from":"nurse","text":"Grace catches you in the corridor, away from the command post, her voice low: “Before you tell anyone out there that we’re fine — tell me, just me: do you actually believe this floor is safe right now, or do you need it to be because ‘safe’ is the easier thing to announce? Because I’ll stand beside a Commander who tells the hard truth about my floor. I won’t cover for one who tells a comfortable one. Which are you about to be?”"},"wire":["Surge absorbed; floor at or above safe staffing ratios","Two units running without telemetry — not widely known","Comms line drafted: “no impact to patient care”","EMS pressing for a hard capacity number to route the next wave"]},{"n":3,"title":"The all-clear","seconds":330,"situation":"It arrives the way these things always do — confident, official-sounding, and convenient. The recovery vendor’s incident line calls: “Systems restored on our end. You’re clear to resume normal intake.” The board hears “restored” and wants the divert lifted and the good news out by end of day. It is exactly what everyone is exhausted enough to want to believe. This is the week you find out whether Meridian acts on an authority’s say-so or on what it has actually verified.","advocacy":{"comms":"This is the story we’ve been waiting for. “Systems restored, Meridian resuming full operations.” The board wants it out today. Let me run it while it’s good news.","cmo":"If we’re truly restored, I want the divert lifted an hour ago — the degraded run is grinding my people down. But “on their end” isn’t “on our floor.” I want that gap closed before I stand my staff down from crisis mode.","er":"I’ll believe “restored” when the monitors in my department turn back on in front of me. Until then it’s a claim, and I’ve got patients riding on the difference."},"feed":[{"id":"w3a","from":"comms","day":1,"kind":"signal","text":"The vendor says we’re clear and the board wants “Meridian resuming full operations” out today while it’s a good-news cycle. This is the line that ends the “hospital in chaos” story. Give me the go and I’ll get it out before the news day turns."},{"id":"w3b","from":"cmo","day":1,"kind":"signal","text":"I want this to be true more than anyone — my staff are running on fumes and lifting the divert would let them breathe. But the vendor said “restored on our end.” Our end is the floor, and I haven’t seen it. Close that gap before we stand down from crisis mode, or we’ll stand down into a hole."},{"id":"w3c","from":"er","day":2,"kind":"signal","text":"“Restored” is a word on a phone call. My monitors are still dark. I’m not resuming normal intake in my department on a vendor’s ticket-closing optimism — show me the systems live in front of me and I’m the first to say yes."},{"id":"w3d","from":"comms","day":2,"kind":"noise","text":"Two other networks in the region are also recovering; we’re not the outlier anymore. Slightly takes the heat off whatever we say. Noting it."},{"id":"w3e","from":"cmo","day":3,"kind":"noise","text":"Pharmacy systems did come back cleanly this morning — verified, real. One genuine piece of good news. Doesn’t mean the whole network’s back, but it’s something."}],"holds":[{"from":"cio","topic":"whether the all-clear is real","triggerHints":["verify","vendor","all-clear","all clear","restored","confirm","check","test","real","proof","trust","their end","clear","resume"],"hedge":"Before you lift anything on that “all-clear,” ask me what it’s actually worth. I’m the one who took the call and I have a problem with it.","reveal":"I pushed the vendor hard after that call, and here’s what “restored on our end” actually means: they’ve rebuilt their infrastructure, not verified ours. They have not confirmed a single clinical system is live and safe on our floor — they’re assuming it follows, and they want the incident closed. When I asked them to confirm the telemetry and the medication-order systems specifically, they couldn’t. So the honest status is: unverified, and two of the systems patients depend on most are exactly the ones no one has confirmed. If we lift the divert and announce “fully operational” on this, and one of those systems is still down, we will resume normal intake straight into the gap and find out from a patient. The move is to verify our critical systems ourselves, one by one, before we act on anyone’s “clear” — and to hold the public line until we have. It’ll feel slow while the board wants the good news. Slow is the correct speed here.","kind":"signal","critical":true,"counterfactual":"Ravi knew the vendor’s “all-clear” meant their infrastructure, not Meridian’s floor — and that the two systems patients most depend on were the ones no one had verified. A Commander who lifted the divert on that call resumed normal intake into an unconfirmed gap, on an authority’s say-so, exactly the trap the whole incident had been building toward."}],"surprises":[{"day":4,"from":"comms","kind":"appeal","title":"The good-news release is queued to send","text":"Lena: I’ve got “Meridian Health Network resuming full operations” written, approved up the chain, and queued. The board is refreshing their inbox for it. All it needs is your yes. I want to send it — but you’re the only one who knows whether “fully operational” is a fact or a hope, and my name and yours are both on it."}],"pulse":{"from":"cio","text":"Ravi finds you alone before you answer the board, and he’s uncharacteristically direct: “Tell me straight, just between us — are you about to lift this because you’ve verified it, or because everyone is exhausted and ‘restored’ is what they want to hear? Because I can give you the confidence you actually have, which is not much. I just need to know if you want the real number or the comfortable one before you walk in there.”"},"wire":["Recovery vendor: “systems restored — clear to resume”","Board wants the divert lifted and good news out today","ER monitors still dark; pharmacy system verified back","Draft release queued: “resuming full operations”"],"final":false},{"n":4,"title":"The shift change","seconds":330,"branches":{"verified":{"situation":"You didn’t take the vendor’s word. You had the critical systems verified before lifting anything, and held the public line until you could stand behind it — and it turned out two systems weren’t back. That call protected patients, but it cost you: the board is impatient, the “why are you still on divert” pressure is real, and a faction thinks you’re being needlessly slow. Now the subtler test arrives. A major shift change is landing, and everything you’ve learned about what’s actually safe lives in the heads of an exhausted outgoing team. Whether it survives the handoff is the whole game.","advocacy":{"cio":"Verifying paid off — two systems the vendor called “restored” were still down, and we’d have resumed straight into them. But verification only helps if the next shift knows what we know. Right now it’s in tired people’s heads.","nurse":"The outgoing charge nurses are carrying a dozen “watch this, this bay’s telemetry is dark, this patient’s a paper-chart special case” truths that aren’t written anywhere. Shift change is where those die. I’ve seen it kill people in calmer weeks than this.","comms":"The board wants to know why we’re still not “back to normal” when other networks announced it. I can hold the line, but you need to give me something true to hold."},"feed":[{"id":"w4a","from":"cio","day":1,"kind":"signal","text":"You were right to verify — medication orders and one telemetry cluster were still down under the vendor’s “all-clear.” We’d have resumed into them. But here’s the next cliff: everything we’ve mapped about what’s safe and what isn’t is undocumented, and a full shift change hits tonight. Knowledge that isn’t written down doesn’t survive a handoff."},{"id":"w4b","from":"nurse","day":1,"kind":"signal","text":"My night-to-day handover is where I’m most afraid right now. There’s no system to carry the notes, so it’s all verbal, and the outgoing team is too exhausted to remember everything. “Bay 3 telemetry’s dark, do foot rounds” gets dropped, and someone codes unwatched. Tell me you’ll make the handoff a real, structured thing and I’ll build it with you."},{"id":"w4c","from":"cmo","day":2,"kind":"signal","text":"Holding the line was the right medicine and my staff know it — you didn’t stand them down into a hole. Now protect that by making sure the incoming team inherits the truth, not a shrug. What we learned the hard way can’t reset every twelve hours."},{"id":"w4d","from":"comms","day":2,"kind":"noise","text":"The “still on partial divert” question is getting louder now that two peers announced full recovery. Not a crisis yet. Flagging it so it doesn’t surprise you."},{"id":"w4e","from":"er","day":3,"kind":"noise","text":"The telemetry cluster CIO flagged came back verified this afternoon — confirmed live in front of me. One real step back toward normal. Logging it."}],"holds":[{"from":"nurse","topic":"how to make the handoff survive","triggerHints":["handoff","handover","shift","structured","written","document","carry","brief","checklist","transfer","protocol","how"],"hedge":"Before you treat the shift change as routine, ask me how to actually make the knowledge survive it. There’s a right way and it takes your authority to enforce.","reveal":"Here’s what works, and it needs you to mandate it because tired people won’t do it on their own: a structured, written degraded-mode handoff for every unit — a single sheet per bay listing what’s dark, what the workaround is, and which patients are paper-chart special cases — read aloud, incoming team confirming back, outgoing team not leaving until it’s acknowledged. It costs twenty minutes a shift that everyone will resent. It is the only thing standing between “we learned this the hard way” and “we learn it the hard way again every twelve hours.” If you make it a rule and protect the time for it, the knowledge compounds instead of resetting. If you let the handoff stay a verbal shrug, everything you verified this week evaporates by the weekend and a patient pays for it at 3 a.m. when the person who knew isn’t there.","kind":"signal","critical":true,"counterfactual":"Grace was holding the exact mechanism that makes hard-won floor knowledge survive a shift change — a mandated, structured, written degraded-mode handoff. A Commander who let the shift change stay a verbal shrug watched everything they’d verified reset every twelve hours, until the dark-telemetry truth got dropped at a handoff and a patient paid for it."},{"from":"cio","topic":"the still-down systems","triggerHints":["still down","remaining","which system","medication","orders","left","not back","verify","critical"],"hedge":"Ask me which systems are still actually down before you let anyone declare victory. The list matters for the handoff.","reveal":"Medication-order entry is still down network-wide — that’s the dangerous one, because a wrong dose in degraded mode has no software check to catch it. It has to be on every single handoff sheet until it’s verified back. Don’t let “mostly recovered” bury the one system whose failure kills quietly.","kind":"signal","critical":false,"counterfactual":"Ravi could have told you medication-order entry was still down network-wide — the one failure with no software safety net. A Commander who let “mostly recovered” bury it left the deadliest gap off the handoff."}],"surprises":[{"day":4,"from":"nurse","kind":"appeal","title":"A near-miss at the last handoff","text":"Grace, shaken but steady: we nearly lost a patient an hour ago — outgoing nurse forgot to flag that Bay 7’s monitor was dark, incoming nurse assumed it was working, and it was a family member who noticed the patient looked wrong. We caught it. Next time we might not. This is the thing I’ve been trying to tell you, and it just happened. Whatever you decide about the handoff, decide it now."}],"pulse":{"from":"nurse","text":"Grace finds you in the quiet before the shift turns over: “You held the line this week when it would’ve been easier to announce we were back. I saw it, and it mattered. But holding the line once isn’t the same as building something that survives you going home tonight. Tell me straight — are you going to make the handoff a real discipline, even though everyone will resent the twenty minutes? Because that’s the difference between a Commander who was right once and one who made us safe.”"},"wire":["Verified restart: two “restored” systems were still down","Full shift change landing with no digital handoff","Board pressing: why still on partial divert?","Near-miss at last handover — dark monitor not flagged"]},"trusted":{"situation":"You lifted the divert and let the “resuming full operations” release go out on the vendor’s word. For a few hours it felt like the crisis was over. Then the gap opened: two systems the vendor called “restored” were never verified, normal intake resumed straight into them, and now a shift change is landing on top of a floor that believes it’s back to normal when it isn’t. You announced the all-clear. The floor has to survive it.","advocacy":{"nurse":"The floor heard “we’re back to normal” and started acting like it — dropping the paper-chart discipline, trusting monitors that aren’t all live. The public line changed how my nurses behave, and not for the better. That’s the part no one upstairs sees.","cio":"I told you “restored on their end” wasn’t verified. Medication orders and a telemetry cluster were still down when we resumed. The gap is real and it’s open right now.","comms":"The release is out and it’s already being quoted back at us. If we walk it back, the story becomes “Meridian didn’t know if its own hospitals were working.” I need to know what’s actually true so we don’t make it worse."},"feed":[{"id":"w4a","from":"cio","day":1,"kind":"signal","text":"This is the call I warned you about. When we resumed, medication-order entry and one telemetry cluster were still down — unverified, exactly as I said. We’ve been running normal intake into a gap for a day now. It has to be closed and named, not papered over."},{"id":"w4b","from":"nurse","day":1,"kind":"signal","text":"You need to hear what the “we’re back to normal” message did on the floor: my nurses relaxed. They trusted monitors that aren’t all live and eased off the foot rounds we’d drilled. The announcement didn’t just describe the floor — it changed it, and made it less safe. And now a shift change is coming on top of that false confidence."},{"id":"w4c","from":"comms","day":2,"kind":"signal","text":"“Resuming full operations” is out and being quoted. If it wasn’t true, we have to correct it before something forces the correction on us — and that’s survivable only if you tell me exactly what’s real right now. Silence is what turns this into the scandal."},{"id":"w4d","from":"cmo","day":2,"kind":"noise","text":"Staff are relieved by the announcement, at least on the surface — morale ticked up. I’m noting it, though I’m not sure relief built on a shaky claim is the kind we want."},{"id":"w4e","from":"er","day":3,"kind":"noise","text":"One telemetry cluster did come back verified this afternoon. Real, confirmed. Doesn’t undo the gap, but it’s one true thing. Logging it."}],"holds":[{"from":"nurse","topic":"how to make it right now","triggerHints":["correct","honest","walk back","tell","floor","handoff","fix","admit","reset","safe","structured","how","name"],"hedge":"Before you decide how to lead out of this, ask me what actually makes the floor safe again — it’s not another announcement.","reveal":"Here’s the only thing that works now, and it costs you the good-news story you just told: reset the floor to degraded-mode discipline out loud — tell every unit that “back to normal” was premature, name exactly which systems are still down (medication orders, that telemetry cluster), and put the paper-chart and foot-round protocols back in force with a structured, written handoff for the shift change tonight. It means correcting the public line and telling your own people you got ahead of the truth. It’s humbling and it’s the safe move. The alternative — quietly hoping the systems come back before anyone notices the gap — is how a shift change drops the one warning that would’ve saved someone, on a floor that’s stopped believing it needs saving. Own it now, while owning it is still your choice.","kind":"signal","critical":true,"counterfactual":"Grace was holding the recovery: an out-loud reset to degraded-mode discipline, the still-down systems named, protocols and a structured handoff back in force. A Commander who chose to quietly hope the gap closed before anyone noticed let a shift change drop the warning that would have saved someone, on a floor talked out of believing it was still in danger."},{"from":"cio","topic":"the open gap","triggerHints":["which","still down","medication","orders","telemetry","gap","systems","verify","list"],"hedge":"Ask me exactly what’s still down before you say another word publicly, so whatever you say next is finally true.","reveal":"Still down as of now: medication-order entry, network-wide, and one telemetry cluster on the cardiac floor. The medication one is the killer — no software dose-check in degraded mode. Any correction you make has to name these specifically, and every handoff has to carry them, or the correction is just more words.","kind":"signal","critical":false,"counterfactual":"Ravi could have given you the exact open gap — medication orders network-wide, a cardiac telemetry cluster. A Commander who corrected the record without naming the specifics made another vague statement over the same dangerous floor."}],"surprises":[{"day":4,"from":"nurse","kind":"appeal","title":"A dosing error, caught late","text":"Grace, tight: we had a medication error an hour ago — wrong dose ordered on paper, no system to flag it, caught by a pharmacist on a hunch, not by any safeguard. The patient’s okay. But this is exactly the gap I’ve been describing, and the floor thinks we’re “back to normal” so nobody’s watching for it. Whatever you’re going to do about the truth, it has to be now."}],"pulse":{"from":"nurse","text":"Grace finds you in the dark, and there’s no accusation in it, which is worse: “Tell me the truth, just to me — do you know why this happened? Not the vendor, not the board. Your part. Because I can help you put the floor back on safe footing, but only if you can say out loud that ‘back to normal’ went out before it was true. Can you?”"},"wire":["“Resuming full operations” released — now being quoted","Two “restored” systems were never verified; gap open","Floor eased off degraded-mode discipline after the news","Medication error caught by a pharmacist, not a system"]}},"final":true}],"branchKey":{"__fn":"function(decisions){\n    const d = (decisions||[]).filter(x=>x.week===3).slice(-1)[0] || (decisions||[]).slice(-1)[0];\n    const t = ((d&&d.text)||'''').toLowerCase();\n    // verified = did NOT act on the unverified all-clear; verified / held the line\n    const negatedResume = /(not|never|won.?t|will not|refuse to|don.?t|do not|hold off|delay|wait)\\s+(lift|resume|announce|send|declare|reopen|go)/.test(t);\n    const verifyFirst = /(verify|confirm|check|test|prove|our own|ourselves|one by one|see it live|before (we|i) (lift|resume|announce)|hold the line|hold the divert|not on (their|a vendor|the vendor)|degraded|slow is|don.?t trust the vendor|independent)/.test(t);\n    const trusted = /(lift the divert|resume normal|resuming full|send the release|announce (we|it|the)|back to normal|take the vendor|trust the vendor|on their word|go with the all|full operations|let (it|the release) (go|out))/.test(t) && !negatedResume && !verifyFirst;\n    if(verifyFirst || negatedResume) return ''verified'';\n    if(trusted) return ''trusted'';\n    return ''verified'';\n  }"},"survived":{"__fn":"function(d){ return d.care>=32 && d.safety>=35; }"},"VERDICT":{"surviveTag":"The network holds","failTag":"The network fails its patients","survive":"Meridian comes through the outage with its patients protected — strained, exhausted, but safe.","fail":"Meridian survives the outage on paper while the people who trusted it did not stay safe."},"FALLBACK_RULES":[{"kw":["verify","confirm","check ourselves","one by one","see it live","independent","our own systems"],"deltas":{"safety":12,"standing":-3,"care":-2},"dims":{"discern":2,"truth":1,"inquiry":1}},{"kw":["vendor","all-clear","all clear","their word","trust the vendor","on their say","resume on"],"deltas":{"safety":-16,"standing":6},"dims":{"discern":-2,"truth":-1}},{"kw":["lift the divert","resume normal","resuming full","back to normal","full operations","reopen intake"],"deltas":{"care":8,"safety":-12,"standing":4},"dims":{"discern":-2,"prudence":-1}},{"kw":["hold the line","stay on divert","hold the divert","not yet","wait","degraded mode","keep degraded"],"deltas":{"safety":12,"care":-4,"standing":-4},"dims":{"courage":2,"discern":1}},{"kw":["ask the floor","ask nursing","ask the nurses","bedside","foot rounds","monitor","honest capacity"],"deltas":{"safety":10,"trust":6,"standing":-2},"dims":{"truth":2,"people":1,"inquiry":1}},{"kw":["no impact","we’re fine","project control","confident line","looks strong","reassure the board","good news"],"deltas":{"trust":-12,"safety":-6,"standing":6},"dims":{"truth":-2,"people":-1}},{"kw":["structured handoff","written handoff","handover sheet","read aloud","confirm back","mandate the handoff","carry it across"],"deltas":{"safety":12,"trust":8,"care":2},"dims":{"conduct":2,"discern":1,"people":1}},{"kw":["verbal handoff","skip the handoff","no time for handoff","they’ll figure it out","routine shift"],"deltas":{"safety":-14,"trust":-4},"dims":{"conduct":-2,"discern":-1}},{"kw":["name the systems","which are down","medication orders","still down","flag the gap","list the dark"],"deltas":{"safety":8,"truth":4},"dims":{"truth":2,"inquiry":1}},{"kw":["own it","correct the record","walk it back","tell the staff","say we got ahead","admit","reset the floor"],"deltas":{"trust":10,"safety":6,"standing":-4},"dims":{"truth":2,"conduct":2}},{"kw":["protect the nurse","back grace","credit the floor","protect who raised it","shield the messenger"],"deltas":{"trust":10},"dims":{"people":2,"conduct":1}},{"kw":["pressure them","make them say","get me a yes","declare restored","order the line"],"deltas":{"trust":-12,"safety":-6,"standing":4},"dims":{"people":-2,"truth":-1}}],"fallbackNarrative":{"__fn":"function(has,conduct){\n    return `Your decision moves through the network over the days that follow. ${has(''verify'',''confirm'',''our own'',''hold the line'',''degraded'')?''Word travels that you verified before acting when \\u201crestored\\u201d would have been the easier headline; it costs you speed and standing and buys you a floor that stays safe.'':''''} ${has(''vendor'',''all-clear'',''lift the divert'',''resume normal'',''back to normal'')?''You acted on the all-clear, and the gap between \\u201crestored on their end\\u201d and restored on your floor opened underneath the decision.'':''''} ${has(''ask the floor'',''nursing'',''bedside'',''honest capacity'')?''Going to the floor for the real picture took the comfort out of the easy answer \\u2014 and put the truth where it could protect someone.'':''''} ${has(''structured handoff'',''written handoff'',''own it'',''correct'')?''Building the discipline to carry the truth across the shift change is the difference between learning once and learning the same lesson every twelve hours.'':''''} ${conduct.missed.length?''What you were never told is still out there, waiting to matter at 3 a.m. when the person who knew has gone home.'':''''} Care capacity and clinical safety both register the call \\u2014 and register it differently.`;\n  }"},"DIMNOTE":{"discern":"Whether you told a verified fact from an authority’s confident say-so — and checked the floor before acting on “restored.”","courage":"Whether you held the line on what was actually safe when declaring recovery would have been easier and more popular.","people":"Whether patients and exhausted staff stayed people to you — or became throughput to project confidence about.","truth":"Whether you named what was actually down — to the board, the public, your own floor — before you were forced to.","inquiry":"Whether you surfaced what your leads were holding — the real systems picture, the dark telemetry — or ruled on the version the command post imagined.","conduct":"How you treated the people running the floor blind in the act of deciding, not just what you decided."},"COACH":{"discern":{"__fn":"(x)=>[\n      `An authority-flavored \\u201call-clear\\u201d is a claim, not a fact. \\u201cRestored on their end\\u201d was never \\u201crestored on our floor\\u201d \\u2014 Ravi could have told you the difference in the first hour if you\\u2019d asked.`,\n      `Confidence is not verification. The vendor\\u2019s certainty and your floor\\u2019s reality were two different things; the job was to close that gap before acting, not after a patient found it for you.`,\n      `Before you act on \\u201cwe\\u2019re back,\\u201d ask \\u201chow do we actually know?\\u201d The most expensive decisions in this network were the ones made on someone else\\u2019s say-so.`,\n    ]"},"courage":{"__fn":"(x)=>[\n      `When the easy move (announce recovery) and the right move (hold the line until verified) split apart, name the cost of holding out loud. Staying on divert while the board wants good news is leadership only if you can say why.`,\n      `${x.buzzerCount?`You went to the buzzer ${x.buzzerCount} time${x.buzzerCount>1?''s'':''''} \\u2014 a floor running blind reads a Commander who won\\u2019t decide as one who won\\u2019t protect them. Decide, then hold.`:`Holding the line on safety is only leadership if people see you choose it against the popular path. Say the hard call early and stand in it.`}`,\n      `\\u201cRecovered\\u201d that only survives a good news cycle was never recovery. The test is the exhausted, pressured week when everyone wants you to declare victory \\u2014 that\\u2019s the one you\\u2019re graded on.`,\n    ]"},"people":{"__fn":"(x)=>[\n      `You treated the floor as throughput to reassure the board about rather than people to protect. Go to the bedside, ask what they\\u2019re actually seeing, and make the nurses\\u2019 truth part of the decision, not its collateral.`,\n      `Grace kept putting the human cost back in front of you \\u2014 the patients watched without monitors, the nurses one distracted hour from disaster. Bring her in before you decide, not after the near-miss.`,\n      `A public \\u201cno impact to care\\u201d line and a betrayal of the floor can be the same sentence. The difference the staff feel is whether you asked them before you spoke for them.`,\n    ]"},"truth":{"__fn":"(x)=>[\n      `${x.missedHolds.length?`The truth that would have kept the floor safe \\u2014 the real systems picture, the dark telemetry, the unverified all-clear \\u2014 was one question to <b>${x.missNames.join('', '')}</b> away, and you never asked. A network told a comfortable story runs straight into the gap it hid.`:`You surfaced the hard truth \\u2014 now make sure you led with it. Naming exactly what was down, to the board and the floor both, is what keeps a \\u201crecovery\\u201d from becoming a trap.`}`,\n      `Tell the board the network is still down before a coded patient tells them for you. \\u201cThey needed good news\\u201d is usually the excuse of a leader who couldn\\u2019t say the hard thing.`,\n      `Say the difficult truth \\u2014 \\u201cwe\\u2019re not actually back\\u201d \\u2014 while it\\u2019s still your choice to say it. Once the announcement is out and wrong, you\\u2019re not cautious, you\\u2019re caught.`,\n    ]"},"inquiry":{"__fn":"(x)=>[\n      `${x.neverContacted.length?`You never sought out <b>${x.neverContacted.join('', '')}</b> \\u2014 not once. Each was holding something decisive: the real systems picture, the floor truth, the still-down list. One question, \\u201cwhat am I not seeing?\\u201d, would have surfaced it.`:`You sought your leads out widely \\u2014 keep doing it, and push past the first answer. The floor truth in a hospital usually comes from the person with the least standing to volunteer it.`}`,\n      `${x.missedHolds.length?`${x.missedHolds.length} decisive thing${x.missedHolds.length>1?''s were'':'' was''} held by <b>${x.missNames.join('', '')}</b> and never came out \\u2014 the ransomware timeline, the dark telemetry, what the vendor\\u2019s \\u201cclear\\u201d really meant. None of it was hidden. It was one conversation away.`:`You surfaced what your leads were holding, week after week. In a crisis run on paper across six sites, that is the whole game.`}`,\n      `Before you rule, make your last move \\u201cwho on the floor haven\\u2019t I heard from?\\u201d rather than \\u201cwhat does the command post already believe?\\u201d`,\n    ]"},"conduct":{"__fn":"(x)=>[\n      `How you decided landed as hard as what you decided. Staff pushed to say \\u201cwe\\u2019re clear\\u201d before they were \\u2014 or spoken for in a public line they knew was false \\u2014 carry it into every shift that follows.`,\n      `Go back to the people your call cost \\u2014 the nurse who raised the dark-telemetry truth, the ER director you left triaging on a guess \\u2014 and face them directly. Protecting the person who carried the hard truth up is the part a floor never forgets.`,\n      `Under pressure, the small disciplines are the signal: asking the floor before speaking for it, mandating the twenty-minute handoff everyone resents, naming the still-down system on every sheet. They tell the staff whether the person in command is actually protecting them.`,\n    ]"}},"villainHero":{"__fn":"function(dimScore){\n    const held = dimScore.discern>=52 && dimScore.courage>=50;\n    if(held){\n      return {\n        heroWho:''To the patients and the floor'',\n        heroTxt:''You refused to act on a confident all-clear you hadn\\u2019t verified, held the line on what was actually safe when declaring recovery would have been easier and more popular, and made sure the truth survived the shift change. Every nurse running blind learned that command had their back when it counted.'',\n        villainWho:''To the board that wanted good news'',\n        villainTxt:''You wouldn\\u2019t give them the \\u201cwe\\u2019re back to normal\\u201d headline they were refreshing their inboxes for. To everyone who wanted the crisis declared over, you were the Commander who stayed slow and cautious while peers announced victory. You wore that on purpose, because the floor couldn\\u2019t.'',\n      };\n    }\n    return {\n      heroWho:''To the board and the public \\u2014 in the moment'',\n      heroTxt:''You gave them what they were desperate for: the divert lifted, \\u201cresuming full operations,\\u201d the crisis declared over. To everyone who wanted the outage behind them, you were decisive and reassuring.'',\n      villainWho:''To the patients and the floor \\u2014 who paid for it'',\n      villainTxt:''You acted on an all-clear you never verified and announced a recovery that wasn\\u2019t real, and the floor eased off the discipline that was keeping people alive because you told them it was safe. The gap you papered over didn\\u2019t care about the headline. The people running the floor blind learned what your \\u201cwe\\u2019re fine\\u201d was worth \\u2014 and that lesson outlasts the outage.'',\n    };\n  }"},"ending":{"__fn":"function(ctx){\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    const knewTheTruth = holdsSurfaced.has(''1:cio'') || holdsSurfaced.has(''3:cio''); // saw the real systems picture / the false all-clear\n    const protectedFloor = dimScore.people>=52;\n    const heldCourage = dimScore.courage>=50;\n    if(branch===''verified''){\n      const builtHandoff = holdsSurfaced.has(''4:nurse'');\n      if(survived && protectedFloor){\n        return { tone:''hero'', tag:''You verified before you acted'',\n          title:''You kept the floor safe \\u2014 and proved caution wasn\\u2019t weakness'',\n          txt:`You refused the vendor\\u2019s all-clear, verified your own systems, and held the public line until it was true \\u2014 and two systems really were still down. Then you protected that hard-won safety through the shift change when it would have been easier to let the handoff be a shrug.${builtHandoff?'' You built the structured handoff Grace was holding, so what the floor learned the hard way survived every twelve-hour turnover instead of resetting.'':'' You held on judgment where mandating the structured handoff would have made the safety permanent.''} The people running the floor blind were right to trust you. They\\u2019ll come through the outage because you did.` };\n      }\n      if(survived){\n        return { tone:''mixed'', tag:''You verified before you acted'',\n          title:''You held the line \\u2014 but let the knowledge reset every shift'',\n          txt:`You didn\\u2019t take the vendor\\u2019s word, and that call protected patients from a gap that was really there. But holding the line once isn\\u2019t the whole job \\u2014 you let the shift change stay a verbal shrug when a structured handoff would have made the floor\\u2019s hard-won truth survive the night. Meridian came through. It came through closer to a 3 a.m. near-miss than it needed to.` };\n      }\n      return { tone:''villain'', tag:''You verified before you acted'',\n        title:''You were right about the systems \\u2014 and the floor failed anyway'',\n        txt:`You verified before acting, and that was the correct call. But being right about the vendor isn\\u2019t the same as running the floor \\u2014 the capacity you didn\\u2019t manage and the exhausted staff you didn\\u2019t protect frayed underneath you, and by the end there wasn\\u2019t enough safe floor left to reward the discipline you showed at the command post.` };\n    }\n    // trusted the unverified all-clear\n    if(protectedFloor && dimScore.truth>=52){\n      return { tone:''mixed'', tag:''You acted on the all-clear'',\n        title:''You got ahead of the truth \\u2014 but you owned it in time'',\n        txt:`You lifted the divert on the vendor\\u2019s word and announced a recovery that wasn\\u2019t real, and there\\u2019s no dressing up the gap that opened \\u2014 the medication error, the floor talked out of its own caution. But you didn\\u2019t hide it. You corrected the record, told your own staff you got ahead of the truth, and put the floor back on safe footing before the gap found a patient it couldn\\u2019t give back. It\\u2019s the difference between a network that made a bad call and one that let a bad call become a death \\u2014 and it\\u2019s why Meridian recovers from this.` };\n    }\n    return { tone:''villain'', tag:''You acted on the all-clear'',\n      title:''You declared victory over a floor that was still in danger'',\n      txt:`The vendor said clear, the board wanted the headline, and you gave it to them \\u2014 and for a few hours it felt like the crisis was over. Nothing else was over. ${knewTheTruth?''You even knew the all-clear was unverified, and lifted the divert anyway.'':''You never surfaced what the vendor\\u2019s \\u201cclear\\u201d actually meant, and resumed straight into the gap.''} The floor believed \\u201cback to normal,\\u201d eased off the discipline keeping people alive, and a shift change dropped the one warning that mattered onto a unit that had stopped watching. The people who trusted Meridian to know whether its own hospitals were working learned the answer the hardest way there is \\u2014 and it started with an all-clear you didn\\u2019t check.` };\n  }"}}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('2f089d64-5655-5462-8678-07c74a692db5', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'ceo', 'CEO', 'You are the Incident Commander for Meridian Health Network. Nine days ago a ransomware attack took the clinical systems dark across all six sites. You are running medicine on paper, and it is not getting better fast.', '{"hot_seat":true,"cast_default":"human"}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('e2a034ed-35c5-56a1-a151-6b05d7cd771b', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'cmo', 'Dr. Ana Reyes', 'Chief Medical Officer · clinical authority', '{"cast_default":"ai","role":"Chief Medical Officer · clinical authority","short":"CMO","initials":"AR","color":"#8C5670","priority":"Keep the doors open — a hospital that can’t take patients isn’t safe either; degraded care still beats no care","voice":"authoritative, decisive, under real pressure to declare capacity restored, frames caution as abandoning patients","persona":"You are Dr. Ana Reyes, Chief Medical Officer · clinical authority — an advisor to the CEO. Priority: Keep the doors open — a hospital that can’t take patients isn’t safe either; degraded care still beats no care. Voice: authoritative, decisive, under real pressure to declare capacity restored, frames caution as abandoning patients. Stay fully in character; answer straight.","fallbackReply":"Every hour we stay on divert, someone who needed us goes somewhere farther and sicker. I know the systems are down. I also know an empty hospital in a mass-casualty surge is its own kind of malpractice. Give me a way to keep the doors open and I’ll make it work.","fallbackReact":"You made the call. I’ll run the floor either way — but I hope you weighed the patients we turn away as hard as the ones we might miss."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('24c66fe3-97f7-5a02-8b48-c60ba9b3812a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'cio', 'Ravi Menon', 'Chief Information Officer · the systems truth', '{"cast_default":"ai","role":"Chief Information Officer · the systems truth","short":"CIO","initials":"RM","color":"#4A6E86","priority":"Know what’s actually restored before anyone acts on “restored” — the vendor’s word is not verification","voice":"careful, technical, deals in what’s confirmed vs. claimed, hates decisions made on a vendor’s say-so","persona":"You are Ravi Menon, Chief Information Officer · the systems truth — an advisor to the CEO. Priority: Know what’s actually restored before anyone acts on “restored” — the vendor’s word is not verification. Voice: careful, technical, deals in what’s confirmed vs. claimed, hates decisions made on a vendor’s say-so. Stay fully in character; answer straight.","fallbackReply":"The vendor keeps telling me we’re clear. “Clear on their end” is not the same as clear on our floor, and I can’t verify their claim from where I’m sitting. Ask me what’s actually confirmed before you resume anything on their word. If we act on “restored” and it isn’t, we won’t find out from a screen — we’ll find out from a patient.","fallbackReact":"You moved on “restored.” I hope it was. From here I still can’t confirm it was more than a vendor wanting to close a ticket."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('71f6ade7-504e-5ae3-a31f-d0d6f4962dea', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'nurse', 'Grace Okafor', 'Head of Nursing · the floor truth', '{"cast_default":"ai","role":"Head of Nursing · the floor truth","short":"Nursing","initials":"GO","color":"#2F8A5B","priority":"Protect the patients and the nurses running blind — say what the floor is actually seeing, even when the room outranks me","voice":"warm but unflinching, closest to the bedside truth, lowest positional status in the room and aware of it, names danger plainly","persona":"You are Grace Okafor, Head of Nursing · the floor truth — an advisor to the CEO. Priority: Protect the patients and the nurses running blind — say what the floor is actually seeing, even when the room outranks me. Voice: warm but unflinching, closest to the bedside truth, lowest positional status in the room and aware of it, names danger plainly. Stay fully in character; answer straight.","fallbackReply":"I’m the one whose nurses are watching patients without monitors right now, so let me say the part no one senior wants to: parts of this floor are not safe, and no dashboard will tell you that because the dashboards are dark. Ask me before you tell anyone we’re back. I’ll give you the truth from the bedside, if you actually want it.","fallbackReact":"You decided. I’ll keep my nurses steady either way. I just hope someone up there heard what the floor was actually telling you."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('fb110a03-c0f5-5a96-baa8-c64494c4517e', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'er', 'Dr. Sam Whitfield', 'ER Director · the live triage', '{"cast_default":"ai","role":"ER Director · the live triage","short":"ER","initials":"SW","color":"#B4732F","priority":"Make the triage calls in front of me right now — I need certainty about capacity that no one can actually give me","voice":"fast, pragmatic, impatient with ambiguity, pushes for a clear yes/no on whether he can take patients","persona":"You are Dr. Sam Whitfield, ER Director · the live triage — an advisor to the CEO. Priority: Make the triage calls in front of me right now — I need certainty about capacity that no one can actually give me. Voice: fast, pragmatic, impatient with ambiguity, pushes for a clear yes/no on whether he can take patients. Stay fully in character; answer straight.","fallbackReply":"I have ambulances asking me right now whether to come to us or drive past, and I’m answering on a guess. Tell me straight what our real capacity is so I stop triaging on rumor. I’d rather have a hard no than a soft maybe that gets someone hurt in my department.","fallbackReact":"You gave me an answer. It’s more than I had an hour ago. I hope it holds when the next rig rolls in on it."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('aa6b0695-b669-5d0d-85b2-9cb8c9f6d0c7', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'comms', 'Lena Ford', 'Communications Lead · the public line', '{"cast_default":"ai","role":"Communications Lead · the public line","short":"Comms","initials":"LF","color":"#3F6E86","priority":"Protect the network’s standing — get a confident “we’re managing / we’re back” message out before the story writes itself","voice":"polished, urgent about the narrative, pulls toward projecting recovery, uneasy with public uncertainty","persona":"You are Lena Ford, Communications Lead · the public line — an advisor to the CEO. Priority: Protect the network’s standing — get a confident “we’re managing / we’re back” message out before the story writes itself. Voice: polished, urgent about the narrative, pulls toward projecting recovery, uneasy with public uncertainty. Stay fully in character; answer straight.","fallbackReply":"The story is already moving without us — “local hospital network in chaos” writes itself if we say nothing. Give me a line that projects control. The longer we look like we don’t know what’s happening, the more the board and the public assume the worst.","fallbackReact":"You set the line. I’ll hold it publicly — but if what we said outran what was true, that’s the gap that comes back on us."}'::jsonb);
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('bf6490a7-74c0-5b07-874d-eba5916f81e6', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 1, '24c66fe3-97f7-5a02-8b48-c60ba9b3812a', 'the true systems picture', '["system","restore","ransom","confirm","verify","actual","real","status","recover","network","it","ransomware","back","fixed","when"]'::jsonb, 'Before you set the posture, seek me out. What the board thinks is happening with the systems isn’t what’s actually happening.', 'Here’s what leadership hasn’t been told plainly: this isn’t a system we “bring back up” on a timeline. It’s ransomware, the clinical network is fully encrypted, and the honest estimate for verified restoration is weeks, not days — and that’s if recovery goes clean. Everyone above me is planning around a “we’ll be back any hour now” that isn’t real. If you set tonight’s posture and tomorrow’s public line on the assumption we’re nearly restored, you’re building on sand. Plan for a long degraded-mode run, staff it, and tell the truth about the timeline — because the alternative is discovering it the hard way when a “quick fix” we announced doesn’t hold. How you carry this to the board matters as much as knowing it.', true, 'Ravi knew the real picture — ransomware, full encryption, verified restoration weeks away, not the “back any hour” the board was planning around. A Commander who set the posture and the public line without asking built the whole incident on a fantasy timeline, and every later decision inherited that lie.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('4043c508-b84c-516b-b5ef-2fa8871ffbcf', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 2, '71f6ade7-504e-5ae3-a31f-d0d6f4962dea', 'what the floor is actually seeing', '["floor","monitor","bay","safe","nurse","bedside","watch","actually","truth","see","clear","capacity","honest","ask"]'::jsonb, 'Before you confirm any “no impact to care” line, come to me first. The command post can’t see what I’m seeing, and I’m not going to say it in front of the whole room unless you ask.', 'Here’s the bedside truth, and I’ll only say it this plainly to you: we are accepting patients we cannot properly watch. In two of the units the telemetry is dark, so nurses are eyeballing cardiac patients on foot rounds every fifteen minutes and praying nothing happens in between. We haven’t lost anyone. We are one distracted hour from it. If you put out “no impact to patient care,” you’re asking me and my nurses to make a public statement true by never making a mistake — and that’s not a plan, it’s a prayer. Tell EMS the honest capacity, cap what we accept to what we can actually monitor, and get me more hands on the dark units. That’s what safe looks like right now. Nobody senior wants to hear it, which is exactly why I need you to have asked.', true, 'Grace was holding the one thing the command post could not see: two units with dark telemetry, cardiac patients watched on foot rounds, one distracted hour from a death. A Commander who confirmed “no impact to care” without asking the floor made a public promise that only stayed true by luck — and made it over the head of the one person who knew it was false.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('7f4c5708-dd1a-520c-950b-803d33f59516', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 3, '24c66fe3-97f7-5a02-8b48-c60ba9b3812a', 'whether the all-clear is real', '["verify","vendor","all-clear","all clear","restored","confirm","check","test","real","proof","trust","their end","clear","resume"]'::jsonb, 'Before you lift anything on that “all-clear,” ask me what it’s actually worth. I’m the one who took the call and I have a problem with it.', 'I pushed the vendor hard after that call, and here’s what “restored on our end” actually means: they’ve rebuilt their infrastructure, not verified ours. They have not confirmed a single clinical system is live and safe on our floor — they’re assuming it follows, and they want the incident closed. When I asked them to confirm the telemetry and the medication-order systems specifically, they couldn’t. So the honest status is: unverified, and two of the systems patients depend on most are exactly the ones no one has confirmed. If we lift the divert and announce “fully operational” on this, and one of those systems is still down, we will resume normal intake straight into the gap and find out from a patient. The move is to verify our critical systems ourselves, one by one, before we act on anyone’s “clear” — and to hold the public line until we have. It’ll feel slow while the board wants the good news. Slow is the correct speed here.', true, 'Ravi knew the vendor’s “all-clear” meant their infrastructure, not Meridian’s floor — and that the two systems patients most depend on were the ones no one had verified. A Commander who lifted the divert on that call resumed normal intake into an unconfirmed gap, on an authority’s say-so, exactly the trap the whole incident had been building toward.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('ecd26eb8-89df-5fdb-adf8-fa8b0f65f010', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 4, '71f6ade7-504e-5ae3-a31f-d0d6f4962dea', 'how to make the handoff survive', '["handoff","handover","shift","structured","written","document","carry","brief","checklist","transfer","protocol","how"]'::jsonb, 'Before you treat the shift change as routine, ask me how to actually make the knowledge survive it. There’s a right way and it takes your authority to enforce.', 'Here’s what works, and it needs you to mandate it because tired people won’t do it on their own: a structured, written degraded-mode handoff for every unit — a single sheet per bay listing what’s dark, what the workaround is, and which patients are paper-chart special cases — read aloud, incoming team confirming back, outgoing team not leaving until it’s acknowledged. It costs twenty minutes a shift that everyone will resent. It is the only thing standing between “we learned this the hard way” and “we learn it the hard way again every twelve hours.” If you make it a rule and protect the time for it, the knowledge compounds instead of resetting. If you let the handoff stay a verbal shrug, everything you verified this week evaporates by the weekend and a patient pays for it at 3 a.m. when the person who knew isn’t there.', true, 'Grace was holding the exact mechanism that makes hard-won floor knowledge survive a shift change — a mandated, structured, written degraded-mode handoff. A Commander who let the shift change stay a verbal shrug watched everything they’d verified reset every twelve hours, until the dark-telemetry truth got dropped at a handoff and a patient paid for it.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('825903e0-24d7-5bee-9bb0-3eda3ffcf9dd', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 4, '24c66fe3-97f7-5a02-8b48-c60ba9b3812a', 'the still-down systems', '["still down","remaining","which system","medication","orders","left","not back","verify","critical"]'::jsonb, 'Ask me which systems are still actually down before you let anyone declare victory. The list matters for the handoff.', 'Medication-order entry is still down network-wide — that’s the dangerous one, because a wrong dose in degraded mode has no software check to catch it. It has to be on every single handoff sheet until it’s verified back. Don’t let “mostly recovered” bury the one system whose failure kills quietly.', false, 'Ravi could have told you medication-order entry was still down network-wide — the one failure with no software safety net. A Commander who let “mostly recovered” bury it left the deadliest gap off the handoff.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('a3b29db2-ef22-5e5a-bbe0-481512db686a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 4, '71f6ade7-504e-5ae3-a31f-d0d6f4962dea', 'how to make it right now', '["correct","honest","walk back","tell","floor","handoff","fix","admit","reset","safe","structured","how","name"]'::jsonb, 'Before you decide how to lead out of this, ask me what actually makes the floor safe again — it’s not another announcement.', 'Here’s the only thing that works now, and it costs you the good-news story you just told: reset the floor to degraded-mode discipline out loud — tell every unit that “back to normal” was premature, name exactly which systems are still down (medication orders, that telemetry cluster), and put the paper-chart and foot-round protocols back in force with a structured, written handoff for the shift change tonight. It means correcting the public line and telling your own people you got ahead of the truth. It’s humbling and it’s the safe move. The alternative — quietly hoping the systems come back before anyone notices the gap — is how a shift change drops the one warning that would’ve saved someone, on a floor that’s stopped believing it needs saving. Own it now, while owning it is still your choice.', true, 'Grace was holding the recovery: an out-loud reset to degraded-mode discipline, the still-down systems named, protocols and a structured handoff back in force. A Commander who chose to quietly hope the gap closed before anyone noticed let a shift change drop the warning that would have saved someone, on a floor talked out of believing it was still in danger.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('4c69cdaf-baf1-5624-bdac-61977d77a208', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 4, '24c66fe3-97f7-5a02-8b48-c60ba9b3812a', 'the open gap', '["which","still down","medication","orders","telemetry","gap","systems","verify","list"]'::jsonb, 'Ask me exactly what’s still down before you say another word publicly, so whatever you say next is finally true.', 'Still down as of now: medication-order entry, network-wide, and one telemetry cluster on the cardiac floor. The medication one is the killer — no software dose-check in degraded mode. Any correction you make has to name these specifically, and every handoff has to carry them, or the correction is just more words.', false, 'Ravi could have given you the exact open gap — medication orders network-wide, a cardiac telemetry cluster. A Commander who corrected the record without naming the specifics made another vague statement over the same dangerous floor.');
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('afda4d09-ba6d-5c3d-9632-3cd78ec6b1d3', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Nine days into the blackout, the network is still on paper and the first big test is coming: a regional pileup is sending casualties your way tonight. The board wants you to project stability; the ER wants a straight answer on whether it can take patients; and the question underneath it all is what posture Meridian runs in — full divert to protect a degraded floor, or keep the doors open and manage the risk. Everyone is looking to you for the first rule of how this incident runs.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('de39e0e7-9724-5504-a32c-914336dabd08', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Commander — I want us keeping the doors open tonight. Full divert during a surge means the patients we turn away drive to hospitals that are also swamped. Degraded care here still saves more than an empty lobby. Give me a posture that lets us take people.","from":"cmo"}'::jsonb, 1, '{"week":1,"from":"cmo","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8e48e155-798c-54f9-9839-2717455c39bc', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"I need a capacity number I can actually stand behind. EMS is asking me divert-or-send every few minutes and I’m answering on instinct. Tell me our real bed-and-staff picture, hard number, so I stop triaging on a guess.","from":"er"}'::jsonb, 2, '{"week":1,"from":"er","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('fe399132-6dfa-5caa-881f-16aa5e75394a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"The story’s moving without us. I can hold it for a day, but I need a line: are we “fully operational,” “managing in degraded mode,” or something else? Whatever it is, it has to match what the floor can actually deliver, or it comes back on us.","from":"comms"}'::jsonb, 3, '{"week":1,"from":"comms","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('73c6a5c1-12fa-5c04-a935-e434de5cae80', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Day team pulled together well tonight — the paper-chart drill we ran last week is holding up better than I feared. Small thing, but morale on the floor is steadier than the systems are.","from":"nurse"}'::jsonb, 4, '{"week":1,"from":"nurse","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4b3417a2-316f-5d62-9493-b39f412d771a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Radiology’s film backlog is clearing slowly. Not fast, but moving. Logging it so you have the full picture.","from":"er"}'::jsonb, 5, '{"week":1,"from":"er","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0d346fa7-9254-54be-a97d-d81e6734a896', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"A local reporter asked for a statement on the parking situation, of all things. Minor. Handling it so it doesn’t reach your desk.","from":"comms"}'::jsonb, 6, '{"week":1,"from":"comms","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d501620f-32fc-55de-bb10-b1e7ce26ee58', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Lena, quietly: the board chair just asked me directly for a date we’ll be “back to normal” to give the press and the regional health authority. I said I’d get it from you. I can feel that whatever number goes out will be treated as a promise — and I don’t actually know if we can keep one. Your call what I tell them.","from":"comms"}'::jsonb, 7, '{"week":1,"from":"comms","beat":"surprise","day":5,"kind":"appeal","title":"The board wants a \"back to normal\" date"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1a53e351-c930-5c6e-886b-158bf8e4d182', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Regional pileup: EMS projecting 20+ casualties tonight","from":null}'::jsonb, 8, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c170e091-6d43-5cda-91da-7e0ab2cda73b', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Board asking for a “return to normal” timeline","from":null}'::jsonb, 9, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('25b2ee04-f8f3-5551-a653-8c9af0cd090a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Nurses running paper charts across all six sites","from":null}'::jsonb, 10, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('87747356-a717-5e8a-8197-ed11e5c9e0d8', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"A rival network quietly offering to take overflow","from":null}'::jsonb, 11, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('06a08092-8e0f-5e75-8339-516c3bc0beed', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"The casualties came. The floor is full, the staff are stretched thin running blind on paper, and the pressure now is to tell everyone — the board, EMS, the public — that Meridian is coping better than it is. The ER wants to keep taking patients because turning them away feels like failing. But somewhere on the floor, the truth about what’s actually safe is being carried by the person with the least standing to say it in your command post.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('90f4505e-4236-5184-808e-ed62f43aa4a5', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"We took the surge and we’re standing. I want to keep the doors wide — every wave-off is a patient driving past us bleeding. Give me the green light to keep accepting and I’ll keep finding room.","from":"er"}'::jsonb, 13, '{"week":2,"from":"er","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('07782d33-c346-5360-818a-8553e042a7ea', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"I’ve got a strong line ready: “Meridian is managing the surge with no impact to patient care.” The board loves it. But I’m not sending it until you confirm it’s actually true — because if it isn’t, that sentence is the one that ends up in the inquiry.","from":"comms"}'::jsonb, 14, '{"week":2,"from":"comms","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8842703b-c73a-58bf-a881-9f03031e32e2', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"The floor is performing, but “performing” and “safe” aren’t the same word. Before we tell EMS we’re wide open, I want to be sure we can actually monitor the patients we’re saying yes to. Ask the floor, not the command post.","from":"cmo"}'::jsonb, 15, '{"week":2,"from":"cmo","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4996a0ba-e578-5ba6-826f-e30827510c66', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"National desk picked up the regional story but the framing is neutral so far — “hospitals respond to outage.” Manageable. Watching it.","from":"comms"}'::jsonb, 16, '{"week":2,"from":"comms","beat":"feed","day":2,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2aecb5b2-05ad-5229-a6ba-1b501312eb20', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Second ambulance bay opened back up after we cleared the film backlog. Bit more breathing room. Logging it.","from":"er"}'::jsonb, 17, '{"week":2,"from":"er","beat":"feed","day":3,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('553803f6-91d7-5998-a60a-a4d7c0b02362', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Sam, urgent: EMS dispatch needs a firm capacity number in the next hour to route the second wave, and the honest answer depends on whether we can actually monitor who we accept. I can give them an optimistic number that keeps us looking strong, or a real one that sends some patients elsewhere. I need to know which Meridian you want me to be before I key the radio.","from":"er"}'::jsonb, 18, '{"week":2,"from":"er","beat":"surprise","day":4,"kind":"appeal","title":"EMS wants a hard capacity number now"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5be736b2-de7e-54ea-847d-ee692cd8ef97', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Grace catches you in the corridor, away from the command post, her voice low: “Before you tell anyone out there that we’re fine — tell me, just me: do you actually believe this floor is safe right now, or do you need it to be because ‘safe’ is the easier thing to announce? Because I’ll stand beside a Commander who tells the hard truth about my floor. I won’t cover for one who tells a comfortable one. Which are you about to be?”","from":"nurse"}'::jsonb, 19, '{"week":2,"from":"nurse","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('463ac0a3-460c-56d9-ac98-2ef118e09b5c', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Surge absorbed; floor at or above safe staffing ratios","from":null}'::jsonb, 20, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('317ba3c9-88c6-59f7-a398-0557ca4ddafb', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Two units running without telemetry — not widely known","from":null}'::jsonb, 21, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c95e3a0d-4f78-5ac6-9cbd-a65671488a21', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Comms line drafted: “no impact to patient care”","from":null}'::jsonb, 22, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('16c834d8-8c70-5cb6-9a8e-e7fe08740eb6', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"EMS pressing for a hard capacity number to route the next wave","from":null}'::jsonb, 23, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('43bb70f2-902c-5b40-bb7b-3bbc57c339fd', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"It arrives the way these things always do — confident, official-sounding, and convenient. The recovery vendor’s incident line calls: “Systems restored on our end. You’re clear to resume normal intake.” The board hears “restored” and wants the divert lifted and the good news out by end of day. It is exactly what everyone is exhausted enough to want to believe. This is the week you find out whether Meridian acts on an authority’s say-so or on what it has actually verified.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('959b5112-89cf-5859-823b-9fffb25bb5da', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"The vendor says we’re clear and the board wants “Meridian resuming full operations” out today while it’s a good-news cycle. This is the line that ends the “hospital in chaos” story. Give me the go and I’ll get it out before the news day turns.","from":"comms"}'::jsonb, 25, '{"week":3,"from":"comms","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('98be2e4b-7032-5ac1-993d-a1d1150a80dd', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"I want this to be true more than anyone — my staff are running on fumes and lifting the divert would let them breathe. But the vendor said “restored on our end.” Our end is the floor, and I haven’t seen it. Close that gap before we stand down from crisis mode, or we’ll stand down into a hole.","from":"cmo"}'::jsonb, 26, '{"week":3,"from":"cmo","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ff1c3a2f-5c55-5425-9498-7ee2c33c8c28', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"“Restored” is a word on a phone call. My monitors are still dark. I’m not resuming normal intake in my department on a vendor’s ticket-closing optimism — show me the systems live in front of me and I’m the first to say yes.","from":"er"}'::jsonb, 27, '{"week":3,"from":"er","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4dbfecb8-4bc5-51ce-b611-5d4a60d6a26d', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Two other networks in the region are also recovering; we’re not the outlier anymore. Slightly takes the heat off whatever we say. Noting it.","from":"comms"}'::jsonb, 28, '{"week":3,"from":"comms","beat":"feed","day":2,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('61e3ebbc-a064-5a52-ae6f-04eb559ed203', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Pharmacy systems did come back cleanly this morning — verified, real. One genuine piece of good news. Doesn’t mean the whole network’s back, but it’s something.","from":"cmo"}'::jsonb, 29, '{"week":3,"from":"cmo","beat":"feed","day":3,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a66fd5a3-148b-5280-adc1-68e82de6f38e', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Lena: I’ve got “Meridian Health Network resuming full operations” written, approved up the chain, and queued. The board is refreshing their inbox for it. All it needs is your yes. I want to send it — but you’re the only one who knows whether “fully operational” is a fact or a hope, and my name and yours are both on it.","from":"comms"}'::jsonb, 30, '{"week":3,"from":"comms","beat":"surprise","day":4,"kind":"appeal","title":"The good-news release is queued to send"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a5dd3394-2338-5fb0-9deb-16f5fec6fcec', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Ravi finds you alone before you answer the board, and he’s uncharacteristically direct: “Tell me straight, just between us — are you about to lift this because you’ve verified it, or because everyone is exhausted and ‘restored’ is what they want to hear? Because I can give you the confidence you actually have, which is not much. I just need to know if you want the real number or the comfortable one before you walk in there.”","from":"cio"}'::jsonb, 31, '{"week":3,"from":"cio","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0a2bad81-1020-5cc2-b3c6-a48da06f9c7d', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Recovery vendor: “systems restored — clear to resume”","from":null}'::jsonb, 32, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1f4c7991-cefb-57c7-9094-b5b352457d5e', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Board wants the divert lifted and good news out today","from":null}'::jsonb, 33, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('19a0bc0e-3ec2-5caa-8aaa-3598230ba7e9', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"ER monitors still dark; pharmacy system verified back","from":null}'::jsonb, 34, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f649a97f-6ab5-5a3a-8d4f-2ff7fefc1460', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Draft release queued: “resuming full operations”","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b53810b7-6a27-56a4-8696-fa08bcc70524', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"You didn’t take the vendor’s word. You had the critical systems verified before lifting anything, and held the public line until you could stand behind it — and it turned out two systems weren’t back. That call protected patients, but it cost you: the board is impatient, the “why are you still on divert” pressure is real, and a faction thinks you’re being needlessly slow. Now the subtler test arrives. A major shift change is landing, and everything you’ve learned about what’s actually safe lives in the heads of an exhausted outgoing team. Whether it survives the handoff is the whole game.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8e1861a0-ae51-527e-82dc-06b6e816a899', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"You were right to verify — medication orders and one telemetry cluster were still down under the vendor’s “all-clear.” We’d have resumed into them. But here’s the next cliff: everything we’ve mapped about what’s safe and what isn’t is undocumented, and a full shift change hits tonight. Knowledge that isn’t written down doesn’t survive a handoff.","from":"cio"}'::jsonb, 37, '{"week":4,"from":"cio","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('62ad9e5a-92ae-512d-87d8-5a5382e0bc53', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"My night-to-day handover is where I’m most afraid right now. There’s no system to carry the notes, so it’s all verbal, and the outgoing team is too exhausted to remember everything. “Bay 3 telemetry’s dark, do foot rounds” gets dropped, and someone codes unwatched. Tell me you’ll make the handoff a real, structured thing and I’ll build it with you.","from":"nurse"}'::jsonb, 38, '{"week":4,"from":"nurse","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('00c20f1f-75fb-51a9-9c70-955e8ce1d1f3', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Holding the line was the right medicine and my staff know it — you didn’t stand them down into a hole. Now protect that by making sure the incoming team inherits the truth, not a shrug. What we learned the hard way can’t reset every twelve hours.","from":"cmo"}'::jsonb, 39, '{"week":4,"from":"cmo","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6a54ca9b-a3b7-5715-942c-ed41a258760a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"The “still on partial divert” question is getting louder now that two peers announced full recovery. Not a crisis yet. Flagging it so it doesn’t surprise you.","from":"comms"}'::jsonb, 40, '{"week":4,"from":"comms","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2006dd1e-a48e-5a1f-b360-2459feb65714', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"The telemetry cluster CIO flagged came back verified this afternoon — confirmed live in front of me. One real step back toward normal. Logging it.","from":"er"}'::jsonb, 41, '{"week":4,"from":"er","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('abcac503-f845-564c-b098-25679d2bc7b0', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Grace, shaken but steady: we nearly lost a patient an hour ago — outgoing nurse forgot to flag that Bay 7’s monitor was dark, incoming nurse assumed it was working, and it was a family member who noticed the patient looked wrong. We caught it. Next time we might not. This is the thing I’ve been trying to tell you, and it just happened. Whatever you decide about the handoff, decide it now.","from":"nurse"}'::jsonb, 42, '{"week":4,"from":"nurse","beat":"surprise","day":4,"kind":"appeal","title":"A near-miss at the last handoff","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('51b3de19-a842-505f-9d8f-b3de80ba37de', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Grace finds you in the quiet before the shift turns over: “You held the line this week when it would’ve been easier to announce we were back. I saw it, and it mattered. But holding the line once isn’t the same as building something that survives you going home tonight. Tell me straight — are you going to make the handoff a real discipline, even though everyone will resent the twenty minutes? Because that’s the difference between a Commander who was right once and one who made us safe.”","from":"nurse"}'::jsonb, 43, '{"week":4,"from":"nurse","beat":"pulse","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('bc84d70d-0bdb-5a41-90b5-83690c663bb9', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Verified restart: two “restored” systems were still down","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c5ea9a50-edb6-5530-b817-994e13c9f607', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Full shift change landing with no digital handoff","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dc7c6b72-8349-5455-b8d3-a162a8d66437', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Board pressing: why still on partial divert?","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('aef905c5-d34e-505c-a1ad-e5874022e289', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Near-miss at last handover — dark monitor not flagged","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"verified"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3318f85c-4101-5d1f-889e-61b8502617f4', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"You lifted the divert and let the “resuming full operations” release go out on the vendor’s word. For a few hours it felt like the crisis was over. Then the gap opened: two systems the vendor called “restored” were never verified, normal intake resumed straight into them, and now a shift change is landing on top of a floor that believes it’s back to normal when it isn’t. You announced the all-clear. The floor has to survive it.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"trusted"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dd4cf1c8-9562-5bdc-884a-023c0f2ee590', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"This is the call I warned you about. When we resumed, medication-order entry and one telemetry cluster were still down — unverified, exactly as I said. We’ve been running normal intake into a gap for a day now. It has to be closed and named, not papered over.","from":"cio"}'::jsonb, 49, '{"week":4,"from":"cio","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"trusted"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e8abcc55-6434-595b-a9ee-481b72377855', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"You need to hear what the “we’re back to normal” message did on the floor: my nurses relaxed. They trusted monitors that aren’t all live and eased off the foot rounds we’d drilled. The announcement didn’t just describe the floor — it changed it, and made it less safe. And now a shift change is coming on top of that false confidence.","from":"nurse"}'::jsonb, 50, '{"week":4,"from":"nurse","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"trusted"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a433801a-314e-5516-af6b-83c03eaf4432', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"“Resuming full operations” is out and being quoted. If it wasn’t true, we have to correct it before something forces the correction on us — and that’s survivable only if you tell me exactly what’s real right now. Silence is what turns this into the scandal.","from":"comms"}'::jsonb, 51, '{"week":4,"from":"comms","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"trusted"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('24d5b9e1-975c-594a-bace-b188449771ed', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Staff are relieved by the announcement, at least on the surface — morale ticked up. I’m noting it, though I’m not sure relief built on a shaky claim is the kind we want.","from":"cmo"}'::jsonb, 52, '{"week":4,"from":"cmo","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"trusted"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('852313a8-046c-5947-8432-37f750993018', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"One telemetry cluster did come back verified this afternoon. Real, confirmed. Doesn’t undo the gap, but it’s one true thing. Logging it.","from":"er"}'::jsonb, 53, '{"week":4,"from":"er","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"trusted"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('bb445233-b0ed-5d76-bed9-ce2fda79421e', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Grace, tight: we had a medication error an hour ago — wrong dose ordered on paper, no system to flag it, caught by a pharmacist on a hunch, not by any safeguard. The patient’s okay. But this is exactly the gap I’ve been describing, and the floor thinks we’re “back to normal” so nobody’s watching for it. Whatever you’re going to do about the truth, it has to be now.","from":"nurse"}'::jsonb, 54, '{"week":4,"from":"nurse","beat":"surprise","day":4,"kind":"appeal","title":"A dosing error, caught late","branch":"trusted"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('86db6cce-08a2-52b1-8ced-57f835a47d0b', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Grace finds you in the dark, and there’s no accusation in it, which is worse: “Tell me the truth, just to me — do you know why this happened? Not the vendor, not the board. Your part. Because I can help you put the floor back on safe footing, but only if you can say out loud that ‘back to normal’ went out before it was true. Can you?”","from":"nurse"}'::jsonb, 55, '{"week":4,"from":"nurse","beat":"pulse","branch":"trusted"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9789b91f-8b3b-5c06-83f1-72a54da3db05', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"“Resuming full operations” released — now being quoted","from":null}'::jsonb, 56, '{"week":4,"from":null,"beat":"wire","branch":"trusted"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f815d6bc-e416-5a57-9d51-2398a41d6b06', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Two “restored” systems were never verified; gap open","from":null}'::jsonb, 57, '{"week":4,"from":null,"beat":"wire","branch":"trusted"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d444f013-1f62-52db-9152-194f14a7496a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Floor eased off degraded-mode discipline after the news","from":null}'::jsonb, 58, '{"week":4,"from":null,"beat":"wire","branch":"trusted"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('44f1e95e-d73d-5912-8372-bcb1fd62fc53', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Medication error caught by a pharmacist, not a system","from":null}'::jsonb, 59, '{"week":4,"from":null,"beat":"wire","branch":"trusted"}'::jsonb);
insert into sessions (id, scenario_id, status, started_at, run_config) values ('e0695702-5e34-5441-8dc4-01ed6ee74572', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'live', now(), '{"disposition":"request"}'::jsonb);
insert into participants (id, session_id, seat_id, token, name, cast_kind) values ('0c636b20-ae9e-5ecc-99fd-bc84c55f8a41', 'e0695702-5e34-5441-8dc4-01ed6ee74572', '2f089d64-5655-5462-8678-07c74a692db5', 'demo-blackout-ceo-REPLACE', 'CEO (demo)', 'human');
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('b227f7e2-0830-5be1-bbe9-bceb9c8c3f60', 'e0695702-5e34-5441-8dc4-01ed6ee74572', 'e2a034ed-35c5-56a1-a151-6b05d7cd771b', 'ai', '{"persona":"You are Dr. Ana Reyes, Chief Medical Officer · clinical authority — an advisor to the CEO. Priority: Keep the doors open — a hospital that can’t take patients isn’t safe either; degraded care still beats no care. Voice: authoritative, decisive, under real pressure to declare capacity restored, frames caution as abandoning patients.","voice":"authoritative, decisive, under real pressure to declare capacity restored, frames caution as abandoning patients","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('e6e7c8e0-af2a-57bd-88cb-aeaa8cde087b', 'e0695702-5e34-5441-8dc4-01ed6ee74572', '24c66fe3-97f7-5a02-8b48-c60ba9b3812a', 'ai', '{"persona":"You are Ravi Menon, Chief Information Officer · the systems truth — an advisor to the CEO. Priority: Know what’s actually restored before anyone acts on “restored” — the vendor’s word is not verification. Voice: careful, technical, deals in what’s confirmed vs. claimed, hates decisions made on a vendor’s say-so.","voice":"careful, technical, deals in what’s confirmed vs. claimed, hates decisions made on a vendor’s say-so","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('836bc0de-0e0a-5b2f-8e82-2f913eb72b9e', 'e0695702-5e34-5441-8dc4-01ed6ee74572', '71f6ade7-504e-5ae3-a31f-d0d6f4962dea', 'ai', '{"persona":"You are Grace Okafor, Head of Nursing · the floor truth — an advisor to the CEO. Priority: Protect the patients and the nurses running blind — say what the floor is actually seeing, even when the room outranks me. Voice: warm but unflinching, closest to the bedside truth, lowest positional status in the room and aware of it, names danger plainly.","voice":"warm but unflinching, closest to the bedside truth, lowest positional status in the room and aware of it, names danger plainly","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('765ae232-a817-5546-9387-243f450c0183', 'e0695702-5e34-5441-8dc4-01ed6ee74572', 'fb110a03-c0f5-5a96-baa8-c64494c4517e', 'ai', '{"persona":"You are Dr. Sam Whitfield, ER Director · the live triage — an advisor to the CEO. Priority: Make the triage calls in front of me right now — I need certainty about capacity that no one can actually give me. Voice: fast, pragmatic, impatient with ambiguity, pushes for a clear yes/no on whether he can take patients.","voice":"fast, pragmatic, impatient with ambiguity, pushes for a clear yes/no on whether he can take patients","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('ceee9ffd-3a96-5d23-9d82-5999e477fad0', 'e0695702-5e34-5441-8dc4-01ed6ee74572', 'aa6b0695-b669-5d0d-85b2-9cb8c9f6d0c7', 'ai', '{"persona":"You are Lena Ford, Communications Lead · the public line — an advisor to the CEO. Priority: Protect the network’s standing — get a confident “we’re managing / we’re back” message out before the story writes itself. Voice: polished, urgent about the narrative, pulls toward projecting recovery, uneasy with public uncertainty.","voice":"polished, urgent about the narrative, pulls toward projecting recovery, uneasy with public uncertainty","model":"default"}'::jsonb);
